 # Returns 1 if @nd_block[nid] is a literal BlockNode (do/end body),
 # 0 otherwise. Pairs with find_block_arg to dispatch correctly at
 # &block-forwarding call sites (literal block vs. `&proc_var`).
  def has_literal_block(nid)
    blk = @nd_block[nid]
    (blk >= 0 && @nd_type[blk] == "BlockNode") ? 1 : 0
  end

 # Returns the inner expression of a BlockArgumentNode whose payload
 # is a captured proc local (the `&block` form). Returns -1 for
 # absent block-arg, or for shapes the codegen doesn't yet forward
 # — `&:sym` (SymbolNode) and `&nil` (NilNode), which would need
 # symbol-to-proc / nil-as-no-block lowering. Call sites fall
 # through to the no-block path in those cases.
  def find_block_arg(nid)
    blk = @nd_block[nid]
    if blk < 0
      return -1
    end
    if @nd_type[blk] != "BlockArgumentNode"
      return -1
    end
    inner = @nd_expression[blk]
    if inner < 0
      return -1
    end
    if @nd_type[inner] != "LocalVariableReadNode"
      return -1
    end
    inner
  end

 # Resolves the call-site block-forwarding expression: returns the C
 # expression for the proc to forward at a `&block`-taking call site
 # (a literal block compiles to sp_proc_new(...); a `&proc_var` is
 # the captured `sp_Proc *` local), or "" if the call site provides
 # no block.
  def block_forward_expr(nid, blk_param_types = "")
    if has_literal_block(nid) == 1
      return compile_proc_literal(nid, blk_param_types)
    end
 # Anonymous `&` forwarding (Ruby 3.1+): `inner(&)` where the
 # enclosing method declared `def outer(&)`. The BlockArgumentNode
 # carries no expression, so `find_block_arg` returns -1; we forward
 # the enclosing method's anon-block param directly.
    blk = @nd_block[nid]
    if blk >= 0 && @nd_type[blk] == "BlockArgumentNode" && @nd_expression[blk] < 0
      if @current_method_block_param != ""
        return "lv_" + @current_method_block_param
      end
    end
    ba = find_block_arg(nid)
    if ba >= 0
      return compile_expr(ba)
    end
    ""
  end

 # Returns the body node id for class ci's midx'th method, or -1
 # if midx is out of range or the body id is invalid. Centralises
 # the @cls_meth_bodies[ci].split(";")[midx].to_i parse so detectors
 # don't have to inline it.
  def cls_method_body_id(ci, midx)
    bodies = @cls_meth_bodies[ci].split(";")
    if midx >= bodies.length
      return -1
    end
    bid = bodies[midx].to_i
    if bid < 0
      return -1
    end
    bid
  end

 # Returns the name of the class method's single proc-typed param
 # (its `&block` slot), or "" if the signature isn't exactly one
 # proc param. Used by detectors that match the
 # `def m(&b); ...; end` shape (instance_eval trampoline today;
 # extensible to instance_exec, tap, etc.).
  def cls_method_sole_proc_param_name(ci, midx)
    pnames = cls_meth_pnames_get(ci, midx)
    ptypes = cls_meth_ptypes_get(ci, midx)
    if pnames.length != 1 || ptypes.length != 1
      return ""
    end
    if ptypes[0] != "proc"
      return ""
    end
    pnames[0]
  end

 # Detects the exact arity-0 instance_eval trampoline shape:
 # `def m(&b); instance_eval(&b); end`. Returns 1 when the
 # (ci, midx) method body is a single CallNode of `instance_eval`
 # forwarded the method's sole proc-typed param via &-arg, 0
 # otherwise. Spinel inlines these at the call site (yield-style)
 # with self rebound to the receiver — full Ruby instance_eval is
 # dynamic, but this AOT compromise covers the common DSL-trampoline
 # shape. Anything wider falls through to today's silent no-op.
  def is_instance_eval_trampoline(ci, midx)
 # AST shape gates first (no string splits — cheap reject path).
    bid = cls_method_body_id(ci, midx)
    if bid < 0
      return 0
    end
    stmts = get_stmts(bid)
    if stmts.length != 1
      return 0
    end
    s = stmts[0]
    if @nd_type[s] != "CallNode"
      return 0
    end
    if @nd_name[s] != "instance_eval"
      return 0
    end
    if @nd_receiver[s] >= 0
      return 0
    end
    inner = find_block_arg(s)
    if inner < 0
      return 0
    end
    if @nd_type[inner] != "LocalVariableReadNode"
      return 0
    end
 # Param signature gate (does the string splits) — only methods
 # that pass the AST shape get here.
    pname = cls_method_sole_proc_param_name(ci, midx)
    if pname == ""
      return 0
    end
    if @nd_name[inner] != pname
      return 0
    end
    1
  end

 # Flatten a constant reference into an internal name.
 # C -> C
 # ::C -> C
 # M::C -> M_C
 # A::B::C -> A_B_C


  def constructor_class_name(recv_nid)
    if recv_nid < 0
      return ""
    end
    rt = @nd_type[recv_nid]
    if rt == "ConstantReadNode" || rt == "ConstantPathNode"
      return resolve_const_ref_name(recv_nid)
    end
    ""
  end

  def module_name_exists(name)
    i = 0
    while i < @module_names.length
      if @module_names[i] == name
        return 1
      end
      i = i + 1
    end
    0
  end

  def const_namespace_exists(name)
    if name == ""
      return 0
    end
    if find_const_idx(name) >= 0
      return 1
    end
    if find_class_idx(name) >= 0
      return 1
    end
    if module_name_exists(name) == 1
      return 1
    end
    0
  end

 # Constant names the codegen recognises as legitimate even when no
 # user-defined class / module / constant of the same name exists.
 # These are dispatcher-handled module-like receivers (Math, File,
 # ENV, Dir, Time, Process, IO), the global ARGV, the built-in type
 # names used in `is_a?` / `case`/`when` arms, and a handful of
 # exception classes referenced by `raise` / `rescue` patterns.
  def is_known_constant_name(name)
    if const_namespace_exists(name) == 1
      return 1
    end
    if name == "ARGV" || name == "ENV" || name == "STDIN" || name == "STDOUT" || name == "STDERR"
      return 1
    end
    if name == "Math" || name == "File" || name == "Dir" || name == "Time" || name == "IO" || name == "Process" || name == "Kernel" || name == "Comparable" || name == "Enumerable" || name == "Complex"
      return 1
    end
    if name == "Object" || name == "Integer" || name == "String" || name == "Float" || name == "Symbol" || name == "Array" || name == "Hash" || name == "Range" || name == "Numeric" || name == "TrueClass" || name == "FalseClass" || name == "NilClass" || name == "Proc" || name == "Lambda" || name == "Regexp" || name == "MatchData" || name == "StringIO" || name == "Fiber"
      return 1
    end
 # Common exception classes referenced by raise / rescue. We
 # don't model the exception hierarchy beyond name-tagging.
    if name == "StandardError" || name == "RuntimeError" || name == "ArgumentError" || name == "TypeError" || name == "NameError" || name == "NoMethodError" || name == "IndexError" || name == "KeyError" || name == "ZeroDivisionError" || name == "FloatDomainError" || name == "RangeError" || name == "IOError" || name == "Errno" || name == "NotImplementedError" || name == "StopIteration" || name == "RegexpError" || name == "FrozenError" || name == "LocalJumpError" || name == "Exception"
      return 1
    end
    0
  end

  def current_lexical_scope_name
    if @current_lexical_scope != ""
      return @current_lexical_scope
    end
    if @current_class_idx >= 0
      if @current_class_idx < @cls_names.length
        return @cls_names[@current_class_idx]
      end
      return ""
    end
    if @current_method_name != ""
      cls_idx = @current_method_name.index("_cls_")
 # CRuby returns nil when not found; spinel runtime returns -1.
      if cls_idx != nil && cls_idx >= 0
        return @current_method_name[0, cls_idx]
      end
    end
    ""
  end

  def trim_const_scope_once(name)
    if name == ""
      return ""
    end
    idx = name.rindex("_")
 # CRuby returns nil when not found; spinel runtime returns -1.
 # Treat both as "no underscore — root scope".
    if idx == nil || idx < 0
      return ""
    end
    name[0, idx]
  end

  def resolve_const_read_name(name)
    scope = current_lexical_scope_name
    while scope != ""
      cand = scope + "_" + name
      if const_namespace_exists(cand) == 1
        return cand
      end
      scope = trim_const_scope_once(scope)
    end
    name
  end

  def resolve_const_ref_name(nid)
    if nid < 0
      return ""
    end
    t = @nd_type[nid]
    if t == "ConstantReadNode"
      return resolve_const_read_name(@nd_name[nid])
    end
    if t == "ConstantPathNode"
      leaf = @nd_name[nid]
      parent = @nd_receiver[nid]
      if parent < 0
        return leaf
      end
      base = resolve_const_ref_name(parent)
      if base == ""
        return ""
      end
      return base + "_" + leaf
    end
    ""
  end

 # ---- Scope management ----
  def push_scope
    @scope_names.push("---")
    @scope_types.push("---")
    @scope_ivar_alias.push("---")
    0
  end

  def pop_scope
    while @scope_names.length > 0
      top_name = @scope_names.last
      if top_name == "---"
        @scope_names.pop
        @scope_types.pop
        @scope_ivar_alias.pop
        return
      end
      @scope_names.pop
      @scope_types.pop
      @scope_ivar_alias.pop
    end
  end

  def declare_var(name, vtype)
    @scope_names.push(name)
    @scope_types.push(vtype)
    @scope_ivar_alias.push("")
    0
  end

 # Returns the snapshot class-name C variable for an exception
 # variable currently bound by an enclosing `rescue => name`, or
 # empty string if `name` is not an active exception binding.
  def find_exc_var_cls(name)
    i = @exc_var_names.length - 1
    while i >= 0
      if @exc_var_names[i] == name
        return @exc_var_cls_vars[i]
      end
      i = i - 1
    end
    ""
  end

 # Emit a bare `raise` (no message arg). Inside a rescue body the
 # snapshotted class+message is re-raised; outside any rescue it
 # falls back to a fresh RuntimeError, matching CRuby.
  def emit_bare_raise
    if @rescue_cls_stack.length > 0
      rcls = @rescue_cls_stack.last
      rmsg = @rescue_msg_stack.last
      emit("  sp_raise_cls(" + rcls + ", " + rmsg + ");")
    else
      emit("  sp_raise(\"RuntimeError\");")
    end
  end

 # Record / clear an ivar alias for a local variable. Walks the
 # `@scope_*` parallel stacks like `set_var_type` does. `iname` is
 # the source ivar name (e.g. `@fetch`); pass `""` to clear.
  def set_var_ivar_alias(name, iname)
    i = @scope_names.length - 1
    while i >= 0
      if @scope_names[i] == name
        @scope_ivar_alias[i] = iname
        return
      end
      i = i - 1
    end
  end

  def find_var_ivar_alias(name)
    i = @scope_names.length - 1
    while i >= 0
      if @scope_names[i] == name
        return @scope_ivar_alias[i]
      end
      i = i - 1
    end
    ""
  end

  def find_var_type(name)
 # Type-narrow override : walk top-down so the
 # innermost is_a? guard wins. Skipped for the unscoped global
 # call (e.g. ivar lookups) — narrows are about local var typing.
    i = @type_narrow_names.length - 1
    while i >= 0
      if @type_narrow_names[i] == name
        return @type_narrow_types[i]
      end
      i = i - 1
    end
    i = @scope_names.length - 1
    while i >= 0
      if @scope_names[i] == name
        return @scope_types[i]
      end
      i = i - 1
    end
    ""
  end

 # Push / pop on the is_a? narrow stack. Codegen pushes during
 # body-stmt walks where a `raise unless x.is_a?(C)` guard
 # eliminates the non-C path; the rest of the StatementsNode sees
 # `x` as `C` via find_var_type's narrow-first lookup, so
 # `compile_call_expr`'s `recv_type == "poly"` check resolves to
 # the concrete obj_<C> path and emits a monomorphic dispatch
 # (vs. the full cls_id-switch). Issue #493.
  def push_type_narrow(var_name, narrow_type)
    @type_narrow_names.push(var_name)
    @type_narrow_types.push(narrow_type)
  end

  def pop_type_narrow
    @type_narrow_names.pop
    @type_narrow_types.pop
  end

 # Like find_var_type but bypasses the is_a? narrow stack — returns
 # the var's declared (C-level) type. Used by call-site arg lowering
 # to detect cases where the narrow says "string" but the underlying
 # storage is still sp_RbVal, so the arg needs an unbox cast.
  def find_var_declared_type(name)
    i = @scope_names.length - 1
    while i >= 0
      if @scope_names[i] == name
        return @scope_types[i]
      end
      i = i - 1
    end
    ""
  end

 # ---- is_a? type narrowing ----
 # `<expr>.is_a?(<Class>)` (or kind_of?) used as the predicate of
 # an if / ternary lets us treat <expr> as <Class>'s type inside
 # the then-arm. The four entry points (push, pop,
 # narrow_type_for_class, parse_is_a_predicate) are called from
 # both inference and codegen sides — keep the API tiny so the
 # narrow context can be plumbed through without leaking state.



 # Map a Ruby class name to spinel's static type tag for narrowing.
 # Returns "" when the class doesn't have a concrete spinel type
 # we can narrow to (and the call site should leave the var type
 # alone). The first set is concrete primitives — narrow gives a
 # real type win. The Hash / Array group widens to the catch-all
 # poly_* variant since spinel doesn't track a single "any hash"
 # type, but `poly_hash` / `poly_array` reaches every receiver-
 # method dispatch the narrowed var participates in.

 # Static evaluation of `<expr>.is_a?(<Class>)` /
 # `.kind_of?(<Class>)` when expr's static type already proves the
 # answer. Returns "TRUE" / "FALSE" / "" (= dynamic). Used at
 # IfNode emit sites to skip the dead arm so the C compiler doesn't
 # type-check a recursion call whose argument types don't match.
  def static_is_a_value(pred_id)
    if pred_id < 0
      return ""
    end
    if @nd_type[pred_id] != "CallNode"
      return ""
    end
    pname = @nd_name[pred_id]
    if pname != "is_a?" && pname != "kind_of?"
      return ""
    end
    expr = @nd_receiver[pred_id]
    if expr < 0
      return ""
    end
    args = @nd_arguments[pred_id]
    if args < 0
      return ""
    end
    arg_ids = get_args(args)
    if arg_ids.length < 1
      return ""
    end
    arg0 = arg_ids[0]
    cname = ""
    if @nd_type[arg0] == "ConstantReadNode"
      cname = @nd_name[arg0]
    elsif @nd_type[arg0] == "ConstantPathNode"
      cname = resolve_const_ref_name(arg0)
    end
    if cname == ""
      return ""
    end
    expr_t = infer_type(expr)
    is_a_static_eval(expr_t, cname)
  end

  def is_a_static_eval(expr_t, cname)
    eb = base_type(expr_t)
    if eb == "poly"
      return ""
    end
 # Concrete primitives: positive answer wins, otherwise narrow
 # to the right tag.
    if cname == "Symbol"
      if eb == "symbol"
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
    if cname == "String"
      if eb == "string" || eb == "mutable_str"
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
    if cname == "Integer" || cname == "Numeric"
      if eb == "int"
        return "TRUE"
      end
      if cname == "Numeric" && eb == "float"
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
    if cname == "Float"
      if eb == "float"
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
    if cname == "TrueClass" || cname == "FalseClass"
      if eb == "bool"
        return ""  # value-dependent, leave dynamic
      end
      return is_a_static_negative(eb)
    end
    if cname == "NilClass"
      if eb == "nil"
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
    if cname == "Hash"
      if is_hash_type(eb) == 1
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
    if cname == "Array"
      if is_array_type(eb) == 1
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
    if cname == "Proc"
      if eb == "proc" || eb == "lambda"
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
    if cname == "Range"
      if eb == "range"
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
 # User-defined class
    if find_class_idx(cname) >= 0
      if is_obj_type(eb) == 1
        ecname = eb[4, eb.length - 4]
        if is_class_or_ancestor(ecname, cname) == 1
          return "TRUE"
        end
        return "FALSE"
      end
      return is_a_static_negative(eb)
    end
    ""
  end

 # When the receiver's static type is a non-poly concrete tag, we
 # can safely declare any non-matching is_a? as FALSE. Used by the
 # primitive class branches above.
  def is_a_static_negative(eb)
    if eb == "poly" || eb == ""
      return ""
    end
    "FALSE"
  end

 # Codegen-side mirrors of the analyze helpers
 # (narrow_type_for_class / parse_is_a_predicate /
 # body_definitely_raises? / parse_raise_guard_narrow). The
 # analyze pass already pushes narrows during fixpoint walks so
 # callee param types widen correctly; codegen has to push them
 # again at emit time so `find_var_type` returns the narrowed
 # type for a LocalVariableReadNode inside the post-guard
 # sibling scope. Without this, the dispatch fall-through at
 # `compile_call_expr`'s `recv_type == "poly"` branch never
 # collapses the cls_id-switch to the single narrowed-class arm.
 # Issue #493.
  def narrow_type_for_class(cname)
    if cname == "Symbol"
      return "symbol"
    end
    if cname == "Integer" || cname == "Numeric"
      return "int"
    end
    if cname == "Float"
      return "float"
    end
    if cname == "String"
      return "string"
    end
    if cname == "TrueClass" || cname == "FalseClass"
      return "bool"
    end
    if cname == "NilClass"
      return "nil"
    end
    if cname == "Proc"
      return "proc"
    end
    if cname == "Range"
      return "range"
    end
    if find_class_idx(cname) >= 0
      return "obj_" + cname
    end
    ""
  end

  def parse_is_a_predicate(pred_id)
    if pred_id < 0
      return ["", ""]
    end
    if @nd_type[pred_id] == "AndNode"
      l_isa = parse_is_a_predicate(@nd_left[pred_id])
      if l_isa[0] != ""
        return l_isa
      end
      r_isa = parse_is_a_predicate(@nd_right[pred_id])
      if r_isa[0] != ""
        return r_isa
      end
      return ["", ""]
    end
    if @nd_type[pred_id] != "CallNode"
      return ["", ""]
    end
    pname = @nd_name[pred_id]
    if pname != "is_a?" && pname != "kind_of?"
      return ["", ""]
    end
    expr = @nd_receiver[pred_id]
    if expr < 0 || @nd_type[expr] != "LocalVariableReadNode"
      return ["", ""]
    end
    args = @nd_arguments[pred_id]
    if args < 0
      return ["", ""]
    end
    arg_ids = get_args(args)
    if arg_ids.length < 1
      return ["", ""]
    end
    arg0 = arg_ids[0]
    cname = ""
    if @nd_type[arg0] == "ConstantReadNode"
      cname = @nd_name[arg0]
    elsif @nd_type[arg0] == "ConstantPathNode"
      cname = resolve_const_ref_name(arg0)
    end
    if cname == ""
      return ["", ""]
    end
    nt = narrow_type_for_class(cname)
    if nt == ""
      return ["", ""]
    end
    [@nd_name[expr], nt]
  end

  def body_definitely_raises?(body_id)
    if body_id < 0
      return 0
    end
    stmts_r = get_stmts(body_id)
    if stmts_r.length == 0
      return 0
    end
    last = stmts_r[stmts_r.length - 1]
    if @nd_type[last] != "CallNode"
      return 0
    end
    if @nd_name[last] != "raise"
      return 0
    end
    1
  end

  def parse_raise_guard_narrow(nid)
    if nid < 0
      return ["", ""]
    end
    t = @nd_type[nid]
    if t == "UnlessNode"
      body_u = @nd_body[nid]
      if body_definitely_raises?(body_u) == 0
        return ["", ""]
      end
      return parse_is_a_predicate(@nd_predicate[nid])
    end
    if t == "IfNode"
      pred_i = @nd_predicate[nid]
      if pred_i < 0 || @nd_type[pred_i] != "CallNode" || @nd_name[pred_i] != "!"
        return ["", ""]
      end
      inner_i = @nd_receiver[pred_i]
      if inner_i < 0
        return ["", ""]
      end
      body_i = @nd_body[nid]
      if body_definitely_raises?(body_i) == 0
        return ["", ""]
      end
      sub_i = @nd_subsequent[nid]
      else_i = @nd_else_clause[nid]
      if sub_i >= 0 || else_i >= 0
        return ["", ""]
      end
      return parse_is_a_predicate(inner_i)
    end
    ["", ""]
  end

 # Nil-guard narrow helpers (parse_nil_predicate /
 # body_definitely_exits? / infer_nil_guard_narrow_type /
 # parse_nil_guard_var / scan_back_writer_narrow_for) moved
 # to compiler_helpers.rb -- shared with spinel_analyze.rb.

 # Try to evaluate a predicate expression at compile time. Returns
 # "TRUE" / "FALSE" when the result is known statically; "" when it
 # depends on runtime state. Currently handles `<typed>.is_a?(Klass)` /
 # `kind_of?(Klass)` / `instance_of?(Klass)` where the receiver's
 # static type clearly does or does not match the queried class —
 # this lets compile_if_expr / infer_type(IfNode) skip the dead arm
 # so the typed-friendly arm doesn't get widened to poly via unify.

  def set_var_type(name, vtype)
    i = @scope_names.length - 1
    while i >= 0
      if @scope_names[i] == name
        @scope_types[i] = vtype
        return
      end
      i = i - 1
    end
  end

 # ---- Class/Method lookup (all parallel arrays) ----
  def find_regexp_index(nid)
    if @nd_type[nid] == "RegularExpressionNode"
      pat = @nd_unescaped[nid]
      i = 0
      while i < @regexp_patterns.length
        if @regexp_patterns[i] == pat
          return i
        end
        i = i + 1
      end
      return -1
    end
 # A constant initialized to a regex literal forwards to the
 # underlying pattern, so `RX = /pat/; RX.match?(s)` and
 # `s =~ RX` dispatch to the engine instead of falling through
 # to the literal-`(-1)` / `sp_str_include` fallbacks.
 # Also unwrap `.freeze` (`PATTERN = /pat/.freeze`) — Prism wraps
 # the literal in a `freeze` CallNode whose receiver is the
 # RegularExpressionNode. .
    if @nd_type[nid] == "ConstantReadNode"
      cname = resolve_const_ref_name(nid)
      if cname != ""
        ci = find_const_idx(cname)
        if ci >= 0 && ci < @const_expr_ids.length
          eid = @const_expr_ids[ci]
          if eid >= 0 && @nd_type[eid] == "CallNode" && @nd_name[eid] == "freeze"
            recv_freeze = @nd_receiver[eid]
            if recv_freeze >= 0
              eid = recv_freeze
            end
          end
          if eid >= 0 && @nd_type[eid] == "RegularExpressionNode"
            return find_regexp_index(eid)
          end
        end
      end
    end
 # A local variable with exactly one write to a regex literal is
 # also resolvable. Multi-write or non-regex-write names were
 # marked ambiguous (-1) by scan_features.
    if @nd_type[nid] == "LocalVariableReadNode"
      lname = @nd_name[nid]
      i = 0
      while i < @local_regex_names.length
        if @local_regex_names[i] == lname
          return @local_regex_idx[i]
        end
        i = i + 1
      end
    end
    -1
  end

 # Returns a C expression evaluating to a `mrb_regexp_pattern *`, or "" if
 # the node isn't a regex source. Static literals resolve to their
 # pre-compiled `sp_re_pat_<i>` global; InterpolatedRegularExpressionNode
 # gets a runtime `sp_re_runtime_compile(...)` call. Centralizes the
 # dispatch so each =~/match?/match/gsub/sub/scan/split call site doesn't
 # have to repeat the InterpolatedRegex check.
  def regex_pat_c_expr(nid)
    ridx = find_regexp_index(nid)
    if ridx >= 0
      return "sp_re_pat_" + ridx.to_s
    end
    if @nd_type[nid] == "InterpolatedRegularExpressionNode"
      @needs_regexp = 1
      return compile_expr(nid)
    end
    ""
  end

 # Maps Prism's regex flag bits to the engine's `RE_FLAG_*` values and
 # returns a C bitwise-OR string ("0", "1", "1|6", etc.). Single source
 # of truth used by both the static-regex collector arm in scan_features
 # and the per-call-site helper emitted by emit_dyn_regex_helpers.
 # Prism: IGNORE_CASE=4, EXTENDED=8, MULTI_LINE=16.
 # Engine: IGNORECASE=1, MULTILINE=2, DOTALL=4, EXTENDED=8.
 # Ruby's /m (dot-matches-newline) maps to MULTILINE|DOTALL = 6.

 # Index of an InterpolatedRegularExpressionNode in @dyn_regex_node_ids,
 # or -1 if scan_features hasn't registered it (defensive — should not
 # happen for any reachable node).
  def find_dyn_regex_index(nid)
    i = 0
    while i < @dyn_regex_node_ids.length
      if @dyn_regex_node_ids[i] == nid
        return i
      end
      i = i + 1
    end
    -1
  end

  def find_class_idx(name)
    i = 0
    while i < @cls_names.length
      if @cls_names[i] == name
        return i
      end
      i = i + 1
    end
    -1
  end

 # Walk @cls_parents starting from `child_idx` and return 1 if we
 # ever land on `ancestor_idx`. Used by `is_a?(<Klass>)` on poly
 # receivers to enumerate descendant cls_ids — `recv.is_a?(C)` is
 # true when recv's class is C or any subclass of C, so we OR
 # together every cls_id whose parent chain reaches C.
  def cls_is_descendant(child_idx, ancestor_idx)
    ck = child_idx
    while ck >= 0
      pname = @cls_parents[ck]
      if pname == ""
        return 0
      end
      pi = find_class_idx(pname)
      if pi < 0
        return 0
      end
      if pi == ancestor_idx
        return 1
      end
      ck = pi
    end
    0
  end

  def find_method_idx(name)
    i = 0
    while i < @meth_names.length
      if @meth_names[i] == name
        return i
      end
      i = i + 1
    end
    -1
  end

  def method_rest_index(mi)
    if mi >= 0 && mi < @meth_rest_index.length
      return @meth_rest_index[mi]
    end
    -1
  end

  def find_const_idx(name)
    i = 0
    while i < @const_names.length
      if @const_names[i] == name
        return i
      end
      i = i + 1
    end
    -1
  end

 # ---- Class variable helpers ----
 # Qualified name for a class-var slot: `<ClassName>_<var>` where
 # <var> drops the leading @@. Codegen emits one C global named
 # `cvar_<qname>` per registered cvar.
  def cvar_qname(class_idx, var_name)
    cls = "Toplevel"
    if class_idx >= 0
      cls = @cls_names[class_idx]
    end
    bare = var_name
    if bare.length >= 2 && bare[0, 2] == "@@"
      bare = bare[2, bare.length - 2]
    end
    cls + "_" + bare
  end

  def find_cvar_idx(qname)
    i = 0
    while i < @cvar_names.length
      if @cvar_names[i] == qname
        return i
      end
      i = i + 1
    end
    -1
  end

 # Register or update a cvar's inferred type. Called from
 # collect_cvars during the pre-pass and (defensively) again from
 # compile_stmt when the write fires.
  def register_cvar(qname, t)
    ci = find_cvar_idx(qname)
    if ci >= 0
 # Widen on type disagreement: int + string -> poly. Conservative
 # for v1 -- when the gap matters we'll revisit.
      if @cvar_types[ci] != t && @cvar_types[ci] != "poly" && t != ""
        @cvar_types[ci] = "poly"
      end
      return ci
    end
    @cvar_names.push(qname)
    @cvar_types.push(t)
    @cvar_init_values.push("")
    @cvar_names.length - 1
  end

 # Try to compile-time fold a class-body cvar initializer. If the
 # value is a simple literal (Integer/Float/String/Symbol/True/
 # False/Nil), capture it as the static decl's initializer so the
 # cvar enters the program with the source's value rather than the
 # type default. Spinel doesn't run class-body statements at
 # startup, so without this fold a `class C; @@x = 42; end` leaves
 # cvar_C_x at 0 until the first write fires.

 # If the constant's initializer is a simple literal, return the
 # corresponding C expression. Otherwise return "" so callers fall
 # back to cst_<name> lookup. Enables propagation of:
 # N = 10 → 10 at use sites
 # PI = 3.14 → 3.14
 # GREETING = "hi" → ("\xff" "hi" + 1)
 # OK = true → TRUE
  def const_literal_c_value(ci)
    if ci < 0 || ci >= @const_expr_ids.length
      return ""
    end
    eid = @const_expr_ids[ci]
    if eid < 0
      return ""
    end
    et = @nd_type[eid]
    if et == "IntegerNode"
      return @nd_value[eid].to_s
    end
    if et == "FloatNode"
      return @nd_content[eid]
    end
    if et == "StringNode"
      return c_string_literal(@nd_content[eid])
    end
    if et == "TrueNode"
      return "TRUE"
    end
    if et == "FalseNode"
      return "FALSE"
    end
    if et == "NilNode"
      return "0"
    end
    if et == "SymbolNode"
      return compile_symbol_literal(@nd_content[eid])
    end
    ""
  end

 # Find method in class (search parent chain)
  def cls_find_method(ci, mname)
    names = @cls_meth_names[ci].split(";")
    j = 0
    while j < names.length
      if names[j] == mname
        return j
      end
      j = j + 1
    end
 # Check parent
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        return cls_find_method(pi, mname)
      end
    end
    -1
  end

 # Walk the parent chain looking for a method named `mname`.
 # Returns the class index that defines it (the owner), or -1.
 # `kind` selects @cls_cmeth_names ("cmeth") or @cls_meth_names
 # ("imeth"). Used by the dispatch lowering to find the static
 # owner before deciding whether a cls_id switch is needed.
  def cls_method_owner_for(ci, mname, kind)
    if ci < 0
      return -1
    end
    if kind == "cmeth"
      mnames = @cls_cmeth_names[ci].split(";")
    else
      mnames = @cls_meth_names[ci].split(";")
    end
    cj = 0
    while cj < mnames.length
      if mnames[cj] == mname
        return ci
      end
      cj = cj + 1
    end
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        return cls_method_owner_for(pi, mname, kind)
      end
    end
    -1
  end

 # Enumerate descendants of inner_ci (including inner_ci itself)
 # whose method owner differs from base_owner. Each entry is
 # encoded `<descendant_ci>,<owner_ci>` separated by `;`. Empty
 # string when no overrides exist (caller stays on the
 # static-dispatch path). `kind` is "cmeth" or "imeth".
  def cls_method_override_descendants(inner_ci, base_owner, mname, kind)
    out = ""
    ck = 0
    while ck < @cls_names.length
      if ck == inner_ci || cls_is_descendant(ck, inner_ci) == 1
        ow = cls_method_owner_for(ck, mname, kind)
        if ow >= 0 && ow != base_owner
          if out != ""
            out = out + ";"
          end
          out = out + ck.to_s + "," + ow.to_s
        end
      end
      ck = ck + 1
    end
    out
  end

 # Whether all imeth overrides in `pairs_str` have a param-type
 # signature compatible with `base_ptypes` (and same length).
 # Used as a gate on the cls_id-switch dispatch — without this,
 # an override declared with narrower param types than the base
 # would emit a C call site that doesn't match its signature.
  def cls_imeth_override_ptypes_match(pairs_str, mname, base_ptypes)
    pairs = pairs_str.split(";")
    pi = 0
    while pi < pairs.length
      p = pairs[pi].split(",")
      cand_owner = p[1].to_i
      cand_midx = cls_find_method_direct(cand_owner, mname)
      cand_pt = cls_meth_ptypes_get(cand_owner, cand_midx)
      if cand_pt.length != base_ptypes.length
        return 0
      end
      k = 0
      while k < base_ptypes.length
        if cand_pt[k] != base_ptypes[k]
          return 0
        end
        k = k + 1
      end
      pi = pi + 1
    end
    1
  end

 # `<arr>.method(:op)` for built-in array types: which (recv_type,
 # mname) pairs we can lower into a Method-dispatch adapter. Limited
 # to int_array's bracket ops + push for now (the optcarrot CPU
 # memory-mapping shape `@ram.method(:[]=)`); extend the body to
 # cover more (recv_type, mname) pairs as workloads need them.
  def builtin_array_method_supported(recv_type, mname)
    if recv_type == "int_array"
      if mname == "[]" || mname == "[]=" || mname == "push"
        return 1
      end
    end
    0
  end

  def builtin_array_type_pfx(recv_type)
    if recv_type == "int_array"
      return "IntArray"
    end
    ""
  end

 # Emit a per-(array_type, mname) trampoline that fits the Method
 # dispatch ABI `(void *self, mrb_int...) -> mrb_int`. The body
 # forwards to the corresponding `sp_<Pfx>_<op>` runtime function;
 # write-style ops (`[]=`, `push`) return the rhs the way Ruby's
 # bracket-write does. Idempotent: re-emitting the same key is a
 # no-op. Reuses @cls_method_adapters with a `@@`-prefixed key so
 # it cannot collide with a user-class method adapter entry.
  def emit_builtin_array_method_adapter(recv_type, mname)
    key = "@@" + recv_type + "::" + mname
    k = 0
    while k < @cls_method_adapters.length
      if @cls_method_adapters[k] == key
        return
      end
      k = k + 1
    end
    @cls_method_adapters.push(key)
    pfx = builtin_array_type_pfx(recv_type)
    if pfx == ""
      return
    end
    cast = "(sp_" + pfx + " *)"
    adapter_name = "sp_" + pfx + "_" + sanitize_name(mname) + "_builtin_method_adapter"
    if recv_type == "int_array" && mname == "[]"
      @lambda_funcs << "static mrb_int "
      @lambda_funcs << adapter_name
      @lambda_funcs << "(void *_self, mrb_int _i) {\n"
      @lambda_funcs << "  return sp_IntArray_get("
      @lambda_funcs << cast
      @lambda_funcs << "_self, _i);\n"
      @lambda_funcs << "}\n"
      return
    end
    if recv_type == "int_array" && mname == "[]="
      @lambda_funcs << "static mrb_int "
      @lambda_funcs << adapter_name
      @lambda_funcs << "(void *_self, mrb_int _i, mrb_int _v) {\n"
      @lambda_funcs << "  sp_IntArray_set("
      @lambda_funcs << cast
      @lambda_funcs << "_self, _i, _v);\n"
      @lambda_funcs << "  return _v;\n"
      @lambda_funcs << "}\n"
      return
    end
    if recv_type == "int_array" && mname == "push"
      @lambda_funcs << "static mrb_int "
      @lambda_funcs << adapter_name
      @lambda_funcs << "(void *_self, mrb_int _v) {\n"
      @lambda_funcs << "  sp_IntArray_push("
      @lambda_funcs << cast
      @lambda_funcs << "_self, _v);\n"
      @lambda_funcs << "  return _v;\n"
      @lambda_funcs << "}\n"
      return
    end
    nil
  end

 # Emit a one-off adapter that wraps `sp_<Klass>_cls_<mname>` so the
 # Method dispatch ABI `(void *self, mrb_int...)` works on a class
 # method (which has no self param). Idempotent: re-emitting the
 # same (Klass, mname) pair is a no-op. Buffered into @lambda_funcs
 # so the function lands at the same insertion point as lambdas
 # (before main, after forward declarations of every cls method).
  def emit_cls_method_adapter(ci, mname)
    cname = @cls_names[ci]
    key = cname + "::" + mname
    k = 0
    while k < @cls_method_adapters.length
      if @cls_method_adapters[k] == key
        return
      end
      k = k + 1
    end
    @cls_method_adapters.push(key)

    cmnames = @cls_cmeth_names[ci].split(";")
    cm_returns = @cls_cmeth_returns[ci].split(";")
    j = 0
    while j < cmnames.length
      if cmnames[j] == mname
        break
      end
      j = j + 1
    end
    rt = "int"
    if j < cm_returns.length
      rt = cm_returns[j]
    end
    pt_list = cls_cmeth_ptypes_get(ci, j)
    base_name = "sp_" + cname + "_cls_" + sanitize_name(mname)
    adapter_name = "sp_" + cname + "_" + sanitize_name(mname) + "_cls_method_adapter"
    sig = c_type(rt) + " " + adapter_name + "(void *_unused"
    body_args = ""
    pi2 = 0
    while pi2 < pt_list.length
      sig = sig + ", mrb_int _a" + pi2.to_s
      if pi2 == 0
        body_args = "_a" + pi2.to_s
      else
        body_args = body_args + ", _a" + pi2.to_s
      end
      pi2 = pi2 + 1
    end
    sig = sig + ")"
    @lambda_funcs << "static "
    @lambda_funcs << sig
    @lambda_funcs << " {\n"
    if rt == "void"
      @lambda_funcs << "  "
      @lambda_funcs << base_name
      @lambda_funcs << "("
      @lambda_funcs << body_args
      @lambda_funcs << ");\n"
      @lambda_funcs << "  return 0;\n"
    else
      @lambda_funcs << "  return "
      @lambda_funcs << base_name
      @lambda_funcs << "("
      @lambda_funcs << body_args
      @lambda_funcs << ");\n"
    end
    @lambda_funcs << "}\n"
    nil
  end


  def cls_method_return(ci, mname, kind = "imeth")
    if ci < 0
      return "int"
    end
    if kind == "cmeth"
      names = @cls_cmeth_names[ci].split(";")
      returns = @cls_cmeth_returns[ci].split(";")
    else
      names = @cls_meth_names[ci].split(";")
      returns = @cls_meth_returns[ci].split(";")
    end
    j = 0
    while j < names.length
      if names[j] == mname
        if j < returns.length
          return returns[j]
        end
        return "int"
      end
      j = j + 1
    end
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        return cls_method_return(pi, mname, kind)
      end
    end
    "int"
  end

 # Get ivar type from class
  def cls_ivar_type(ci, iname)
    names = @cls_ivar_names[ci].split(";")
    types = @cls_ivar_types[ci].split(";")
    own_t = ""
    j = 0
    while j < names.length
      if names[j] == iname
        if j < types.length
          own_t = types[j]
        else
          own_t = "int"
        end
        break
      end
      j = j + 1
    end
    parent_t = ""
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0 && ivar_in_chain(pi, iname) == 1
        parent_t = cls_ivar_type(pi, iname)
      end
    end
 # The struct embeds parent ivars at the parent's recorded type
 # (`emit_class_fields` skips own copies that are also in the
 # parent chain). When the parent has the same ivar, the parent's
 # type is what the C struct field actually has — so any access
 # through `self->iv_X` must agree with that, regardless of what
 # this child's own table happened to record. Defer to the parent
 # type when both classes know the ivar.
    if parent_t != ""
      return parent_t
    end
    if own_t != ""
      return own_t
    end
    "int"
  end

 # ---- Emit helpers ----
  def emit(s)
    ind = ""
    j = 0
    while j < @indent
      ind = ind + "  "
      j = j + 1
    end
    @out_lines.push(ind + s)
  end

  def emit_raw(s)
    @out_lines.push(s)
  end


 # ---- Type inference ----
 # `node_type` is the codegen's interface to per-AST-node types.
 # When the cache has been pre-filled (analyze→codegen split path)
 # this is an O(1) array read. Otherwise it's a transparent forward
 # to infer_type. We do NOT lazily fill the cache from emission paths
 # because emission can mutate analysis state (auto_register_attr_*,
 # @needs_* side-flags, etc.) and a cached value would freeze before
 # those mutations land.

  def infer_type(nid)
    if nid < 0
      return "void"
    end
 # `<poly>[idx]` — analyze may cache an optimistic concrete type
 # (e.g. "int" picked from one observed elem kind), but
 # compile_poly_method_call's actual emit widens to sp_RbVal
 # whenever its narrow_int check fails (e.g. block-param recv).
 # When the cache disagrees with the emit, downstream consumers
 # (compile_arg0_as_int for `>>` / `<<`, ...) skip the unbox and
 # produce `int >> sp_RbVal` in C — fails C compile. Compute the
 # answer that mirrors the actual emit, before honouring the
 # cache.
    pa = poly_aref_call_type(nid)
    if pa != ""
      return pa
    end
 # Sibling-scope narrow override: when the active narrow stack
 # narrows `x` to `obj_<C>` and this CallNode is `x.attr` where
 # `attr` is an attr_reader on `C`, the cached type (filled by
 # analyze's walk_and_cache before the narrow was active) is
 # stale. Resolve the attr_reader directly off the narrowed
 # class's ivar table and return its type, bypassing the cache.
 # Issue #493. Cheap: only fires when narrow is non-empty AND
 # the node is `LV(narrowed_name).attr_reader_name`.
    if @type_narrow_names.length > 0 && @nd_type[nid] == "CallNode"
      narrow_recv_id = @nd_receiver[nid]
      if narrow_recv_id >= 0 && @nd_type[narrow_recv_id] == "LocalVariableReadNode"
        narrow_lvname = @nd_name[narrow_recv_id]
        narrow_t_lookup = ""
        ki_nt = @type_narrow_names.length - 1
        while ki_nt >= 0
          if @type_narrow_names[ki_nt] == narrow_lvname
            narrow_t_lookup = @type_narrow_types[ki_nt]
            ki_nt = -1
          else
            ki_nt = ki_nt - 1
          end
        end
        if is_obj_type(narrow_t_lookup) == 1
          ncname_nt = narrow_t_lookup[4, narrow_t_lookup.length - 4]
          nci_nt = find_class_idx(ncname_nt)
          if nci_nt >= 0
            mname_nt = @nd_name[nid]
            if cls_has_attr_reader(nci_nt, mname_nt) == 1
              return cls_ivar_type(nci_nt, "@" + mname_nt)
            end
          end
        end
      end
    end
 # Cache lookup. analyze.rb's annotate_all_node_types fills
 # @nd_inferred_type for every reachable node OUTSIDE block bodies
 # (block-iteration scope is iterator-specific and dispatched at
 # emit time, so block-body nodes are intentionally left empty
 # for codegen's own infer_type to handle).
    cached = @nd_inferred_type[nid]
    if cached != ""
      return cached
    end
    t = @nd_type[nid]
    if t == "SuperNode" || t == "ForwardingSuperNode"
 # `super` returns whatever the parent's same-named method
 # returns. Walk to the parent's `find_method_owner`-resolved
 # method and read its return type.
      if @current_class_idx >= 0 && @current_method_name != ""
        parent_name_st = @cls_parents[@current_class_idx]
        if parent_name_st != ""
          parent_ci_st = find_class_idx(parent_name_st)
          if parent_ci_st >= 0
            owner_st = find_method_owner(parent_ci_st, @current_method_name)
            if owner_st != ""
              ret_st = cls_method_return(find_class_idx(owner_st), @current_method_name)
              if ret_st != ""
                return ret_st
              end
            end
          end
        end
      end
      return "int"
    end
 # Leaf literal-shaped nodes. analyze caches these for nearly
 # every reachable site, but ieval bodies (instance_eval-rewritten
 # method calls) aren't visited by walk_and_cache, so the fallback
 # has to handle them or compile_call would mis-type a "/" arg as
 # int and dispatch sp_int_to_s on a string.
    if t == "IntegerNode"
      return "int"
    end
    if t == "FloatNode"
      return "float"
    end
    if t == "StringNode" || t == "SourceFileNode" || t == "SourceEncodingNode" || t == "NumberedReferenceReadNode" || t == "InterpolatedStringNode" || t == "InterpolatedSymbolNode" || t == "BackReferenceReadNode" || t == "XStringNode" || t == "InterpolatedXStringNode"
      return "string"
    end
    if t == "SymbolNode"
      return "symbol"
    end
    if t == "MatchWriteNode"
      return "int"
    end
    if t == "TrueNode" || t == "FalseNode"
      return "bool"
    end
    if t == "NilNode"
      return "nil"
    end
    if t == "ArrayNode"
      return infer_array_elem_type(nid)
    end
    if t == "HashNode"
      if is_int_array_lowered_hash(nid) == 1
        return infer_int_keyed_hash_as_array_type(nid)
      end
      return infer_hash_val_type(nid)
    end
    if t == "RangeNode"
      return "range"
    end
    if t == "RescueModifierNode"
 # `expr rescue fallback` — unify the types of the two branches.
 # The fallback always runs on error, so prefer its type when the
 # main branch is a noreturn-shaped expression like a bare `raise`
 # (whose compile_expr returns the int literal `0`).
      t1 = infer_type(@nd_expression[nid])
      t2 = infer_type(@nd_else_clause[nid])
      if t1 == t2
        return t1
      end
      if t2 != "void" && t2 != "nil"
        return t2
      end
      return t1
    end
    if t == "ReturnNode"
 # `return X` evaluated in expression position — same shape as
 # collect_return_types' ReturnNode arm in spinel_analyze.rb.
 # Without this case the universal `"int"` fallback fires; in
 # practice that's demoted by unify_return_type's int-as-sentinel
 # logic when paired with a concrete type from collect_return_types,
 # but returning the actual arg type makes infer_type semantically
 # correct and resilient to future sentinel-handling changes.
 # `return a, b` materializes as a fixed-arity tuple; bare `return`
 # contributes "nil" matching CRuby.
      args_id = @nd_arguments[nid]
      if args_id >= 0
        arg_ids = get_args(args_id)
        if arg_ids.length == 1
          return infer_type(arg_ids[0])
        end
        if arg_ids.length > 1
          return tuple_type_from_elems(arg_ids)
        end
      end
      return "nil"
    end
    if t == "BeginNode"
 # Method bodies that end in `def f; X; rescue; Y; end` need
 # the method's inferred return type to unify both branches.
 # Without this arm spinel falls back to int (the default), and
 # string-returning rescue bodies fail C compilation when the
 # ret_tmp slot's type doesn't match the value being assigned.
      types_b = "".split(",")
      bodies_b = begin_node_arm_bodies(nid)
      bi = 0
      while bi < bodies_b.length
        bstmts = get_stmts(bodies_b[bi])
        if bstmts.length > 0
          types_b.push(infer_type(bstmts.last))
        end
        bi = bi + 1
      end
      if types_b.length > 0
        return unify_return_type(types_b)
      end
      return "void"
    end
    if t == "LocalVariableReadNode"
      vt = find_var_type(@nd_name[nid])
      if vt != ""
        return vt
      end
      return "int"
    end
    if t == "LocalVariableWriteNode"
 # `var = expr` used as an expression — the value of the
 # expression is the assigned slot's value (after any boxing
 # done by the LocalVariableWriteNode emit path). Reporting the
 # slot type lets compile_cond_expr know to wrap with
 # sp_poly_truthy when the slot is poly (e.g.
 # `if (sprite = arr[i])` where sprite is a sp_RbVal local).
      vt = find_var_type(@nd_name[nid])
      if vt != ""
        return vt
      end
      return infer_type(@nd_expression[nid])
    end
    if t == "IndexOrWriteNode" || t == "IndexAndWriteNode" || t == "IndexOperatorWriteNode"
 # `recv[k] ||= v` (etc.) as an expression value. The result type
 # is the recv's element type — same shape as Hash#[] / Array#[]
 # — so callers like LocalVariableWriteNode can pick the right
 # local slot type via the same lookup that `recv[k]` would use.
      iow_recv_t = @nd_receiver[nid]
      if iow_recv_t >= 0
        rt_iow_t = infer_type(iow_recv_t)
        leaf_iow = hash_leaf_type(rt_iow_t)
        if leaf_iow != ""
          return leaf_iow
        end
        if rt_iow_t == "int_array" || rt_iow_t == "float_array" || rt_iow_t == "str_array" || rt_iow_t == "sym_array"
          return elem_type_of_array(rt_iow_t)
        end
 # poly_array elements are sp_RbVal; chained IndexOrWriteNode
 # over a poly_array recv (or a poly-typed recv that carries a
 # poly_array at runtime) returns the element value as poly so
 # the next chain link sees an sp_RbVal, not the int default.
        if rt_iow_t == "poly_array" || rt_iow_t == "poly"
          return "poly"
        end
      end
      return "int"
    end
    if t == "GlobalVariableReadNode"
 # `alias $copy $orig` -- a $copy read must look up $orig's
 # registered type so the C codegen sees the correct format
 # specifier when interpolating or printing.
      gname = resolve_gvar_alias(@nd_name[nid])
      gi = 0
      while gi < @gvar_names.length
        if @gvar_names[gi] == gname
          return @gvar_types[gi]
        end
        gi = gi + 1
      end
      return "int"
    end
    if t == "InstanceVariableOrWriteNode" || t == "InstanceVariableAndWriteNode"
 # `(@x ||= expr)` / `(@x &&= expr)` evaluates to @x's slot type
 # (union of the prior value and the rhs, but Spinel widens those
 # via update_ivar_type already, so reading the slot type is the
 # same answer).
      if @current_class_idx >= 0
        return cls_ivar_type(@current_class_idx, @nd_name[nid])
      end
      return "int"
    end
    if t == "InstanceVariableReadNode"
      if @current_class_idx >= 0
        return cls_ivar_type(@current_class_idx, @nd_name[nid])
      end
 # Inside a module class method (`def self.foo` in `module M`,
 # compiled as the top-level `M_cls_foo`), an ivar read like
 # `@slots` resolves to `cst_M_slots` — already handled by
 # compile_expr's matching arm. Mirror that resolution here so
 # infer_type returns the slot's recorded hash/array type
 # instead of the "int" default, which would otherwise route
 # `@slots[k]` through the int-bit-extract codegen even though
 # the storage is a hash.
      mi3 = 0
      while mi3 < @module_names.length
        mmod = @module_names[mi3]
        if mmod != "" && @current_method_name.start_with?(mmod + "_cls_")
          iname = @nd_name[nid]
          cname3 = mmod + "_" + iname[1, iname.length - 1]
          ci3 = find_const_idx(cname3)
          if ci3 >= 0
            return @const_types[ci3]
          end
        end
        mi3 = mi3 + 1
      end
      tit = toplevel_ivar_type(@nd_name[nid])
      if tit != ""
        return tit
      end
      return "int"
    end
    if t == "ClassVariableReadNode"
      qname = cvar_qname(@current_class_idx, @nd_name[nid])
      ci = find_cvar_idx(qname)
      if ci >= 0
        return @cvar_types[ci]
      end
      return "int"
    end
    if t == "ClassVariableWriteNode"
 # `@@x = expr` as an expression returns the assigned value, so
 # the static type is the rhs's type. Without this case the
 # caller's `infer_type` falls through to the default (int) and
 # surrounding code -- e.g. a method whose body's last
 # expression is `@@x = v` -- gets `mrb_int` as the inferred
 # return, producing a const char* / mrb_int mismatch when v
 # is a string.
      return infer_type(@nd_expression[nid])
    end
    if t == "ConstantReadNode"
      if @nd_name[nid] == "ARGV"
        return "argv"
      end
      rname = resolve_const_read_name(@nd_name[nid])
      ci = find_const_idx(rname)
      if ci >= 0
        return @const_types[ci]
      end
      cx = find_class_idx(rname)
      if cx >= 0
 # a class constant in value position is
 # a sp_Class value carrying its cls_id. Other call sites that
 # still want the "this name is a class, not a value" signal
 # (constructor lookups, class-method dispatch) consult
 # find_class_idx directly via constructor_class_name and
 # never call infer_type on the receiver.
        return "class"
      end
      return "int"
    end
    if t == "ConstantPathNode"
      cpname = resolve_const_ref_name(nid)
      if cpname != ""
        ci = find_const_idx(cpname)
        if ci >= 0
          return @const_types[ci]
        end
        cx = find_class_idx(cpname)
        if cx >= 0
 # class constant in value position.
          return "class"
        end
      end
      parent = @nd_receiver[nid]
      if parent >= 0
        rname = resolve_const_ref_name(parent)
        if rname == "Float"
          return "float"
        end
        if rname == "Math"
          return "float"
        end
      end
      return "int"
    end
    if t == "CallNode"
 # CallNode falls here only on cache miss. analyze's
 # walk_and_cache covers ~99% of CallNodes; the remaining
 # misses are:
 # - bare `new` in an inherited class method body —
 # resolution depends on the calling subclass at emit time,
 # not the lexical class, so analyze can't safely cache)
 # - block bodies of proc / lambda / Fiber.new / Proc.new
 # (skipped because the param's runtime type depends on the
 # caller, and codegen's compile_lambda_def hardcodes the
 # param as int regardless)
 # Bare `new` resolves via current_class_method_owning_class so
 # subclass-context-sensitive constructions land on the right
 # class. Everything else defaults to "int" — for proc/lambda
 # block bodies that matches compile_lambda_def's hardcoded
 # param type.
      if @nd_name[nid] == "new" && @nd_receiver[nid] < 0
        implicit = current_class_method_owning_class
        if implicit != ""
          return "obj_" + implicit
        end
      end
 # Bare class-method call inside a class-method body (`def
 # self.last; all[-1]; end` — both `all` and `last` are cmeths
 # on the same class hierarchy). analyze skips the cache for
 # these nodes (see analyze's walk_and_cache skip_cache arm)
 # because inherited bodies share AST node ids across subclass
 # copies; the resolution must follow the *current* emit-time
 # @current_class_idx, not whichever class walked last during
 # annotate. Mirror analyze's @cls_cmeth_returns lookup so the
 # cache-miss path picks up the subclass's override. Issue #523.
      if @nd_receiver[nid] < 0 && @current_class_idx >= 0 && @current_method_has_self == 0
        mn_cmeth = @nd_name[nid]
        cmnames_cm_dispatch = @cls_cmeth_names[@current_class_idx].split(";")
        cmreturns_cm_dispatch = @cls_cmeth_returns[@current_class_idx].split(";")
        kk_cm = 0
        while kk_cm < cmnames_cm_dispatch.length
          if cmnames_cm_dispatch[kk_cm] == mn_cmeth && kk_cm < cmreturns_cm_dispatch.length
            return cmreturns_cm_dispatch[kk_cm]
          end
          kk_cm = kk_cm + 1
        end
      end
 # Comparison / boolean operators always return bool, regardless
 # of recv type. scan_lambda_ret_types calls infer_type on a
 # lambda body's last expr — when that's `a > b` inside a
 # lambda body that walk_and_cache skipped, the cache misses
 # and this fallback used to default to "int", which made the
 # outer `.to_s` emit `sp_int_to_s(...)` instead of the bool
 # ternary `(... ? "true" : "false")`.
      cmp_mname = @nd_name[nid]
      if cmp_mname == "block_given?"
        cmp_recv = @nd_receiver[nid]
        if cmp_recv < 0 || (cmp_recv >= 0 && @nd_type[cmp_recv] == "SelfNode")
          return "bool"
        end
      end
      if cmp_mname == "<" || cmp_mname == ">" || cmp_mname == "<=" || cmp_mname == ">=" || cmp_mname == "==" || cmp_mname == "!=" || cmp_mname == "===" || cmp_mname == "eql?" || cmp_mname == "equal?" || cmp_mname == "is_a?" || cmp_mname == "kind_of?" || cmp_mname == "instance_of?" || cmp_mname == "respond_to?" || cmp_mname == "include?" || cmp_mname == "start_with?" || cmp_mname == "end_with?" || cmp_mname == "match?" || cmp_mname == "empty?" || cmp_mname == "nil?" || cmp_mname == "zero?" || cmp_mname == "even?" || cmp_mname == "odd?" || cmp_mname == "frozen?"
        return "bool"
      end
 # `+` on string recv returns string — walk_and_cache skips
 # block bodies of `each`-family / proc / lambda, so a chained
 # concat like `puts k + ": " + v.to_s` inside a hash `.each do
 # |k, v|` block hits this cache-miss path. Without this arm
 # infer_type fell back to the "int" default below, the inner
 # `k + ": "` got typed as int, and `puts` lowered to
 # `printf("%lld", (long long)(string_call + int_call))` — both
 # the cast and the raw `+` between pointers fail C compile.
      if cmp_mname == "+"
        cm_recv = @nd_receiver[nid]
        if cm_recv >= 0
          cm_rt = infer_type(cm_recv)
          if cm_rt == "string" || cm_rt == "mutable_str"
            return "string"
          end
        end
      end
 # `.to_s` returns string regardless of recv (the only exception
 # is `obj.to_s` falling through to a user-defined `to_s` that
 # returned something else — rare; the cache covers that case).
      if cmp_mname == "to_s"
        return "string"
      end
 # `lv.call(...)` / `lv.()` on a lambda local — recover the
 # lambda's recorded return type from @lambda_var_ret_*.
 # walk_and_cache skips lambda bodies, so the call itself isn't
 # cached; without this the outer `.to_s` (etc.) would default
 # to "int" and emit sp_int_to_s on a bool/string return.
      if cmp_mname == "call" || cmp_mname == "[]"
        cmp_recv = @nd_receiver[nid]
        if cmp_recv >= 0 && @nd_type[cmp_recv] == "LocalVariableReadNode"
          lrt = lambda_var_ret_type(@nd_name[cmp_recv])
          if lrt != ""
            return lrt
          end
        end
      end
      return "int"
    end
    if t == "IfNode"
      then_type = "nil"
      body = @nd_body[nid]
      if body >= 0
        stmts = get_stmts(body)
        if stmts.length > 0
          then_type = infer_type(stmts.last)
        end
      end
      else_type = "nil"
      sub = @nd_subsequent[nid]
      if sub >= 0
        if @nd_type[sub] == "ElseNode"
          ebody = @nd_body[sub]
          if ebody >= 0
            es = get_stmts(ebody)
            if es.length > 0
              else_type = infer_type(es.last)
            end
          end
        else
 # elsif chain — recurse
          else_type = infer_type(sub)
        end
      end
      types = "".split(",")
      types.push(then_type)
      types.push(else_type)
      return unify_return_type(types)
    end
    if t == "CaseMatchNode"
      types = "".split(",")
      conds = parse_id_list(@nd_conditions[nid])
      k = 0
      while k < conds.length
        inid = conds[k]
        if @nd_type[inid] == "InNode"
          ibody = @nd_body[inid]
          if ibody >= 0
            is = get_stmts(ibody)
            if is.length > 0
              types.push(infer_type(is.last))
            end
          end
        end
        k = k + 1
      end
      ec = @nd_else_clause[nid]
      if ec >= 0
        ebody = @nd_body[ec]
        if ebody >= 0
          es = get_stmts(ebody)
          if es.length > 0
            types.push(infer_type(es.last))
          end
        end
      end
      if types.length > 0
        return unify_return_type(types)
      end
      return "int"
    end
    if t == "CaseNode"
      types = "".split(",")
      conds = parse_id_list(@nd_conditions[nid])
      k = 0
      while k < conds.length
        wid = conds[k]
        if @nd_type[wid] == "WhenNode"
          wbody = @nd_body[wid]
          if wbody >= 0
            ws = get_stmts(wbody)
            if ws.length > 0
              types.push(infer_type(ws.last))
            end
          end
        end
        k = k + 1
      end
      ec = @nd_else_clause[nid]
      if ec >= 0
        ebody = @nd_body[ec]
        if ebody >= 0
          es = get_stmts(ebody)
          if es.length > 0
            types.push(infer_type(es.last))
          end
        end
      end
      if types.length > 0
        return unify_return_type(types)
      end
      return "int"
    end
    if t == "AndNode"
      return "bool"
    end
    if t == "OrNode"
      return or_result_type(nid)
    end
    if t == "ParenthesesNode"
      body = @nd_body[nid]
      if body >= 0
        stmts = get_stmts(body)
        if stmts.length > 0
          return infer_type(stmts.last)
        end
      end
      return "void"
    end
    if t == "SelfNode"
      if @current_class_idx >= 0
        return "obj_" + @cls_names[@current_class_idx]
      end
      st = find_var_type("__self_type")
      if st != ""
        return st
      end
      return "int"
    end
    if t == "LambdaNode"
 # Record return type if inside a variable assignment context
      lbody = @nd_body[nid]
      if lbody >= 0
        lbs = get_stmts(lbody)
        if lbs.length > 0
          lrt = infer_type(lbs.last)
          @last_lambda_ret_type = lrt
        end
      end
      return "lambda"
    end
    "int"
  end

  def infer_array_elem_type(nid)
    infer_array_elem_type_from_ids(parse_id_list(@nd_elements[nid]))
  end

 # Body of infer_array_elem_type, parameterised on the list of value
 # node ids. Lets a {0=>v0,1=>v1,...} HashNode lowered to an Array
 # share the same type-inference logic by feeding in [v0, v1, ...]
 # without needing an actual ArrayNode to host them.
  def infer_array_elem_type_from_ids(elems)
    if elems.length > 0
      et = infer_type(elems[0])
      if et == "symbol"
 # Check if ALL elements are symbols
        all_sym = 1
        k = 1
        while k < elems.length
          if infer_type(elems[k]) != "symbol"
            all_sym = 0
          end
          k = k + 1
        end
        if all_sym == 1
          return "sym_array"
        end
        return "poly_array"
      end
      if et == "string"
 # Check if ALL elements are strings
        all_str = 1
        k = 1
        while k < elems.length
          if infer_type(elems[k]) != "string"
            all_str = 0
          end
          k = k + 1
        end
        if all_str == 1
          return "str_array"
        end
        return "poly_array"
      end
      if et == "float"
 # Check if ALL elements are float
        all_float = 1
        k = 1
        while k < elems.length
          if infer_type(elems[k]) != "float"
            all_float = 0
          end
          k = k + 1
        end
        if all_float == 1
          return "float_array"
        end
      end
 # Check if all elements are the same obj type → ptr_array
      if is_obj_type(et) == 1
        all_same = 1
        k = 1
        while k < elems.length
          if infer_type(elems[k]) != et
            all_same = 0
          end
          k = k + 1
        end
        if all_same == 1
          @needs_gc = 1
          return et + "_ptr_array"
        end
        return "poly_array"
      end
 # Check if all elements are the same array type → array of arrays
      if et == "int_array" || et == "str_array" || et == "float_array" || et == "sym_array"
        all_same = 1
        k = 1
        while k < elems.length
          if infer_type(elems[k]) != et
            all_same = 0
          end
          k = k + 1
        end
        if all_same == 1
          @needs_gc = 1
          return et + "_ptr_array"
        end
        return "poly_array"
      end
 # Nested-deeper case: elements are themselves a typed
 # ptr_array (`int_array_ptr_array`, etc.) or already
 # poly_array. Spinel doesn't have a typed
 # `<X>_ptr_array_ptr_array` slot, so box each level via
 # poly_array — sp_box_*_array on each push, and the
 # poly-builtin dispatch on `[]` recurses into the next
 # level.
      if is_ptr_array_type(et) == 1 || et == "poly_array"
        @needs_gc = 1
        @needs_rb_value = 1
        return "poly_array"
      end
 # Hash literals as elements (`[{n: 3}, {n: 1}]`): each
 # element is a heap-allocated hash pointer. Spinel has no
 # typed `<hash>_ptr_array` slot, so box via poly_array;
 # sp_box_hash_to_poly is called on each push and the
 # poly-builtin dispatch on `arr[i]` recovers the hash.
 # Without this arm, the array's inferred type fell back to
 # `int_array` (the bottom of this function), and
 # `sp_IntArray_push` was called with a hash pointer —
 # int-from-pointer C-compile error.
      if is_hash_type(et) == 1
        @needs_gc = 1
        @needs_rb_value = 1
        return "poly_array"
      end
 # Proc / lambda literals as elements (`[proc { ... }, proc { ... }]`):
 # see the analyzer's mirror branch. Spinel has no typed
 # `proc_ptr_array` slot, so box via poly_array — sp_box_proc on
 # each push.
      if et == "proc" || et == "lambda"
        @needs_gc = 1
        @needs_rb_value = 1
        return "poly_array"
      end
 # `String.new` (and locals widened to mutable_str via `s = ""; s << ...`)
 # produces sp_String* values. Lower an all-mutable_str literal to a
 # mutable_str_ptr_array — a sp_PtrArray of sp_String* — so the generic
 # `<X>_ptr_array` codegen path (length/push/pop/[]) works without
 # truncating the pointer to int. Mirrors the analyzer's arm; issue #519.
      if et == "mutable_str"
        all_same = 1
        k = 1
        while k < elems.length
          if infer_type(elems[k]) != "mutable_str"
            all_same = 0
          end
          k = k + 1
        end
        if all_same == 1
          @needs_gc = 1
          return "mutable_str_ptr_array"
        end
        @needs_gc = 1
        @needs_rb_value = 1
        return "poly_array"
      end
 # Check if elements have mixed types
      k = 1
      while k < elems.length
        et2 = infer_type(elems[k])
        if et2 != et
          return "poly_array"
        end
        k = k + 1
      end
    end
    "int_array"
  end

 # Detects a Hash literal whose keys are the consecutive non-negative
 # integers 0, 1, ..., N-1 in source order. Such a literal is
 # semantically equivalent to the Array `[v0, v1, ..., vN-1]` for the
 # common `H[k]` lookup pattern, so we lower it to an Array
 # internally — no `int_<X>_hash` runtime type needed. Detection is
 # AST-shape only (IntegerNode key with literal value `k` at index
 # `k`); any deviation (gap, duplicate, non-integer key, splat) opts
 # back into the regular hash codegen.
  def is_int_array_lowered_hash(nid)
    if @nd_type[nid] != "HashNode"
      return 0
    end
    elems = parse_id_list(@nd_elements[nid])
    if elems.length == 0
      return 0
    end
    k = 0
    while k < elems.length
      eid = elems[k]
      if @nd_type[eid] != "AssocNode"
        return 0
      end
      kid = @nd_key[eid]
      if kid < 0 || @nd_type[kid] != "IntegerNode"
        return 0
      end
      if @nd_value[kid].to_i != k
        return 0
      end
      k = k + 1
    end
    1
  end

 # Returns the array type the lowered HashNode evaluates to. Same
 # logic as infer_array_elem_type but reads each AssocNode's value.
  def infer_int_keyed_hash_as_array_type(nid)
    elems = parse_id_list(@nd_elements[nid])
    vids = []
    k = 0
    while k < elems.length
      vids.push(@nd_expression[elems[k]])
      k = k + 1
    end
    infer_array_elem_type_from_ids(vids)
  end

  def infer_hash_val_type(nid)
    elems = parse_id_list(@nd_elements[nid])
    if elems.length > 0
      eid = elems[0]
      if @nd_type[eid] == "AssocNode"
        first_vt = infer_type(@nd_expression[eid])
 # Check if all values have the same type
        all_same = 1
        k = 1
        while k < elems.length
          eid2 = elems[k]
          if @nd_type[eid2] == "AssocNode"
            vt2 = infer_type(@nd_expression[eid2])
            if vt2 != first_vt
              all_same = 0
            end
          end
          k = k + 1
        end
 # Detect all-symbol keys → sym_int_hash variant for int-valued
 # hashes. (sym_str_hash etc. not yet implemented; they fall
 # through to str_str_hash with sym_to_s wrapping at hash sites.)
        all_sym_keys = 1
        kk = 0
        while kk < elems.length
          ekid = elems[kk]
          if @nd_type[ekid] == "AssocNode"
            kid = @nd_key[ekid]
            if kid < 0 || @nd_type[kid] != "SymbolNode"
              all_sym_keys = 0
            end
          end
          kk = kk + 1
        end
        all_int_keys = 1
        ki = 0
        while ki < elems.length
          ekid2 = elems[ki]
          if @nd_type[ekid2] == "AssocNode"
            kid2 = @nd_key[ekid2]
            if kid2 < 0 || @nd_type[kid2] != "IntegerNode"
              all_int_keys = 0
            end
          end
          ki = ki + 1
        end
        if all_same == 1
          if first_vt == "string"
            if all_int_keys == 1
              return "int_str_hash"
            end
            if all_sym_keys == 1
              return "sym_str_hash"
            end
            return "str_str_hash"
          end
          if all_sym_keys == 1 && (first_vt == "int" || first_vt == "bool" || first_vt == "nil")
            return "sym_int_hash"
          end
 # Symbol values get sym_poly_hash storage so dig / lookup
 # preserves the SP_TAG_SYM tag. Issue #555 case 07.
          if all_sym_keys == 1 && first_vt == "symbol"
            @needs_rb_value = 1
            return "sym_poly_hash"
          end
 # Every value already inferred as poly (the slot was
 # widened upstream — typically an ivar that
 # finalize_ivar_heterogeneity widened on a sibling-writer
 # disagreement). Use the same poly-hash storage as the
 # mixed-types `else` branch — every value carries its
 # own tag.
          if first_vt == "poly"
            if all_sym_keys == 1
              return "sym_poly_hash"
            end
            return "str_poly_hash"
          end
 # Inner hash/array values need a poly outer so each pointer
 # can carry its own cls_id through SP_TAG_OBJ.
          if is_hash_type(first_vt) == 1 || is_array_type(first_vt) == 1
            if all_sym_keys == 1
              return "sym_poly_hash"
            end
            if all_int_keys == 0
              return "str_poly_hash"
            end
          end
        else
 # Mixed value types: use a *_poly_hash so each slot carries its
 # own tag (sp_RbVal) rather than coercing everything to one type.
          if all_sym_keys == 1
            return "sym_poly_hash"
          end
 # Mixed-shape keys (IntegerNode + SymbolNode etc.): no single
 # *_poly_hash variant can carry them. Use poly_poly_hash where
 # both key and value are sp_RbVal. Mirrors the analyzer arm.
 # Issue #536: `{ 0 => false, a: 1 }` segfaulted because
 # str_poly_hash was selected and the integer key was passed
 # directly to `sp_StrPolyHash_set` (which dereferences a
 # `const char *`).
          all_str_keys_check = 1
          ksk = 0
          while ksk < elems.length
            ekks = elems[ksk]
            if @nd_type[ekks] == "AssocNode"
              kids = @nd_key[ekks]
              if kids < 0 || (@nd_type[kids] != "StringNode" && @nd_type[kids] != "InterpolatedStringNode" && @nd_type[kids] != "SymbolNode")
                all_str_keys_check = 0
              end
            end
            ksk = ksk + 1
          end
          if all_str_keys_check == 0
            @needs_rb_value = 1
            @needs_poly_poly_hash = 1
            return "poly_poly_hash"
          end
          return "str_poly_hash"
        end
      end
    end
    "str_int_hash"
  end


  def is_class_or_ancestor(cname, target)
    if cname == target
      return 1
    end
    ci = find_class_idx(cname)
    if ci >= 0
      if @cls_parents[ci] != ""
        return is_class_or_ancestor(@cls_parents[ci], target)
      end
    end
    0
  end

 # `is_descendant(child, ancestor)` — 1 iff `child` is a strict
 # (proper) descendant of `ancestor` in the class hierarchy; 0
 # otherwise (including when they're identical). Wraps
 # is_class_or_ancestor, which is descendant-OR-EQUAL.
  def is_descendant(child, ancestor)
    if child == ancestor
      return 0
    end
    is_class_or_ancestor(child, ancestor)
  end

 # `is_value_type_class(cname)` — 1 iff `cname` is a user class
 # marked value-type (stack-allocated, no subclasses by design,
 # no `cls_id` field on the struct). emit_class_fields gates the
 # cls_id emission on the inverse of this; runtime cls_id checks
 # must guard against value-type recvs to avoid referencing a
 # nonexistent struct member.
  def is_value_type_class(cname)
    ci = find_class_idx(cname)
    if ci >= 0 && @cls_is_value_type[ci] == 1
      return 1
    end
    0
  end

  def is_operator_name(name)
    if name == "+"
      return 1
    end
    if name == "-"
      return 1
    end
    if name == "*"
      return 1
    end
    if name == "/"
      return 1
    end
    if name == "%"
      return 1
    end
    if name == "<"
      return 1
    end
    if name == ">"
      return 1
    end
    if name == "<="
      return 1
    end
    if name == ">="
      return 1
    end
    if name == "=="
      return 1
    end
    if name == "!="
      return 1
    end
    if name == "<=>"
      return 1
    end
    0
  end

  def is_obj_type(t)
    if t == nil
      return 0
    end
    if t.length > 4
      if t[0] == "o"
        if t[1] == "b"
          if t[2] == "j"
            if t[3] == "_"
              return 1
            end
          end
        end
      end
    end
    0
  end

 # Check if type is a ptr_array (e.g., "obj_Planet_ptr_array")
  def is_ptr_array_type(t)
    if t != nil && t.length > 10
      if t.end_with?("_ptr_array")
        return 1
      end
    end
    0
  end

 # Get element class type from ptr_array type (e.g., "obj_Planet_ptr_array" → "obj_Planet")
  def elem_type_of_array(t)
    if t == "int_array"
      return "int"
    end
    if t == "str_array"
      return "string"
    end
    if t == "float_array"
      return "float"
    end
    if t == "sym_array"
      return "symbol"
    end
    if t == "poly_array"
      return "poly"
    end
    if is_ptr_array_type(t) == 1
      return ptr_array_elem_type(t)
    end
    "int"
  end

  def ptr_array_elem_type(t)
    if is_ptr_array_type(t) == 1
      return t[0, t.length - 10]
    end
    ""
  end

 # ---- Tuple type helpers ----
  def is_tuple_type(t)
    if t != nil && t.length > 6
      if t[0] == "t" && t[1] == "u" && t[2] == "p" && t[3] == "l" && t[4] == "e" && t[5] == ":"
 # Exclude ptr_array of tuples
        if is_ptr_array_type(t) == 1
          return 0
        end
        return 1
      end
    end
    0
  end

  def tuple_elem_types_str(t)
 # "tuple:int,string" → "int,string"
    t[6, t.length - 6]
  end

  def tuple_elem_type_at(t, idx)
    parts = tuple_elem_types_str(t).split(",")
    if idx < parts.length
      return parts[idx]
    end
    "int"
  end

  def tuple_arity(t)
    tuple_elem_types_str(t).split(",").length
  end

  def tuple_c_name(t)
 # "tuple:int,string" → "sp_Tuple_int_string"
    "sp_Tuple_" + tuple_elem_types_str(t).split(",").join("_")
  end

 # Whether a tuple element type must be traced by the GC scan function.
 # Scalars (int/float/bool/symbol) are pure values; pointer-to-GC-object
 # element types must be marked, otherwise the GC frees the inner object
 # while the tuple keeps a dangling pointer.
  def tuple_field_needs_mark(et)
    if et == "poly"
      return 1
    end
    if et == "int" || et == "float" || et == "bool" || et == "symbol" || et == "void" || et == "nil"
      return 0
    end
    type_is_pointer(et)
  end

 # Returns the scan function name for the tuple, or "NULL" if no field
 # requires marking.
  def tuple_scan_name(t)
    parts = tuple_elem_types_str(t).split(",")
    fi = 0
    while fi < parts.length
      if tuple_field_needs_mark(parts[fi]) == 1
        return tuple_c_name(t) + "_scan"
      end
      fi = fi + 1
    end
    "NULL"
  end

  def register_tuple_type(t)
    if is_tuple_type(t) == 1
      k = 0
      found = 0
      while k < @tuple_types.length
        if @tuple_types[k] == t
          found = 1
        end
        k = k + 1
      end
      if found == 0
        @tuple_types.push(t)
      end
    end
  end

 # Build "tuple:T0,T1,..." from a list of element node ids and register it.
  def tuple_type_from_elems(elems)
    parts = "".split(",")
    k = 0
    while k < elems.length
      parts.push(infer_type(elems[k]))
      k = k + 1
    end
    tt = "tuple:" + parts.join(",")
    register_tuple_type(tt)
    tt
  end

 # Type for the splat target in `a, *b = rhs`. Returns the rhs's array
 # type (so `b` is a typed-array of the same element type).
  def splat_rest_type(val_id)
    if val_id < 0
      return "int_array"
    end
    rt = infer_type(val_id)
    if rt == "int_array" || rt == "str_array" || rt == "float_array" || rt == "sym_array" || rt == "poly_array"
      return rt
    end
    if is_ptr_array_type(rt) == 1
      return rt
    end
    "int_array"
  end

  def is_splat_with_target(nid)
    if nid < 0
      return 0
    end
    if @nd_type[nid] != "SplatNode"
      return 0
    end
    if @nd_expression[nid] < 0
      return 0
    end
    1
  end

  def type_is_pointer(t)
    if is_nullable_type(t) == 1
      t = base_type(t)
    end
 # Raw C pointer (FFI). Intentionally NOT a GC pointer — foreign
 # pointers are user-managed and the GC must not trace or free them.
    if t == "ptr"
      return 0
    end
    if t == "int_array"
      return 1
    end
    if t == "float_array"
      return 1
    end
    if is_ptr_array_type(t) == 1
      return 1
    end
    if t == "str_array"
      return 1
    end
    if t == "str_int_hash"
      return 1
    end
    if t == "str_str_hash"
      return 1
    end
    if t == "int_str_hash"
      return 1
    end
    if t == "sym_int_hash"
      return 1
    end
    if t == "sym_str_hash"
      return 1
    end
    if t == "str_poly_hash"
      return 1
    end
    if t == "sym_poly_hash"
      return 1
    end
    if t == "poly_poly_hash"
      return 1
    end
    if t == "sym_array"
      return 1
    end
    if t == "poly_array"
      return 1
    end
    if t == "lambda"
      return 1
    end
    if t == "mutable_str"
      return 1
    end
    if t == "string"
      return 1
    end
    if t == "fiber" || t == "bigint"
      return 1
    end
    if t == "proc"
      return 1
    end
    if is_obj_type(t) == 1
      cname = t[4, t.length - 4]
      ci = find_class_idx(cname)
      if ci >= 0 && @cls_is_value_type[ci] == 1
        return 0
      end
      return 1
    end
    if is_tuple_type(t) == 1
      return 1
    end
    0
  end

 # Check if evaluating an expression might trigger GC allocation
  def expr_may_gc(nid)
    if nid < 0
      return 0
    end
    t = @nd_type[nid]
    if t == "IntegerNode" || t == "FloatNode" || t == "StringNode"
      return 0
    end
    if t == "SymbolNode" || t == "TrueNode" || t == "FalseNode" || t == "NilNode"
      return 0
    end
    if t == "LocalVariableReadNode" || t == "SelfNode"
      return 0
    end
    if t == "InstanceVariableReadNode" || t == "ConstantReadNode"
      return 0
    end
    1
  end

  def is_nullable_type(t)
    if t.length > 1 && t[t.length - 1] == "?"
      return 1
    end
    0
  end

 # Empty `[]` / `{}` literals need deferred element-type resolution
 # — the type can only be settled by later writes. This helper
 # distinguishes `[]` from `[1, 2, 3]` so the promotion machinery
 # can recognize "writes haven't fixed the element type yet, so a
 # later push can still pick it".
  def is_empty_hash_literal(nid)
    if nid < 0
      return 0
    end
    if @nd_type[nid] != "HashNode"
      return 0
    end
    elems = parse_id_list(@nd_elements[nid])
    if elems.length == 0
      return 1
    end
    0
  end

  def is_empty_array_literal(nid)
    if nid < 0
      return 0
    end
    if @nd_type[nid] != "ArrayNode"
      return 0
    end
    elems = parse_id_list(@nd_elements[nid])
    if elems.length == 0
      return 1
    end
    0
  end

 # `[]` / `[].dup` — an empty array whose static element type is
 # ambiguous. When this is the tail of a block whose result becomes
 # the inner storage of a nested array (`Array.new(N) { [].dup }`,
 # `(0..N).map { [].dup }`), defaulting to `int_array` is unsafe:
 # later pushes of pointer-typed values (3-tuples, IntArrays, etc.)
 # silently truncate the pointer to mrb_int. Use `poly_array` for
 # the inner container instead so push goes through sp_PolyArray
 # (with sp_RbVal slots) and the runtime cls_id dispatch in
 # sp_poly_shl handles any pushed kind correctly.
  def is_empty_array_or_dup(nid)
    if is_empty_array_literal(nid) == 1
      return 1
    end
    if nid < 0
      return 0
    end
    if @nd_type[nid] != "CallNode"
      return 0
    end
    if @nd_name[nid] != "dup"
      return 0
    end
    recv = @nd_receiver[nid]
    if recv < 0
      return 0
    end
    is_empty_array_literal(recv)
  end

 # `[nil] * N` / `[0] * N` is a sized empty default — the elements
 # come from `nil`/`0`, so the array's effective element type is the
 # same as `[]`'s default (int_array). Used by writer-scan and the
 # expected-type-aware compile path so a later typed `arr[i] = obj`
 # write can promote / direct-allocate the right kind of container.
  def is_sized_empty_array_default(nid)
    if nid < 0
      return 0
    end
    if @nd_type[nid] != "CallNode" || @nd_name[nid] != "*"
      return 0
    end
    arr_recv = @nd_receiver[nid]
    if arr_recv < 0 || @nd_type[arr_recv] != "ArrayNode"
      return 0
    end
    recv_elems = parse_id_list(@nd_elements[arr_recv])
 # Restrict to single-element [nil] or [0] literals — the emit
 # paths in compile_expr_for_expected_type / emit_constructor /
 # compile_stmt all multiply by N (the multiplier) and fill with
 # NULL/0, so a multi-element literal would produce length=N
 # instead of length=N*elements, and a non-zero integer literal
 # would silently lose its value. The Gemini review on
 # caught both gaps. Stay tight: only the canonical
 # `[nil] * N` and `[0] * N` shapes.
    if recv_elems.length != 1
      return 0
    end
    ti = recv_elems[0]
    if ti < 0
      return 0
    end
    if @nd_type[ti] == "NilNode"
      return 1
    end
    if @nd_type[ti] == "IntegerNode" && @nd_value[ti].to_i == 0
      return 1
    end
    0
  end

  def base_type(t)
    if t.length > 1 && t[t.length - 1] == "?"
      return t[0, t.length - 1]
    end
    t
  end

  def is_nullable_pointer_type(t)
 # Pointer types that can represent nil as NULL
    bt = base_type(t)
    if bt == "ptr"
      return 1
    end
    if bt == "string" || bt == "mutable_str"
      return 1
    end
    if bt == "int_array" || bt == "str_array" || bt == "float_array" || bt == "sym_array"
      return 1
    end
    if bt == "str_int_hash" || bt == "str_str_hash"
      return 1
    end
    if bt == "sym_int_hash" || bt == "sym_str_hash" || bt == "sym_array"
      return 1
    end
    if bt == "str_poly_hash" || bt == "sym_poly_hash"
      return 1
    end
    if bt == "stringio" || bt == "lambda" || bt == "poly_array"
      return 1
    end
    if is_ptr_array_type(bt) == 1
      return 1
    end
    if bt == "fiber" || bt == "bigint"
      return 1
    end
    if is_obj_type(bt) == 1
      return 1
    end
    if is_tuple_type(bt) == 1
      return 1
    end
    0
  end

 # True when class `ci` (or any of its parents) has registered `bname` as
 # an attr_writer / attr_accessor or a struct field — i.e. `obj.bname = v`
 # may safely become a direct field write.
  def cls_has_attr_writer(ci, bname)
    if ci < 0
      return 0
    end
    writers = @cls_attr_writers[ci].split(";")
    wi = 0
    while wi < writers.length
      if writers[wi] == bname
        return 1
      end
      wi = wi + 1
    end
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        return cls_has_attr_writer(pi, bname)
      end
    end
    0
  end

  def is_value_type_obj(t)
    if is_obj_type(t) == 1
      cname = t[4, t.length - 4]
      ci = find_class_idx(cname)
      if ci >= 0 && @cls_is_value_type[ci] == 1
        return 1
      end
    end
    0
  end

 # ---- C type mapping ----
  def c_type(t)
    if is_nullable_type(t) == 1
      t = base_type(t)
    end
    if t == "range"
      return "sp_Range"
    end
    if t == "time"
      return "sp_Time"
    end
    if t == "complex"
      return "sp_Complex"
    end
    if t == "int"
      return "mrb_int"
    end
 # FFI raw C pointer (void *). See type_is_pointer for GC rules.
    if t == "ptr"
      return "void *"
    end
    if t == "bigint"
      return "sp_Bigint *"
    end
    if t == "float"
      return "mrb_float"
    end
    if t == "bool"
      return "mrb_bool"
    end
    if t == "string"
      return "const char *"
    end
    if t == "symbol"
      return "sp_sym"
    end
    if t == "mutable_str"
      return "sp_String *"
    end
    if t == "void"
      return "mrb_int"
    end
    if t == "nil"
      return "mrb_int"
    end
    if t == "int_array"
      return "sp_IntArray *"
    end
    if t == "float_array"
      return "sp_FloatArray *"
    end
    if is_ptr_array_type(t) == 1
      return "sp_PtrArray *"
    end
    if t == "str_array"
      return "sp_StrArray *"
    end
    if t == "str_int_hash"
      return "sp_StrIntHash *"
    end
    if t == "str_str_hash"
      return "sp_StrStrHash *"
    end
    if t == "int_str_hash"
      return "sp_IntStrHash *"
    end
    if t == "sym_int_hash"
      return "sp_SymIntHash *"
    end
    if t == "sym_str_hash"
      return "sp_SymStrHash *"
    end
    if t == "str_poly_hash"
      return "sp_StrPolyHash *"
    end
    if t == "sym_poly_hash"
      return "sp_SymPolyHash *"
    end
    if t == "poly_poly_hash"
      @needs_poly_poly_hash = 1
      @needs_rb_value = 1
      return "sp_PolyPolyHash *"
    end
    if t == "sym_array"
 # sym_array is an IntArray internally (sp_sym = mrb_int)
      return "sp_IntArray *"
    end
    if is_tuple_type(t) == 1
      return tuple_c_name(t) + " *"
    end
    if t == "fiber"
      return "sp_Fiber *"
    end
    if t == "poly"
      return "sp_RbVal"
    end
    if t == "class"
 # class object as value. Carries the class
 # id so `c.to_s` can index sp_class_names[].
      @needs_class_table = 1
      return "sp_Class"
    end
    if t == "proc"
      return "sp_Proc *"
    end
    if t == "stringio"
      return "sp_StringIO *"
    end
    if t == "poly_array"
      return "sp_PolyArray *"
    end
    if t == "lambda"
      return "sp_Val *"
    end
    if is_obj_type(t) == 1
      cname = t[4, t.length - 4]
      ci = find_class_idx(cname)
      if ci >= 0 && @cls_is_value_type[ci] == 1
        return "sp_" + cname
      end
      return "sp_" + cname + " *"
    end
    "mrb_int"
  end

  def c_default_val(t)
    if is_nullable_type(t) == 1
 # Value-type classes (`obj_<C>?` where C is a value type) lower
 # to a struct, not a pointer — `NULL` is an invalid initializer.
 # Fall through to the value-type branch below by stripping `?`.
      bt_n = base_type(t)
      if is_value_type_obj(bt_n) == 1
        return "{0}"
      end
      return "NULL"
    end
 # NOTE: nullable returns above, so rest handles base types only
    if t == "range"
      return "((sp_Range){0,0})"
    end
    if t == "time"
      return "((sp_Time){0,0,0})"
    end
    if t == "complex"
      return "((sp_Complex){0,0})"
    end
    if t == "int"
      return "0"
    end
    if t == "ptr"
      return "NULL"
    end
    if t == "bigint"
      return "NULL"
    end
    if t == "float"
      return "0.0"
    end
    if t == "bool"
      return "FALSE"
    end
    if t == "string"
      return "(&(\"\\xff\")[1])"
    end
    if t == "symbol"
      return "((sp_sym)-1)"
    end
    if t == "mutable_str"
      return "NULL"
    end
    if t == "void"
      return "0"
    end
    if t == "nil"
      return "0"
    end
    if t == "poly"
      return "sp_box_nil()"
    end
    if t == "class"
 # -1 is the "no class" sentinel; sp_class_to_s
 # returns "" for it. Locals declared `sp_Class lv_x = ((sp_Class){-1})`
 # are equivalent to nil for to_s purposes.
      return "((sp_Class){-1LL})"
    end
    if t == "stringio"
      return "NULL"
    end
    if t == "proc"
      return "NULL"
    end
    if type_is_pointer(t) == 1
      return "NULL"
    end
    if is_value_type_obj(t) == 1
      return "{0}"
    end
    "0"
  end

  def c_return_default(t)
 # Like c_default_val but for return statements (compound literal for value types)
    bt = base_type(t)
    if is_value_type_obj(bt) == 1
      return "(" + c_type(bt) + "){0}"
    end
    c_default_val(t)
  end

 # PM_RANGE_FLAGS_EXCLUDE_END = 4: bit 2 set means `...` (exclusive).
  def range_excl_end(rid)
    if (@nd_flags[rid] & 4) != 0
      return 1
    end
    return 0
  end

  def sanitize_name(name)
    if name == "<=>"
      return "_cmp"
    end
    if name == "<="
      return "_le"
    end
    if name == ">="
      return "_ge"
    end
    if name == "<<"
      return "_lshift"
    end
    if name == ">>"
      return "_rshift"
    end
    if name == "<"
      return "_lt"
    end
    if name == ">"
      return "_gt"
    end
    if name == "+"
      return "_plus"
    end
    if name == "-"
      return "_minus"
    end
    if name == "*"
      return "_mul"
    end
    if name == "/"
      return "_div"
    end
    if name == "=="
      return "_eq_eq"
    end
    if name == "!="
      return "_neq"
    end
    if name == "[]"
      return "_aref"
    end
    if name == "[]="
      return "_aset"
    end
    result = ""
    i = 0
    while i < name.length
      ch = name[i]
      if ch == "?"
        result = result + "_p"
      else
        if ch == "!"
          result = result + "_bang"
        else
          if ch == "="
            result = result + "_eq"
          else
            result = result + ch
          end
        end
      end
      i = i + 1
    end
    result
  end

  def sanitize_ivar(name)
 # @x → iv_x, x → iv_x
    if name.length > 0 && name[0] == "@"
      return "iv_" + name[1, name.length - 1]
    end
    "iv_" + name
  end

  def toplevel_ivar_type(name)
    i = 0
    while i < @toplevel_ivar_names.length
      if @toplevel_ivar_names[i] == name
        return @toplevel_ivar_types[i]
      end
      i = i + 1
    end
    ""
  end

 # Resolves an ivar lhs / rhs C expression. Three cases:
 #   - inside a module class method (def self.X on a module),
 #     `@x` lowers to the module's `cst_<Mod>_<x>` static --
 #     module class methods have no instance, so `self->iv_x`
 #     would dangle.
 #   - at script-toplevel script scope where the ivar was
 #     registered as a toplevel slot, `iv_<name>` (no self).
 #   - otherwise, `self->iv_<name>` (or `self.iv_<name>` for
 #     value-typed self).
  def ivar_lhs(name)
    mod_slot = module_ivar_const_lhs(name)
    if mod_slot != ""
      return mod_slot
    end
    if @current_class_idx < 0 && toplevel_ivar_type(name) != ""
      return sanitize_ivar(name)
    end
    self_arrow + sanitize_ivar(name)
  end

 # When the current emit scope is a module class method
 # (`def self.X` on a module), the bare `@count` ivar maps to
 # the module's `cst_<Mod>_<name>` static slot rather than a
 # nonexistent `self->iv_count`. Returns the C expression or ""
 # when the current scope isn't a module class method or no
 # matching const is registered.
  def module_ivar_const_lhs(name)
    if @current_method_name == ""
      return ""
    end
    mi = 0
    while mi < @module_names.length
      mmod = @module_names[mi]
      if mmod != "" && @current_method_name.start_with?(mmod + "_cls_")
        cname = mmod + "_" + name[1, name.length - 1]
        if find_const_idx(cname) >= 0
          return "cst_" + cname
        end
      end
      mi = mi + 1
    end
    ""
  end


 # Walk the program for ivar nodes at script scope. Class/Module bodies
 # are skipped — their ivars belong to the enclosing class. Top-level
 # `def` bodies ARE walked: in Ruby, `def foo; @x; end` at script scope
 # shares the same `main` ivar that bare `@x` writes.

  def sanitize_gvar(name)
 # `alias $copy $orig` -- transparently rewrite `$copy` to `$orig`
 # everywhere it appears so the C output uses one storage slot
 # for both names. Compile-time only; matches CRuby's
 # `$copy and $orig share storage` semantics for the static-alias
 # case.
    name = resolve_gvar_alias(name)
 # $last → gv_last, $1 → gv_1
    if name.length > 0 && name[0] == "$"
      return "gv_" + name[1, name.length - 1]
    end
    "gv_" + name
  end

  def resolve_gvar_alias(name)
    i = 0
    while i < @galias_new.length
      if @galias_new[i] == name
        return @galias_old[i]
      end
      i = i + 1
    end
    name
  end

 # ---- Array type helpers ----
  def array_c_prefix(t)
    if t == "str_array"
      return "StrArray"
    end
    if t == "float_array"
      return "FloatArray"
    end
    if t == "poly_array"
      return "PolyArray"
    end
    if is_ptr_array_type(t) == 1
      return "PtrArray"
    end
    "IntArray"
  end

 # The canonical "is this an array type?" check. Use this when you need
 # to dispatch a method that's defined for every typed array — `+`,
 # `concat`, `shuffle`, `each_with_object`, `flat_map`, etc. Covers the
 # 5 typed arrays (int/str/float/sym/poly) and any *_ptr_array.
  def is_array_type(t)
    if is_nullable_type(t) == 1
      t = base_type(t)
    end
    if t == "int_array" || t == "str_array" || t == "float_array" || t == "sym_array" || t == "poly_array"
      return 1
    end
    if is_ptr_array_type(t) == 1
      return 1
    end
    0
  end

  def is_hash_type(t)
    if is_nullable_type(t) == 1
      t = base_type(t)
    end
    if t == "str_int_hash" || t == "str_str_hash" || t == "int_str_hash"
      return 1
    end
    if t == "sym_int_hash" || t == "sym_str_hash"
      return 1
    end
    if t == "str_poly_hash" || t == "sym_poly_hash"
      return 1
    end
    if t == "poly_poly_hash"
      return 1
    end
    0
  end

  def cls_id_for_hash_type(at)
    if at == "str_int_hash"
      return "SP_BUILTIN_STR_INT_HASH"
    end
    if at == "str_str_hash"
      return "SP_BUILTIN_STR_STR_HASH"
    end
    if at == "int_str_hash"
      return "SP_BUILTIN_INT_STR_HASH"
    end
    if at == "sym_int_hash"
      return "SP_BUILTIN_SYM_INT_HASH"
    end
    if at == "sym_str_hash"
      return "SP_BUILTIN_SYM_STR_HASH"
    end
    if at == "str_poly_hash"
      return "SP_BUILTIN_STR_POLY_HASH"
    end
    if at == "sym_poly_hash"
      return "SP_BUILTIN_SYM_POLY_HASH"
    end
    if at == "poly_poly_hash"
      return "SP_BUILTIN_POLY_POLY_HASH"
    end
    ""
  end

  def hash_leaf_type(recv_type)
    if recv_type == "str_int_hash" || recv_type == "sym_int_hash"
      return "int"
    end
    if recv_type == "str_str_hash" || recv_type == "sym_str_hash" || recv_type == "int_str_hash"
      return "string"
    end
    if recv_type == "str_poly_hash" || recv_type == "sym_poly_hash" || recv_type == "poly_poly_hash"
      return "poly"
    end
    ""
  end

 # CRuby returns nil for static mismatches (e.g. `{a: 1}.dig("a")`)
 # since no key compares equal — Hash#dig short-circuits to nil here.
  def hash_key_matches_recv(recv_type, key_type)
    if recv_type.start_with?("sym_") && key_type == "symbol"
      return 1
    end
    if recv_type.start_with?("str_") && key_type == "string"
      return 1
    end
    if recv_type.start_with?("int_") && key_type == "int"
      return 1
    end
    0
  end

 # The four typed arrays that have set-op runtime helpers
 # (sp_*_intersect / _union / _difference). poly_array and ptr_array
 # are deliberately excluded — element equality isn't available there.
  def is_typed_array_type(t)
    t == "int_array" || t == "sym_array" || t == "str_array" || t == "float_array"
  end

 # Returns "" to fall through to the literal C operator; otherwise the
 # typed-array helper call. `op` is one of "intersect"/"union"/"difference".
 # `lt` is the pre-computed receiver type from the caller.
  def compile_array_setop_expr(nid, recv, op, lt)
    if !is_typed_array_type(lt)
      if is_array_type(lt) == 1
        $stderr.puts "warning: Array set-op '" + op + "' is not supported on " + lt + " (falling through)"
      end
      return ""
    end
    args_id = @nd_arguments[nid]
    if args_id < 0
      return ""
    end
    aargs = get_args(args_id)
    if aargs.length == 0
      return ""
    end
 # Strict equality (not is_array_type): nullable variants and
 # cross-type RHS aren't handled by the helpers, and the fall-through
 # would emit a C arithmetic/bitwise op on array pointers.
    rt = infer_type(aargs[0])
    if rt != lt
      $stderr.puts "warning: Array set-op '" + op + "' RHS type " + rt + " does not match LHS " + lt + " (falling through)"
      return ""
    end
    mark_array_runtime_needs(lt)
    "sp_" + array_c_prefix(lt) + "_" + op + "(" + compile_expr_gc_rooted(recv) + ", " + compile_arg0(nid) + ")"
  end

 # Set the right @needs_<runtime> flag for the given array type.
  def mark_array_runtime_needs(t)
    if t == "float_array"
      @needs_float_array = 1
    elsif t == "str_array"
      @needs_str_array = 1
    elsif t == "poly_array"
      @needs_rb_value = 1
    else
      @needs_int_array = 1
    end
  end

 # ---- Collection pass ----
 # Returns the module-singleton-accessor index for "<Module>.<accessor>",
 # or -1 if not registered.
  def find_module_acc_idx(key)
    i = 0
    while i < @module_acc_keys.length
      if @module_acc_keys[i] == key
        return i
      end
      i = i + 1
    end
    -1
  end

 # Walk the AST for `Module.accessor = RHS` writes where
 # (Module, accessor) was registered in `collect_module` as a
 # singleton accessor. Accumulates the set of distinct
 # ConstantReadNode RHSes; the lowering paths read this list to
 # choose:
 # - 0 entries: never written, falls through (un-folded)
 # - 1 entry: Stage 1, inline `<resolved>.<method>` directly
 # - 2+ entries: Stage 2, sentinel switch over the union
 # A non-constant RHS poisons the slot with a `?` sentinel marker
 # so the lowering paths treat it as un-folded.

 # Returns the resolved constant list for this (module, accessor):
 # `<Name1>;<Name2>;...` for foldable, `""` if never written, `"?"`
 # if poisoned (non-constant RHS).
  def module_acc_resolved(mod_name, accessor)
    idx = find_module_acc_idx(mod_name + "." + accessor)
    if idx < 0
      return ""
    end
    @module_acc_consts[idx]
  end

 # Sentinel value for Stage 2 switch dispatch. Each module's index in
 # `@module_names` doubles as its sentinel id; reading `Module` as a
 # value lowers to this integer.

 # Look up the return type of a `<class_or_module>.<mname>`
 # singleton method, walking @meth_* (module / synthetic top-level
 # form) and @cls_cmeth_* (in-class `def self.X`). Returns "" when
 # the method isn't registered. Used by the module-dispatch ternary
 # default-tail and per-arm boxing paths.
  def lookup_cls_meth_return(cn, mname)
    mid = find_method_idx(cn + "_cls_" + mname)
    if mid >= 0
      return @meth_return_types[mid]
    end
    cci = find_class_idx(cn)
    if cci >= 0
      cmnames = @cls_cmeth_names[cci].split(";")
      ki = 0
      while ki < cmnames.length
        if cmnames[ki] == mname
          cmrets = @cls_cmeth_returns[cci].split(";")
          if ki < cmrets.length
            return cmrets[ki]
          end
        end
        ki = ki + 1
      end
    end
    ""
  end

  def module_sentinel(mname)
 # Module-singleton accessors hold either a module reference (rare)
 # or a class reference (the strategy-pattern shape: `Disp.adapter
 # = A` / `Disp.adapter = B`). Both must produce *distinct* sentinel
 # values so the dispatch ternary's per-candidate `slot == sentinel`
 # arms don't all collapse to the same comparison. the
 # class case used to fall through to 0 here, leaving every
 # candidate's `slot == 0` arm matching the never-written default
 # and the rest of the chain unreachable.
    i = 0
    while i < @module_names.length
      if @module_names[i] == mname
        return i + 1
      end
      i = i + 1
    end
    ci = find_class_idx(mname)
    if ci >= 0
 # Reserve [1 .. @module_names.length] for module sentinels and
 # offset class sentinels above that range so the two namespaces
 # don't collide.
      return @module_names.length + 1 + ci
    end
    0
  end

 # Identifies the method body we're currently emitting, formatted for
 # diagnostic messages. Library-style methods with no concrete caller
 # default their params to `mrb_int` and surface as a flood of
 # "cannot resolve call to ... on int" lines; without context the
 # user can't tell which def the warning came from. Returns
 # "Foo#bar" for an instance method, "Foo.bar" for a class method
 # (incl. module class methods stored as @meth_names with a
 # `<Mod>_cls_<m>` form), or "(top level)" outside any def.
  def current_method_context_str
    if @current_class_idx >= 0 && @current_class_idx < @cls_names.length
      sep = "."
      if @current_method_has_self == 1
        sep = "#"
      end
      return @cls_names[@current_class_idx] + sep + @current_method_name
    end
    if @current_method_name != ""
      ix_cls = @current_method_name.index("_cls_")
 # CRuby returns nil when not found; spinel runtime returns -1.
      if ix_cls != nil && ix_cls > 0
        return @current_method_name[0, ix_cls] + "." +
               @current_method_name[ix_cls + 5, @current_method_name.length - (ix_cls + 5)]
      end
      return @current_method_name
    end
    "(top level)"
  end

 # Print a stderr warning the first time we see an unresolved call to
 # `mname` with the given receiver-type tag in the current method
 # context. Subsequent identical warnings are suppressed so a
 # silent-fallthrough call inside a hot loop emits one line, not a
 # torrent. Dedupe key includes the method context so the same shape
 # of unresolved call in two different defs each produces its own
 # line — the prior key (`mname:recv_tag`) collapsed them and made
 # library-method-with-no-caller diagnostics opaque. The warning is
 # informational only — codegen continues and emits `0` for the
 # call's C expression (the historical silent-no-op behaviour) so
 # existing tests/benches whose outputs happen to coincide with `0`
 # keep compiling.
  def warn_unresolved_call(mname, recv_tag)
    ctx = current_method_context_str
    key = mname + ":" + recv_tag + ":" + ctx
    i = 0
    while i < @unresolved_call_warnings.length
      if @unresolved_call_warnings[i] == key
        return
      end
      i = i + 1
    end
    @unresolved_call_warnings.push(key)
