 # Map an FFI type-spec symbol to the C type used in extern prototypes
 # and call-site casts. Unlike ffi_type_of (which collapses to Spinel
 # tokens), this preserves C-level detail (uint32_t vs size_t etc.).
  def ffi_c_type_of(spec)
    if spec == "int"
      return "int"
    end
    if spec == "uint32"
      return "uint32_t"
    end
    if spec == "int32"
      return "int32_t"
    end
    if spec == "uint16"
      return "uint16_t"
    end
    if spec == "int16"
      return "int16_t"
    end
    if spec == "uint8"
      return "uint8_t"
    end
    if spec == "int8"
      return "int8_t"
    end
    if spec == "size_t"
      return "size_t"
    end
    if spec == "long"
      return "long"
    end
    if spec == "float"
      return "float"
    end
    if spec == "double"
      return "double"
    end
    if spec == "bool"
      return "int"
    end
    if spec == "str"
      return "const char *"
    end
    if spec == "ptr"
      return "void *"
    end
 # Spinel array specs (#474): pointer to underlying storage.
    if spec == "float_array"
      return "const double *"
    end
    if spec == "int_array"
      return "const int64_t *"
    end
    if spec == "void"
      return "void"
    end
    ""
  end

