      end
      if mname == "shift"
        return "sp_FloatArray_shift(" + rc + ")"
      end
      if mname == "empty?"
        return "sp_FloatArray_empty(" + rc + ")"
      end
      if mname == "size"
        return "sp_FloatArray_length(" + rc + ")"
      end
      if mname == "min"
        return "sp_FloatArray_min(" + rc + ")"
      end
      if mname == "max"
        return "sp_FloatArray_max(" + rc + ")"
      end
      if mname == "sum"
        return "sp_FloatArray_sum(" + rc + ", " + compile_arg0_as_float(nid) + ")"
      end
      if mname == "first"
