        emit("  sp_PtrArray *" + tmp + " = sp_PtrArray_new();")
        emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + rc + "->len; " + itmp + "++) {")
        emit("    " + tname + " *_tp = (" + tname + " *)sp_gc_alloc(sizeof(" + tname + "), NULL, " + tuple_scan_name(tt) + ");")
        emit("    _tp->_0 = " + rc + "->order[" + itmp + "];")
        emit("    _tp->_1 = sp_StrIntHash_get(" + rc + ", " + rc + "->order[" + itmp + "]);")
        emit("    sp_PtrArray_push(" + tmp + ", _tp);")
        emit("  }")
        return tmp
      end
      if mname == "transform_values"
        if @nd_block[nid] >= 0
          blk = @nd_block[nid]
          bp = get_block_param(nid, 0)
          tmp = new_temp
          emit("  sp_StrIntHash *" + tmp + " = sp_StrIntHash_new();")
          emit("  for (mrb_int _i = 0; _i < " + rc + "->len; _i++) {")
          emit("    mrb_int lv_" + bp + " = sp_StrIntHash_get(" + rc + ", " + rc + "->order[_i]);")
          push_scope
          declare_var(bp, "int")
          bbody = @nd_body[blk]
          bexpr = "0"
          if bbody >= 0
            bs = get_stmts(bbody)
            if bs.length > 0
              bexpr = compile_expr(bs.last)
            end
          end
          emit("    sp_StrIntHash_set(" + tmp + ", " + rc + "->order[_i], " + bexpr + ");")
          pop_scope
          emit("  }")
          return tmp
        end
      end
 # transform_keys: apply the block to each key, keep the matching
 # value, build a new hash. Result type matches the input hash
 # type when the block returns the same key C-type — the common
 # case for `transform_keys { |k| k.upcase }` etc.
      if mname == "transform_keys"
        if @nd_block[nid] >= 0
          blk = @nd_block[nid]
          bp = get_block_param(nid, 0)
          tmp = new_temp
          emit("  sp_StrIntHash *" + tmp + " = sp_StrIntHash_new();")
          emit("  for (mrb_int _i = 0; _i < " + rc + "->len; _i++) {")
          emit("    const char *lv_" + bp + " = " + rc + "->order[_i];")
          push_scope
          declare_var(bp, "string")
          bbody = @nd_body[blk]
          bexpr = "lv_" + bp
          if bbody >= 0
            bs = get_stmts(bbody)
            if bs.length > 0
              bexpr = compile_expr(bs.last)
            end
          end
          emit("    sp_StrIntHash_set(" + tmp + ", " + bexpr + ", sp_StrIntHash_get(" + rc + ", " + rc + "->order[_i]));")
          pop_scope
          emit("  }")
          return tmp
        end
      end
    end
    if recv_type == "int_str_hash"
      @needs_int_str_hash = 1
      if mname == "[]"
        return "sp_IntStrHash_get(" + rc + ", " + compile_arg0_as_int(nid) + ")"
      end
      if mname == "has_key?" || mname == "key?" || mname == "include?" || mname == "member?"
        return "sp_IntStrHash_has_key(" + rc + ", " + compile_arg0_as_int(nid) + ")"
      end
      if mname == "length" || mname == "size" || (mname == "count" && @nd_block[nid] < 0 && @nd_arguments[nid] < 0)
        return "sp_IntStrHash_length(" + rc + ")"
      end
      if mname == "empty?"
        return "(sp_IntStrHash_length(" + rc + ") == 0)"
      end
      if mname == "any?" && @nd_block[nid] < 0
        return "(sp_IntStrHash_length(" + rc + ") > 0)"
      end
      if mname == "keys"
        @needs_int_array = 1
        return "sp_IntStrHash_keys(" + rc + ")"
      end
      if mname == "values"
        @needs_str_array = 1
        return "sp_IntStrHash_values(" + rc + ")"
      end
      if mname == "fetch"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          key = compile_expr(aargs[0])
          if infer_type(aargs[0]) == "poly"
            key = "(" + key + ").v.i"
          end
          if aargs.length >= 2
            defval = compile_expr(aargs[1])
            return "(sp_IntStrHash_has_key(" + rc + ", " + key + ") ? sp_IntStrHash_get(" + rc + ", " + key + ") : " + defval + ")"
          end
          return "sp_IntStrHash_get(" + rc + ", " + key + ")"
        end
      end
 # transform_values block form. Mirrors str_int_hash's arm: walk
 # self, run the block on each value, build a new hash with the
 # same keys and the block's returns. Result type matches the
 # input hash type.
      if mname == "transform_values"
        if @nd_block[nid] >= 0
          blk = @nd_block[nid]
          bp = get_block_param(nid, 0)
          tmp = new_temp
          emit("  sp_IntStrHash *" + tmp + " = sp_IntStrHash_new();")
          emit("  for (mrb_int _i = 0; _i < " + rc + "->len; _i++) {")
          emit("    const char *lv_" + bp + " = sp_IntStrHash_get(" + rc + ", " + rc + "->order[_i]);")
          push_scope
          declare_var(bp, "string")
          bbody = @nd_body[blk]
          bexpr = "0"
          if bbody >= 0
            bs = get_stmts(bbody)
            if bs.length > 0
              bexpr = compile_expr(bs.last)
            end
          end
          emit("    sp_IntStrHash_set(" + tmp + ", " + rc + "->order[_i], " + bexpr + ");")
          pop_scope
          emit("  }")
          return tmp
        end
      end
    end
    if recv_type == "str_str_hash"
      if mname == "[]"
        return "sp_StrStrHash_get(" + rc + ", " + compile_str_arg0(nid) + ")"
      end
      if mname == "has_key?" || mname == "key?" || mname == "include?" || mname == "member?"
        return "sp_StrStrHash_has_key(" + rc + ", " + compile_str_arg0(nid) + ")"
      end
      if mname == "length" || mname == "size" || (mname == "count" && @nd_block[nid] < 0 && @nd_arguments[nid] < 0)
        if @hoisted_strlen_var != "" && @hoisted_strlen_recv == rc
          return @hoisted_strlen_var
        end
        return "sp_StrStrHash_length(" + rc + ")"
      end
      if mname == "empty?"
        return "(sp_StrStrHash_length(" + rc + ") == 0)"
      end
      if mname == "any?" && @nd_block[nid] < 0
        return "(sp_StrStrHash_length(" + rc + ") > 0)"
      end
      if mname == "keys"
        return "sp_StrStrHash_keys(" + rc + ")"
      end
      if mname == "values"
        return "sp_StrStrHash_values(" + rc + ")"
      end
      if mname == "invert"
        return "sp_StrStrHash_invert(" + rc + ")"
      end
      if mname == "to_a"
        tt = "tuple:string,string"
        register_tuple_type(tt)
        @needs_gc = 1
        tname = tuple_c_name(tt)
        tmp = new_temp
        itmp = new_temp
        emit("  sp_PtrArray *" + tmp + " = sp_PtrArray_new();")
        emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + rc + "->len; " + itmp + "++) {")
        emit("    " + tname + " *_tp = (" + tname + " *)sp_gc_alloc(sizeof(" + tname + "), NULL, " + tuple_scan_name(tt) + ");")
        emit("    _tp->_0 = " + rc + "->order[" + itmp + "];")
        emit("    _tp->_1 = sp_StrStrHash_get(" + rc + ", " + rc + "->order[" + itmp + "]);")
        emit("    sp_PtrArray_push(" + tmp + ", _tp);")
        emit("  }")
        return tmp
      end
      if (mname == "select" || mname == "reject") && @nd_block[nid] >= 0
        return compile_hash_select_reject(nid, "str_str_hash", rc, mname)
      end
      if (mname == "count" || mname == "any?" || mname == "all?" || mname == "find" || mname == "detect") && @nd_block[nid] >= 0
        return compile_hash_block_predicate(nid, "str_str_hash", rc, mname)
      end
      if mname == "fetch"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          key = compile_expr_as_string(aargs[0])
          if aargs.length >= 2
            defval = compile_expr(aargs[1])
            return "(sp_StrStrHash_has_key(" + rc + ", " + key + ") ? sp_StrStrHash_get(" + rc + ", " + key + ") : " + defval + ")"
          end
          return "sp_StrStrHash_get(" + rc + ", " + key + ")"
        end
      end
    end
    ""
  end

 # Multi-key Hash#dig walks across poly slots: each step dispatches
 # on acc.cls_id to pick a concrete-hash variant (cls_ids stamped in
 # box_value_to_poly via cls_id_for_hash_type). A cls_id that matches
 # no known variant collapses the walk to nil, covering both "key
 # missing mid-walk" and "value at this depth isn't a hash".
  def compile_hash_dig(nid, rc, recv_type)
    args_id = @nd_arguments[nid]
    aargs = []
    if args_id >= 0
      aargs = get_args(args_id)
    end
    if aargs.length == 0
      @needs_rb_value = 1
      return "sp_box_nil()"
    end

 # `"".split(",")` builds an empty str_array — bare `[]` would be
 # inferred as int_array under spinel's self-host rules and can't
 # hold the string temps below.
    key_tmps = "".split(",")
    key_types = "".split(",")
    ki = 0
    while ki < aargs.length
      kt = infer_type(aargs[ki])
      tmp = new_temp
      if kt == "symbol"
        emit("  sp_sym " + tmp + " = " + compile_expr(aargs[ki]) + ";")
      elsif kt == "string"
        emit("  const char *" + tmp + " = " + compile_expr_as_string(aargs[ki]) + ";")
      elsif kt == "int"
        emit("  mrb_int " + tmp + " = " + compile_expr(aargs[ki]) + ";")
      else
        emit("  mrb_int " + tmp + " = 0; (void)" + tmp + ";")
      end
      key_tmps.push(tmp)
      key_types.push(kt)
      ki = ki + 1
    end

 # First-key static mismatch: short-circuit before the typed `_get`
 # so we don't fabricate a sentinel 0/"" leaf that would round-trip
 # through boxing as a real boxed 0/"".
    if hash_key_matches_recv(recv_type, key_types[0]) == 0
      @needs_rb_value = 1
      return "sp_box_nil()"
    end

    if aargs.length == 1
      return hash_get_expr(recv_type, rc, key_tmps[0])
    end

    @needs_rb_value = 1
    acc = new_temp
    emit("  sp_RbVal " + acc + ";")
    first_get = hash_get_expr(recv_type, rc, key_tmps[0])
    emit("  " + acc + " = " + box_non_nullable_value_to_poly(hash_leaf_type(recv_type), first_get) + ";")

    si = 1
    while si < aargs.length
      emit_dig_step(acc, key_tmps[si], key_types[si])
      si = si + 1
    end
    acc
  end

 # Caller must pass `key_expr` typed for recv_type's key family —
 # compile_hash_dig validates this with hash_key_matches_recv first.
  def hash_get_expr(recv_type, rc, key_expr)
    if recv_type == "sym_int_hash"
      return "sp_SymIntHash_get((sp_SymIntHash *)(" + rc + "), " + key_expr + ")"
    end
    if recv_type == "sym_str_hash"
      return "sp_SymStrHash_get((sp_SymStrHash *)(" + rc + "), " + key_expr + ")"
    end
    if recv_type == "sym_poly_hash"
      @needs_rb_value = 1
      return "sp_SymPolyHash_get((sp_SymPolyHash *)(" + rc + "), " + key_expr + ")"
    end
    if recv_type == "str_poly_hash"
      @needs_rb_value = 1
      return "sp_StrPolyHash_get(" + rc + ", " + key_expr + ")"
    end
    if recv_type == "str_int_hash"
      return "sp_StrIntHash_get(" + rc + ", " + key_expr + ")"
    end
    if recv_type == "str_str_hash"
      return "sp_StrStrHash_get(" + rc + ", " + key_expr + ")"
    end
    if recv_type == "int_str_hash"
      return "sp_IntStrHash_get(" + rc + ", " + key_expr + ")"
    end
    "0"
  end

 # Non-poly inner hashes need a has_key guard: their typed `_get`
 # returns 0/"" on miss, which sp_box_int/sp_box_str would otherwise
 # round-trip as a genuine 0/"" leaf indistinguishable from a real
 # value. Poly inner hashes don't need the guard — their `_get`
 # already returns sp_box_nil() on miss.
  def emit_dig_step(acc, key_expr, key_type)
    emit("  if (" + acc + ".tag != SP_TAG_OBJ) { " + acc + " = sp_box_nil(); } else {")
    if key_type == "symbol"
      emit_dig_arm_poly(acc, key_expr, "SP_BUILTIN_SYM_POLY_HASH", "sp_SymPolyHash")
      emit_dig_arm_typed(acc, key_expr, "SP_BUILTIN_SYM_INT_HASH", "sp_SymIntHash", "sp_box_int")
      emit_dig_arm_typed(acc, key_expr, "SP_BUILTIN_SYM_STR_HASH", "sp_SymStrHash", "sp_box_str")
    elsif key_type == "string"
      emit_dig_arm_poly(acc, key_expr, "SP_BUILTIN_STR_POLY_HASH", "sp_StrPolyHash")
      emit_dig_arm_typed(acc, key_expr, "SP_BUILTIN_STR_INT_HASH", "sp_StrIntHash", "sp_box_int")
      emit_dig_arm_typed(acc, key_expr, "SP_BUILTIN_STR_STR_HASH", "sp_StrStrHash", "sp_box_str")
    elsif key_type == "int"
      emit_dig_arm_typed(acc, key_expr, "SP_BUILTIN_INT_STR_HASH", "sp_IntStrHash", "sp_box_str")
    end
    emit("    " + acc + " = sp_box_nil();")
    emit("  }")
  end

  def emit_dig_arm_poly(acc, key_expr, cls_id, cstruct)
    emit("    if (" + acc + ".cls_id == " + cls_id + ") { " + acc + " = " + cstruct + "_get((" + cstruct + " *)" + acc + ".v.p, " + key_expr + "); } else")
  end

  def emit_dig_arm_typed(acc, key_expr, cls_id, cstruct, box_fn)
    emit("    if (" + acc + ".cls_id == " + cls_id + ") { " + cstruct + " *_dh = (" + cstruct + " *)" + acc + ".v.p; " + acc + " = " + cstruct + "_has_key(_dh, " + key_expr + ") ? " + box_fn + "(" + cstruct + "_get(_dh, " + key_expr + ")) : sp_box_nil(); } else")
  end

  def compile_enumerable_expr(nid, mname, precomputed_rc = "")
 # map as expression
    if mname == "map"
      if @nd_block[nid] >= 0
        return compile_map_expr(nid, precomputed_rc)
      end
    end

 # flat_map as expression
    if mname == "flat_map"
      if @nd_block[nid] >= 0
        return compile_flat_map_expr(nid)
      end
    end

 # each_with_object as expression: run the loop as side effect, return obj
    if mname == "each_with_object"
      if @nd_block[nid] >= 0
        return compile_each_with_object_block(nid)
      end
    end

 # tap: run block with receiver, return receiver
    if mname == "tap"
      if @nd_block[nid] >= 0
        return compile_tap_expr(nid)
      end
    end

 # then / yield_self: pass receiver to block, return block result
    if mname == "then" || mname == "yield_self"
      if @nd_block[nid] >= 0
        return compile_then_expr(nid)
      end
    end

 # select as expression
    if mname == "select" || mname == "filter"
      if @nd_block[nid] >= 0
        return compile_select_expr(nid)
      end
    end

 # reject as expression
    if mname == "reject"
      if @nd_block[nid] >= 0
        return compile_reject_expr(nid)
      end
    end

 # reduce/inject as expression
    if mname == "reduce"
      if @nd_block[nid] >= 0
        return compile_reduce_expr(nid)
      end
    end
    if mname == "inject"
      if @nd_block[nid] >= 0
        return compile_reduce_expr(nid)
      end
    end
    ""
  end

 # Returns the C op token ("+", "*", ...) when `nid` is an
 # `arr.reduce(:op)` / `arr.inject(:op)` call with a single
 # SymbolNode arg naming an inlinable binary arithmetic /
 # bitwise op. Else "". Issue #506. Pulled out of the
 # int_array dispatch so the emit site has no new locals
 # (the dispatch method is large and adding scope tripped
 # self-host scan_locals; see feedback_self_host_recursive_fn_arm).
  def reduce_sym_op_for(nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      return ""
    end
    args = get_args(args_id)
    if args.length != 1
      return ""
    end
    if @nd_type[args[0]] != "SymbolNode"
      return ""
    end
    op = @nd_content[args[0]]
    if op == "+" || op == "*" || op == "-" || op == "/" || op == "%" || op == "&" || op == "|" || op == "^"
      return op
    end
    ""
  end

 # 1 if `mname` is a Math module function taking exactly one
 # argument and lowering to a libm call of the same name. Keep
 # in sync with math_fn_returns_float? in spinel_analyze.rb —
 # both files iterate over the same name set.
  def math_fn_one_arg?(mname)
    if mname == "sqrt" || mname == "cos" || mname == "sin" || mname == "tan"
      return 1
    end
    if mname == "acos" || mname == "asin" || mname == "atan"
      return 1
    end
    if mname == "sinh" || mname == "cosh" || mname == "tanh"
      return 1
    end
    if mname == "asinh" || mname == "acosh" || mname == "atanh"
      return 1
    end
    if mname == "log" || mname == "log2" || mname == "log10" || mname == "exp"
      return 1
    end
    0
  end

 # 1 if `mname` is a Math module function taking two arguments.
  def math_fn_two_arg?(mname)
    if mname == "atan2" || mname == "hypot"
      return 1
    end
    0
  end

  def compile_constant_recv_expr(nid, mname, recv, rc)
    rcname = constructor_class_name(recv)
 # `Mod.accessor` read for a `class << self; attr_accessor :x; end`
 # whose write side stored to the poly-slot const synthesized at
 # analyze time. The constant-fold path (used when every observed
 # write had a ConstantReadNode RHS) is checked separately below;
 # this arm covers the non-const RHS case where the slot holds an
 # sp_RbVal at runtime. Issue #511.
    if rcname != "" && (@nd_arguments[nid] < 0 || get_args(@nd_arguments[nid]).length == 0)
      if module_name_exists(rcname) == 1
        slot_r = rcname + "_" + mname
        if find_const_idx(slot_r) >= 0 && find_module_acc_idx(rcname + "." + mname) >= 0
          rconsts_r = module_acc_resolved(rcname, mname)
          if rconsts_r == "" || rconsts_r == "?"
            @needs_rb_value = 1
            return "cst_" + slot_r
          end
        end
      end
    end
    if rcname != ""
 # Foo.method_defined?(:sym[, inherit=true]) — compile-time decide.
 # Default arm walks the parent chain via class_has_method (covers
 # instance methods, attr readers/writers, ancestors). When the
 # second arg is the literal `false`, restrict the lookup to the
 # receiver's own methods (no parent walk) via class_has_method_local.
      if mname == "method_defined?"
        ci_md = find_class_idx(rcname)
        if ci_md >= 0
          args_id_md = @nd_arguments[nid]
          if args_id_md >= 0
            a_md = get_args(args_id_md)
            if a_md.length > 0
              if @nd_type[a_md[0]] == "SymbolNode" || @nd_type[a_md[0]] == "StringNode"
                lit_name = @nd_content[a_md[0]]
                inherit_md = 1
                if a_md.length >= 2 && @nd_type[a_md[1]] == "FalseNode"
                  inherit_md = 0
                end
                hit = inherit_md == 1 ? class_has_method(ci_md, lit_name) : class_has_method_local(ci_md, lit_name)
                return hit == 1 ? "TRUE" : "FALSE"
              end
            end
          end
        end
      end
 # ARGV methods
      if rcname == "ARGV"
        if mname == "length"
          @needs_argv = 1
          return "sp_argv.len"
        end
        if mname == "[]"
          @needs_argv = 1
          idx_expr = compile_arg0(nid)
          return "((" + idx_expr + " < sp_argv.len) ? sp_argv.data[(int)" + idx_expr + "] : NULL)"
        end
      end
 # Math.<fn> dispatch. Single source of truth via
 # math_fn_one_arg? / math_fn_two_arg?; the matching analyze-side
 # gate lives in spinel_analyze.rb:math_fn_returns_float? and
 # additions need both files updated.
      if rcname == "Math"
        if math_fn_one_arg?(mname) == 1
          return mname + "(" + compile_arg0(nid) + ")"
        end
        if math_fn_two_arg?(mname) == 1
          args_id = @nd_arguments[nid]
          if args_id >= 0
            arg_ids = get_args(args_id)
            if arg_ids.length >= 2
              return mname + "(" + compile_expr(arg_ids[0]) + ", " + compile_expr(arg_ids[1]) + ")"
            end
          end
        end
      end
 # Integer class methods (Ruby 2.5+)
      if rcname == "Integer"
        if mname == "sqrt"
 # Integer.sqrt(n) is the integer square root, distinct from
 # Math.sqrt's float result. Use sp_int_sqrt (Newton's method,
 # exact for the full mrb_int range) instead of casting through
 # double — double has only 53 bits of mantissa so values above
 # ~2^53 round and produce off-by-one results.
          return "sp_int_sqrt(" + compile_arg0(nid) + ")"
        end
      end
 # File operations
      if rcname == "File"
        if mname == "read" || mname == "binread"
          return "sp_file_read(" + compile_arg0(nid) + ")"
        end
        if mname == "exist?"
          return "sp_file_exist(" + compile_arg0(nid) + ")"
        end
        if mname == "directory?"
          return "sp_file_directory(" + compile_arg0(nid) + ")"
        end
        if mname == "file?"
          return "sp_file_file(" + compile_arg0(nid) + ")"
        end
        if mname == "readable?"
 # Reuse the exist check: on every platform Spinel
 # targets, a fopen-able file is also readable from
 # the same process. Distinguishing the two would
 # need access(2), which isn't worth a runtime fn for
 # the dead-code optcarrot battery-save path that
 # surfaced this.
          return "sp_file_exist(" + compile_arg0(nid) + ")"
        end
        if mname == "delete"
          return "(sp_file_delete(" + compile_arg0(nid) + "), 0)"
        end
        if mname == "binwrite" || mname == "write"
 # NOTE: `sp_file_write` uses fputs, so an embedded NUL
 # in the payload truncates the write; fine for the
 # optcarrot save-RAM dead-code path that surfaced
 # this, not safe for general binary use. File.write
 # in CRuby returns the number of bytes written; we
 # return 0 to match the statement-context lowering at
 # compile_control_call_stmt (which also discards the
 # byte count).
          args_id_bw = @nd_arguments[nid]
          if args_id_bw >= 0
            a_bw = get_args(args_id_bw)
            if a_bw.length >= 2
              return "(sp_file_write(" + compile_expr(a_bw[0]) + ", " + compile_expr(a_bw[1]) + "), 0)"
            end
          end
          return "0"
        end
        if mname == "join"
          args_id = @nd_arguments[nid]
          if args_id >= 0
            arg_ids = get_args(args_id)
            if arg_ids.length >= 2
              return "sp_str_concat(sp_str_concat(" + compile_expr(arg_ids[0]) + ", " + c_string_literal("/") + "), " + compile_expr(arg_ids[1]) + ")"
            end
          end
          return "\"\""
        end
        if mname == "basename"
          return "sp_file_basename(" + compile_arg0(nid) + ")"
        end
      end
      if rcname == "Time"
        if mname == "now"
          return "sp_time_now()"
        end
        if mname == "at"
          arg_id = compile_arg0(nid)
          args_id = @nd_arguments[nid]
          if args_id >= 0
            aargs = get_args(args_id)
            if aargs.length > 0 && infer_type(aargs[0]) == "float"
              return "sp_time_at_float(" + arg_id + ")"
            end
          end
          return "sp_time_at_int(" + arg_id + ")"
        end
 # Time.new(y[,mo[,d[,h[,mi[,s]]]]]) — local construction with
 # compile-time arity resolution (same shape as Time.at). Missing
 # positions get C-literal defaults; 0 args is the current time.
 # 7+ args is the fixed-offset form (a separate Issue): this arm
 # does not emit for it. analyze still types Time.new as "time",
 # so the call surfaces as an unresolved-call warning and then a
 # hard C type error — Time.new with an offset is unsupported and
 # fails to build by design, not silently.
        if mname == "new"
          nargs_id = @nd_arguments[nid]
          na = nargs_id >= 0 ? get_args(nargs_id) : []
          nn = na.length
          if nn == 0
            return "sp_time_now()"
          end
          if nn >= 1 && nn <= 6
            ny = compile_expr(na[0])
            nmo = nn >= 2 ? compile_expr(na[1]) : "1"
            nd = nn >= 3 ? compile_expr(na[2]) : "1"
            nh = nn >= 4 ? compile_expr(na[3]) : "0"
            nmi = nn >= 5 ? compile_expr(na[4]) : "0"
            ns = nn >= 6 ? compile_expr(na[5]) : "0"
            return "sp_time_new(" + ny + ", " + nmo + ", " + nd + ", " + nh + ", " + nmi + ", " + ns + ")"
          end
        end
      end
 # Complex.polar(magnitude, angle) — value-type Cartesian
 # Complex (sp_Complex). Used in optcarrot's nestopia palette
 # generator; see lib/sp_runtime.h for the runtime helpers.
 # Args may arrive boxed (poly) when the surrounding code
 # destructured them out of a poly_array; unbox via
 # sp_poly_to_f rather than a plain `(mrb_float)` cast (the
 # cast would mis-reinterpret the sp_RbVal struct).
      if rcname == "Complex"
        if mname == "polar"
          args_id_cp = @nd_arguments[nid]
          if args_id_cp >= 0
            aargs_cp = get_args(args_id_cp)
            if aargs_cp.length >= 2
              a0_e = compile_expr(aargs_cp[0])
              a1_e = compile_expr(aargs_cp[1])
              if infer_type(aargs_cp[0]) == "poly"
                a0_e = "sp_poly_to_f(" + a0_e + ")"
              else
                a0_e = "(mrb_float)(" + a0_e + ")"
              end
              if infer_type(aargs_cp[1]) == "poly"
                a1_e = "sp_poly_to_f(" + a1_e + ")"
              else
                a1_e = "(mrb_float)(" + a1_e + ")"
              end
              return "sp_complex_polar(" + a0_e + ", " + a1_e + ")"
            end
          end
        end
      end
 # Process.clock_gettime — assume CLOCK_MONOTONIC; the clock_id
 # arg is not modeled. Returns seconds as a float.
      if rcname == "Process"
        if mname == "clock_gettime"
          return "({ struct timespec _ts; clock_gettime(CLOCK_MONOTONIC, &_ts); (mrb_float)_ts.tv_sec + (mrb_float)_ts.tv_nsec / 1e9; })"
        end
      end
 # ENV
      if rcname == "ENV"
        if mname == "[]"
          return "sp_str_dup_external(getenv(" + compile_arg0(nid) + "))"
        end
        if mname == "fetch"
 # Two-arg form: ENV.fetch(key, default). If the env var is
 # set, return its value; otherwise return the supplied
 # default. The single-arg form (`ENV.fetch("X")`) raises
 # KeyError in CRuby; spinel doesn't model that, so it
 # behaves like ENV[] -- callers wanting strict behaviour
 # should pass an explicit default.
          args_id = @nd_arguments[nid]
          if args_id >= 0
            argz = get_args(args_id)
            if argz.length >= 2
              key = compile_expr(argz[0])
              dfl = compile_expr_as_string(argz[1])
              tmp = new_temp
              return "({ const char *" + tmp + " = getenv(" + key + "); " +
                     tmp + " ? sp_str_dup_external(" + tmp + ") : (" + dfl + "); })"
            end
            if argz.length == 1
              return "sp_str_dup_external(getenv(" + compile_arg0(nid) + "))"
            end
          end
          return "(&(\"\\xff\")[1])"
        end
      end
 # Dir
      if rcname == "Dir"
        if mname == "home"
          return "sp_str_dup_external(getenv(\"HOME\"))"
        end
      end
 # Module class method dispatch
      mi2 = 0
      while mi2 < @module_names.length
        if @module_names[mi2] == rcname
 # Look for module class method
          mfn = rcname + "_cls_" + mname
          mfi = find_method_idx(mfn)
          if mfi >= 0
 # Route through compile_call_args_with_defaults so a
 # `def self.greet(name, msg = nil); end` inside a
 # module accepts shorter call sites — caller-omitted
 # trailing args get filled in from the method's
 # recorded default expressions, the same as top-level
 # method calls.
            ca = compile_call_args_with_defaults(nid, mfi)
            if ca != ""
              return "sp_" + sanitize_name(mfn) + "(" + ca + ")"
            else
              return "sp_" + sanitize_name(mfn) + "()"
            end
          end
        end
        mi2 = mi2 + 1
      end
 # `Klass.method(:cls_meth)` — bind to a class method. Mirrors
 # the instance-recv `obj.method(:bar)` form (line ~20940), but
 # the underlying class method has no `self *` param. Emit a
 # static adapter trampoline that ignores the dispatch ABI's
 # `void *self` slot and forwards the rest, then bind the
 # Method's iv_fn_ptr to the adapter. iv_self_obj is unused but
 # set to a stable stand-in (a NULL pointer cast through
 # sp_Method *); the Method dispatch in compile_poly_method_call
 # passes it as the void * arg, which the adapter discards.
      if mname == "method"
        ci_cm = find_class_idx(rcname)
        if ci_cm >= 0
          args_id_cm = @nd_arguments[nid]
          if args_id_cm >= 0
            arg_ids_cm = get_args(args_id_cm)
            if arg_ids_cm.length >= 1
              cm_ref = @nd_content[arg_ids_cm[0]]
              if cm_ref == ""
                cm_ref = @nd_name[arg_ids_cm[0]]
              end
              owner_cm = cls_method_owner_for(ci_cm, cm_ref, "cmeth")
              if owner_cm >= 0
                owner_cm_name = @cls_names[owner_cm]
                emit_cls_method_adapter(owner_cm, cm_ref)
                adapter_name = "sp_" + owner_cm_name + "_" + sanitize_name(cm_ref) + "_cls_method_adapter"
                return "sp_Method_new((sp_Method *)0, (mrb_int)(uintptr_t)&" + adapter_name + ")"
              end
            end
          end
        end
      end
 # Class method dispatch (def self.xxx). walk the
 # parent chain so `Leaf.all` resolves to `Base.all`'s emitter
 # (`sp_Base_cls_all`, not `sp_Leaf_cls_all` which is never
 # generated when Leaf doesn't override).
      ci3 = find_class_idx(rcname)
      if ci3 >= 0
        owner_ci = cls_method_owner_for(ci3, mname, "cmeth")
        if owner_ci >= 0
          owner_name = @cls_names[owner_ci]
          owner_cmnames = @cls_cmeth_names[owner_ci].split(";")
          owner_cmptypes = @cls_cmeth_ptypes[owner_ci].split("|")
          owner_cmdefaults = @cls_cmeth_defaults[owner_ci].split("|")
          cmidx = 0
          while cmidx < owner_cmnames.length
            if owner_cmnames[cmidx] == mname
              break
            end
            cmidx = cmidx + 1
          end
          ca = ""
          if cmidx < owner_cmnames.length && cmidx < owner_cmptypes.length
            owner_pn = cls_cmeth_pnames_get(owner_ci, cmidx)
            owner_pt = owner_cmptypes[cmidx].split(",")
            owner_df = "".split(",")
            if cmidx < owner_cmdefaults.length
              owner_df = owner_cmdefaults[cmidx].split(",")
            end
 # Extract positional + kwarg pairs from the call site, so
 # `W.write(200, set_cookies: cookies)` against
 # `def self.write(status, set_cookies: {})` routes `cookies`
 # into the set_cookies slot (instead of compiling the
 # KeywordHashNode as a generic literal that lowers to 0).
 # Sibling to the kwarg-fallback path in
 # compile_call_args_with_defaults' instance-method handler.
            args_id_cm2 = @nd_arguments[nid]
            arg_ids_cm2 = []
            if args_id_cm2 >= 0
              arg_ids_cm2 = get_args(args_id_cm2)
            end
            kw_names_cm = "".split(",")
            kw_vals_cm = "".split(",")
            positional_cm = []
            ak_cm = 0
            while ak_cm < arg_ids_cm2.length
              if @nd_type[arg_ids_cm2[ak_cm]] == "KeywordHashNode"
                elems_cm = parse_id_list(@nd_elements[arg_ids_cm2[ak_cm]])
                ek_cm = 0
                while ek_cm < elems_cm.length
                  if @nd_type[elems_cm[ek_cm]] == "AssocNode"
                    key_id_cm = @nd_key[elems_cm[ek_cm]]
                    if key_id_cm >= 0 && @nd_type[key_id_cm] == "SymbolNode"
                      kw_names_cm.push(@nd_content[key_id_cm])
                      kw_vals_cm.push(compile_expr(@nd_expression[elems_cm[ek_cm]]))
                    end
                  end
                  ek_cm = ek_cm + 1
                end
              else
                positional_cm.push(arg_ids_cm2[ak_cm])
              end
              ak_cm = ak_cm + 1
            end
            pos_idx_cm = 0
            kk = 0
            while kk < owner_pn.length
              slot_expr_cm = ""
              if pos_idx_cm < positional_cm.length
                slot_expr_cm = cast_away_volatile_arg(positional_cm[pos_idx_cm], compile_expr(positional_cm[pos_idx_cm]))
                pos_idx_cm = pos_idx_cm + 1
              else
 # Try kwarg by name.
                pname_cm = owner_pn[kk]
                ki_cm = 0
                while ki_cm < kw_names_cm.length
                  if kw_names_cm[ki_cm] == pname_cm
                    slot_expr_cm = kw_vals_cm[ki_cm]
                    ki_cm = kw_names_cm.length
                  else
                    ki_cm = ki_cm + 1
                  end
                end
                if slot_expr_cm == ""
                  if kk < owner_df.length
                    def_id_cm = owner_df[kk].to_i
                    if def_id_cm >= 0
                      def_pt_cm = ""
                      if kk < owner_pt.length
                        def_pt_cm = owner_pt[kk]
                      end
                      coerced_cm = empty_hash_coerce(def_id_cm, def_pt_cm)
                      if coerced_cm != ""
                        slot_expr_cm = coerced_cm
                      else
                        slot_expr_cm = compile_expr(def_id_cm)
                      end
                    end
                  end
                end
              end
              if slot_expr_cm != ""
                if ca == ""
                  ca = slot_expr_cm
                else
                  ca = ca + ", " + slot_expr_cm
                end
              end
              kk = kk + 1
            end
            has_block_param = (owner_pt.length > 0 && owner_pt.last == "proc") ? 1 : 0
            if has_block_param == 1
              blk_types = ""
              if @cls_cmeth_blk_param_types != nil
                flat_idx = 0
                ci_walk = 0
                while ci_walk < owner_ci
                  if ci_walk < @cls_cmeth_names.length
                    flat_idx = flat_idx + @cls_cmeth_names[ci_walk].split(";").length
                  end
                  ci_walk = ci_walk + 1
                end
                flat_idx = flat_idx + cmidx
                if flat_idx < @cls_cmeth_blk_param_types.length
                  blk_types = @cls_cmeth_blk_param_types[flat_idx]
                end
              end
              block_proc = block_forward_expr(nid, blk_types)
              if block_proc != ""
                if ca != ""
                  ca = ca + ", " + block_proc
                else
                  ca = block_proc
                end
              end
            end
          end
          if ca != ""
            return "sp_" + owner_name + "_cls_" + sanitize_name(mname) + "(" + ca + ")"
          else
            return "sp_" + owner_name + "_cls_" + sanitize_name(mname) + "()"
          end
        end
      end
    end
    ""
  end

  def compile_to_a_range_expr(nid, recv)
    range_nid = -1
    if @nd_type[recv] == "RangeNode"
      range_nid = recv
    end
    if @nd_type[recv] == "ParenthesesNode"
      pb = @nd_body[recv]
      if pb >= 0
        pstmts = get_stmts(pb)
        if pstmts.length > 0
          if @nd_type[pstmts.first] == "RangeNode"
            range_nid = pstmts.first
          end
        end
      end
    end
    if range_nid >= 0
      @needs_int_array = 1
      @needs_gc = 1
      right_expr = compile_expr(@nd_right[range_nid])
 # sp_IntArray_from_range is inclusive; for `1...3` shave the upper end.
      if range_excl_end(range_nid) == 1
        right_expr = "(" + right_expr + ") - 1"
      end
      return "sp_IntArray_from_range(" + compile_expr(@nd_left[range_nid]) + ", " + right_expr + ")"
    end
    ""
  end

  def compile_open_class_dispatch_expr(nid, mname, rc, recv_type)
 # Open class method dispatch on built-in types
    oc_prefix = ""
    if recv_type == "int"
      oc_prefix = "__oc_Integer_"
    end
    if recv_type == "string"
      oc_prefix = "__oc_String_"
    end
    if recv_type == "float"
      oc_prefix = "__oc_Float_"
    end
    if oc_prefix != ""
      oc_name = oc_prefix + mname
      oc_mi = find_method_idx(oc_name)
      if oc_mi >= 0
        ca = compile_call_args(nid)
        if ca != ""
          return "sp_" + sanitize_name(oc_name) + "(" + rc + ", " + ca + ")"
        else
          return "sp_" + sanitize_name(oc_name) + "(" + rc + ")"
        end
      end
    end
    ""
  end

  def is_static_const_ref(aid)
    if @nd_type[aid] == "ConstantReadNode" || @nd_type[aid] == "ConstantPathNode"
      return 1
    end
    0
  end

 # Resolve an is_a?/kind_of?/instance_of? argument to its registered
 # class name. ConstantPathNode (`Foo::Bar`) walks the path via
 # resolve_const_ref_name; ConstantReadNode (`Foo`) carries the leaf
 # in @nd_name. Other shapes fall back to @nd_name so static lookup
 # still has a name to try.
  def resolve_introspection_arg_name(aid)
    if @nd_type[aid] == "ConstantPathNode"
      return resolve_const_ref_name(aid)
    end
    @nd_name[aid]
  end

  def compile_introspection_expr(nid, mname, rc, recv_type)
 # is_a? / kind_of? — kind_of? is an exact alias of is_a? in MRI.
 # Both walk the class hierarchy: cname is or inherits from arg0 → TRUE.
    if mname == "is_a?" || mname == "kind_of?"
      if is_obj_type(recv_type) == 1
        cname = recv_type[4, recv_type.length - 4]
        arg0 = ""
        args_id = @nd_arguments[nid]
        if args_id >= 0
          a = get_args(args_id)
          if a.length > 0
 # Dynamic Class arg (a non-const expression evaluating to a class).
 # The statically-typed recv knows its own cls_id; the arg carries
 # the target cls_id at runtime. sp_class_le walks the precomputed
 # ancestors table to decide membership.
            arg_t = infer_type(a[0])
            if arg_t == "class" && is_static_const_ref(a[0]) == 0
              ci = find_class_idx(cname)
              if ci >= 0
                @needs_class_table = 1
                @needs_class_ancestors = 1
                return "sp_class_le((sp_Class){" + cls_id_for_user_internal(ci).to_s + "LL}, " + compile_expr(a[0]) + ")"
              end
            end
            arg0 = resolve_introspection_arg_name(a[0])
          end
        end
        if is_class_or_ancestor(cname, arg0) == 1
          return "TRUE"
        end
 # Descendant case: arg0 is a proper subclass of cname (recv's
 # static type). The recv's static type only bounds the runtime
 # class above; the instance can be cname or any descendant
 # including arg0. Consult the recv's actual cls_id slot.
        target_ci = find_class_idx(arg0)
        if target_ci >= 0 && is_descendant(arg0, cname) == 1
          @needs_class_table = 1
          @needs_class_ancestors = 1
          recv_id = @nd_receiver[nid]
          if recv_id >= 0
            return "sp_class_le((sp_Class){" + compile_expr(recv_id) + "->cls_id}, (sp_Class){" + cls_id_for_user_internal(target_ci).to_s + "LL})"
          end
        end
 # Unrelated classes — neither ancestor nor descendant. Always FALSE.
        return "FALSE"
      end
      return "FALSE"
    end

 # instance_of? — exact class identity, no ancestor walk.
 # The recv's static type only bounds the runtime class above; the
 # instance can be the static type OR any descendant. The runtime
 # class can therefore equal arg0 only if arg0 is in that set —
 # i.e., arg0 is cname or a descendant of cname. Other shapes
 # (arg0 is an ancestor of cname, or unrelated) make the equality
 # statically impossible and collapse to FALSE.
 #
 # `cname == arg0` does NOT in general collapse to TRUE — a parent-
 # typed local holding a descendant returns FALSE for
 # `instance_of?(parent)`. The check is runtime via the recv's
 # cls_id slot. EXCEPTION: value-type classes have no subclasses
 # by design (no cls_id field on the struct, no polymorphism), so
 # for value-type cname the runtime is always exactly cname and
 # the cname == arg0 check collapses back to static TRUE.
    if mname == "instance_of?"
      arg0 = ""
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
          arg0 = resolve_introspection_arg_name(a[0])
        end
      end
 # Built-in container classes: every Array variant
 # (int_array / str_array / etc.) is conceptually `Array`
 # in CRuby; every Hash variant is `Hash`. Static recv-type
 # knowledge folds the check at compile time. Issue #562.
      if arg0 == "Array" && is_array_type(recv_type) == 1
        return "TRUE"
      end
      if arg0 == "Hash" && is_hash_type(recv_type) == 1
        return "TRUE"
      end
      if is_obj_type(recv_type) == 1
        cname = recv_type[4, recv_type.length - 4]
        target_ci = find_class_idx(arg0)
        if target_ci >= 0 && (cname == arg0 || is_descendant(arg0, cname) == 1)
          if is_value_type_class(cname) == 1
            return "TRUE"
          end
          @needs_class_table = 1
          recv_id = @nd_receiver[nid]
          if recv_id >= 0
            return "(" + compile_expr(recv_id) + "->cls_id == " + cls_id_for_user_internal(target_ci).to_s + "LL)"
          end
        end
        return "FALSE"
      end
      return "FALSE"
    end

 # respond_to? - check if method exists
    if mname == "respond_to?"
      if is_obj_type(recv_type) == 1
        cname = recv_type[4, recv_type.length - 4]
        ci = find_class_idx(cname)
        if ci >= 0
          arg0 = ""
          args_id = @nd_arguments[nid]
          if args_id >= 0
            a = get_args(args_id)
            if a.length > 0
              arg0 = @nd_content[a[0]]
            end
          end
          if cls_find_method(ci, arg0) >= 0
            return "TRUE"
          end
 # Check attr_readers
          readers = @cls_attr_readers[ci].split(";")
          rk = 0
          while rk < readers.length
            if readers[rk] == arg0
              return "TRUE"
            end
            rk = rk + 1
          end
          return "FALSE"
        end
      end
      return "FALSE"
    end

 # nil?
    if mname == "nil?"
      if recv_type == "nil"
        return "TRUE"
      end
      if recv_type == "poly"
        return "sp_poly_nil_p(" + rc + ")"
      end
      if is_nullable_type(recv_type) == 1
        return "(" + rc + " == NULL)"
      end
      if type_is_pointer(recv_type) == 1
        return "(" + rc + " == NULL)"
      end
      return "FALSE"
    end

 # frozen? on any type
    if mname == "frozen?"
      return "TRUE"
    end

 # `freeze` on any object — returns the receiver. The string /
 # mutable-str dispatchers earlier in compile_call_expr handle their
 # own variants; this catches everything else (obj_*, sp_Object *,
 # array types, etc.) so `expr.freeze` in a const initializer (issue
 # #63) doesn't fall through to the "0" fallback.
    if mname == "freeze"
      return rc
    end

 # positive? / negative?
    if mname == "positive?"
      return "(" + rc + " > 0)"
    end
    if mname == "negative?"
      return "(" + rc + " < 0)"
    end
    ""
  end

  def compile_object_method_expr(nid, mname, rc, recv_type)
 # `self.name` inside `def self.<m>` -- self is typed obj_<C>
 # by infer_type, but the runtime intent is the class itself.
 # Route to sp_class_to_s before the obj-dispatch arms below
 # would emit a no-op. Issue #509.
    if mname == "name" && @current_method_has_self == 0 && @current_class_idx >= 0
      recv_n = @nd_receiver[nid]
      if recv_n >= 0 && @nd_type[recv_n] == "SelfNode"
        @needs_class_table = 1
        return "sp_class_to_s(((sp_Class){" + cls_id_for_user_internal(@current_class_idx).to_s + "LL}))"
      end
    end
 # methods on a sp_Class value.
 #
 # Phase 1: `.to_s` -> sp_class_to_s(c) (per-program
 # sp_class_names[] lookup).
 #
 # Phase 2 additions:
 # - `.name` / `.inspect` -- both alias `.to_s` in the simple
 # case. CRuby's #inspect is technically `"#<Class:Foo>"`
 # but Phase 2 keeps the bare-name shape consistent with
 # the existing #to_s; the canonical CRuby spelling is a
 # Phase 3 polish.
 # - `.==` / `.!=` / `.eql?` -- equality compares the cls_id
 # fields via the sp_class_eq runtime helper.
 #
 # Out of scope for Phase 2: `.superclass`, `.ancestors`,
 # `.<` / `.<=` / `.>` / `.>=`, dynamic `is_a?(c)` against a
 # variable, case-when on a Class value. Those need
 # precomputed ancestor tables (see docs/CLASS-OBJECT.md).
    if recv_type == "class"
 # `Kernel.<m>(args)` routes to the bare-method
 # dispatch (compile_no_recv_call_expr handles `sleep` /
 # `puts` / `rand` / etc. as zero-receiver calls already).
 # Bare `sleep(...)` works fine; the Kernel-prefixed form
 # was emit-0'd because compile_object_method_expr's
 # recv_type=="class" arms only covered class-introspection
 # methods. CRuby's Kernel includes every method-function
 # we already implement at the bare path, so the redirect
 # is uniform -- no per-method list needed here.
      recv_id = @nd_receiver[nid]
      if recv_id >= 0 && @nd_type[recv_id] == "ConstantReadNode" && @nd_name[recv_id] == "Kernel"
        return compile_no_recv_call_expr(nid, mname)
      end
      if mname == "to_s" || mname == "name" || mname == "inspect"
        @needs_class_table = 1
        return "sp_class_to_s(" + rc + ")"
      end
      if mname == "==" || mname == "eql?"
        rhs_eq = compile_arg0(nid)
        return "sp_class_eq(" + rc + ", " + rhs_eq + ")"
      end
      if mname == "!="
        rhs_ne = compile_arg0(nid)
        return "(!sp_class_eq(" + rc + ", " + rhs_ne + "))"
      end
 # `<class_value_slot>.nil?` — sp_Class's nil sentinel is
 # cls_id == -1 (matches sp_class_superclass's root return and
 # the default value emitted for unassigned `attr_accessor`
 # class slots). Without this arm the call falls through to the
 # constant-receiver dispatch which would emit
 # `sp_<Klass>_cls_nil_p()` against whatever concrete class the
 # slot was statically resolved to — an undeclared function.
      if mname == "nil?"
        return "((" + rc + ").cls_id == -1)"
      end
 # class hierarchy queries.
 # .superclass -> sp_class_superclass(c) (returns sp_Class{-1} for root)
 # .ancestors -> sp_class_ancestors_arr(c) (returns sp_PolyArray of boxed sp_Class)
 # <, <= -> sp_class_lt / sp_class_le (proper / non-proper subclass)
 # >, >= -> reversed args of the above.
      if mname == "superclass"
        @needs_class_table = 1
        @needs_class_parents = 1
        return "sp_class_superclass(" + rc + ")"
      end
      if mname == "ancestors"
        @needs_class_table = 1
        @needs_class_ancestors = 1
        @needs_rb_value = 1
        return "sp_class_ancestors_arr(" + rc + ")"
      end
      if mname == "<"
        @needs_class_table = 1
        @needs_class_ancestors = 1
        return "sp_class_lt(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == "<="
        @needs_class_table = 1
        @needs_class_ancestors = 1
        return "sp_class_le(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == ">"
        @needs_class_table = 1
        @needs_class_ancestors = 1
        return "sp_class_lt(" + compile_arg0(nid) + ", " + rc + ")"
      end
      if mname == ">="
        @needs_class_table = 1
        @needs_class_ancestors = 1
        return "sp_class_le(" + compile_arg0(nid) + ", " + rc + ")"
      end
 # Tier 5: `<sp_Class>.new` over a *dynamic*
 # Class value (Class-typed local / param / ivar). Routes
 # through the per-cls_id adapter table. The static constant
 # path (`Foo.new(...)`) keeps using constructor_class_name
 # / direct sp_<C>_new dispatch -- we only want dynamic
 # recv here.
      if mname == "new"
        recv_id_new = @nd_receiver[nid]
        recv_ty_new = recv_id_new >= 0 ? @nd_type[recv_id_new] : ""
        if recv_ty_new != "ConstantReadNode" && recv_ty_new != "ConstantPathNode"
          nargs_id = @nd_arguments[nid]
          if nargs_id < 0 || get_args(nargs_id).length == 0
            @needs_class_table = 1
            @needs_rb_value = 1
            return "sp_class_new_dispatch(" + rc + ")"
          end
        end
      end
 # `<obj>.class.<cmeth>(...)` lowering. The recv
 # here is itself a `<X>.class` CallNode -- the outer
 # `compile_call_expr` already emitted the inner sp_Class
 # literal into `rc`, but for a `cmeth` dispatch we want to
 # bypass the runtime sp_Class value and emit a direct
 # `sp_<C>_cls_<m>` call against the statically-known class.
 # Gated on the recv AST being a `class` CallNode whose own
 # recv has a known obj_<C> type, so dynamic poly Class
 # values still fall through (they're Phase 3 work).
      recv_id = @nd_receiver[nid]
      if recv_id >= 0 && @nd_type[recv_id] == "CallNode" && @nd_name[recv_id] == "class"
        inner_recv = @nd_receiver[recv_id]
        if inner_recv >= 0
          inner_t = infer_type(inner_recv)
          if is_obj_type(inner_t) == 1
            inner_bt = base_type(inner_t)
            inner_cname = inner_bt[4, inner_bt.length - 4]
            inner_ci = find_class_idx(inner_cname)
            if inner_ci >= 0
              owner_idx = cls_method_owner_for(inner_ci, mname, "cmeth")
              if owner_idx >= 0
                owner_name = @cls_names[owner_idx]
                ca = compile_call_args(nid)
 # when descendants of inner_ci override
 # `mname` as a cmeth, the static call below routes
 # everything to the base class -- wrong when the
 # runtime instance is actually a subclass. Lower to
 # a switch on `<inner>->cls_id` so the dispatch lands
 # on the override. Gated on:
 # - inner_recv simple (SelfNode or LocalVar) so its
 # C expression has no side effects and can be
 # reused for both `->cls_id` and the per-arm call.
 # - inner_ci non-value-type (value types have no
 # cls_id slot and no subclassing in spinel).
 # - args absent (the no-arg case covers the canonical
 # reproducer and lets us reuse compile_call_args
 # output across arms without reasoning about side
 # effects from arg expressions).
 # - all candidate owners' return types match (otherwise
 # a unified result temp can't be typed).
                ovr = ""
                if @cls_is_value_type[inner_ci] == 0 && ca == ""
                  nty = @nd_type[inner_recv]
                  if nty == "SelfNode" || nty == "LocalVariableReadNode"
                    ovr = cls_method_override_descendants(inner_ci, owner_idx, mname, "cmeth")
                  end
                end
                if ovr != ""
                  base_rt = cls_method_return(owner_idx, mname, "cmeth")
                  ovr_pairs = ovr.split(";")
                  rt_ok = 1
                  op = 0
                  while op < ovr_pairs.length
                    pair = ovr_pairs[op].split(",")
                    cand_owner_check = pair[1].to_i
                    cand_rt = cls_method_return(cand_owner_check, mname, "cmeth")
                    if cand_rt != base_rt
                      rt_ok = 0
                      op = ovr_pairs.length
                    else
                      op = op + 1
                    end
                  end
                  inner_c_chain = compile_expr(inner_recv)
                  tmp_chain = new_temp
                  default_call_chain = "sp_" + owner_name + "_cls_" + sanitize_name(mname) + "()"
                  if rt_ok == 1
 # Matching return types across base + descendants
 # (the canonical shape). Declare the temp with
 # the shared C type and put the base call in the
 # `default:` arm so a base-only implementation
 # that raises -- the Rails abstract-base pattern --
 # only fires when the runtime cls_id is the base
 # (or an unmodelled type), not on every dispatch.
                    rt_c_chain = c_type(base_rt)
                    emit("  " + rt_c_chain + " " + tmp_chain + " = " + c_default_val(base_rt) + ";")
                    emit("  switch (" + inner_c_chain + "->cls_id) {")
                    oi_chain = 0
                    while oi_chain < ovr_pairs.length
                      pair_chain = ovr_pairs[oi_chain].split(",")
                      cand_cid_chain = pair_chain[0].to_i
                      cand_owner_chain = pair_chain[1].to_i
                      cand_name_chain = @cls_names[cand_owner_chain]
                      cand_call_chain = "sp_" + cand_name_chain + "_cls_" + sanitize_name(mname) + "()"
 # cls_id_for_user_internal converts the candidate
 # internal index to the unified id that the
 # constructor stamped into self->cls_id.
                      emit("    case " + cls_id_for_user_internal(cand_cid_chain).to_s + "LL: " + tmp_chain + " = " + cand_call_chain + "; break;")
                      oi_chain = oi_chain + 1
                    end
                    emit("    default: " + tmp_chain + " = " + default_call_chain + "; break;")
                    emit("  }")
                    return tmp_chain
                  else
 # candidate return types diverge -- the
 # canonical "abstract base raises, subclass returns
 # a concrete value" Rails pattern, plus the milder
 # "different concrete types per override". Box each
 # arm's return into sp_RbVal so the unified result
 # temp has a single C type, and route the base call
 # through the `default:` arm so a raise stub only
 # fires when the runtime cls_id genuinely lands on
 # the base. infer_type on the analyze side widens
 # the chain's return to "poly" so downstream
 # callers consume the boxed value through the
 # existing poly-dispatch machinery.
                    @needs_rb_value = 1
                    default_box_chain = box_value_to_poly(base_rt, default_call_chain)
                    emit("  sp_RbVal " + tmp_chain + " = sp_box_nil();")
                    emit("  switch (" + inner_c_chain + "->cls_id) {")
                    oi_div = 0
                    while oi_div < ovr_pairs.length
                      pair_div = ovr_pairs[oi_div].split(",")
                      cand_cid_div = pair_div[0].to_i
                      cand_owner_div = pair_div[1].to_i
                      cand_name_div = @cls_names[cand_owner_div]
                      cand_rt_div = cls_method_return(cand_owner_div, mname, "cmeth")
                      cand_call_div = "sp_" + cand_name_div + "_cls_" + sanitize_name(mname) + "()"
                      cand_box_div = box_value_to_poly(cand_rt_div, cand_call_div)
                      emit("    case " + cls_id_for_user_internal(cand_cid_div).to_s + "LL: " + tmp_chain + " = " + cand_box_div + "; break;")
                      oi_div = oi_div + 1
                    end
                    emit("    default: " + tmp_chain + " = " + default_box_chain + "; break;")
                    emit("  }")
                    return tmp_chain
                  end
                end
                if ca == ""
                  return "sp_" + owner_name + "_cls_" + sanitize_name(mname) + "()"
                end
                return "sp_" + owner_name + "_cls_" + sanitize_name(mname) + "(" + ca + ")"
              end
            end
          end
        end
      end
    end
 # `<obj>.class` on an object with a statically-known
 # class. Returns a sp_Class value carrying the class id; the
 # surrounding chain consumes it (typically through the
 # recv_type == "class" arm above for the next method, or via
 # an assignment like `c = obj.class; c.to_s`).
    if mname == "class" && is_obj_type(recv_type) == 1
      cls_bt = base_type(recv_type)
      cls_cname = cls_bt[4, cls_bt.length - 4]
      cls_idx = find_class_idx(cls_cname)
      if cls_idx >= 0
        @needs_class_table = 1
        return "((sp_Class){" + cls_id_for_user_internal(cls_idx).to_s + "LL})"
      end
    end
 # Object method calls
    if is_obj_type(recv_type) == 1
      bt = base_type(recv_type)
      cname = bt[4, bt.length - 4]
      ci = find_class_idx(cname)
      if ci >= 0
        arrow = "->"
        if @cls_is_value_type[ci] == 1
          arrow = "."
        end
 # attr_reader -- walks the parent chain for inherited
 # attr_accessor / attr_reader (issue #508).
        if cls_has_attr_reader(ci, mname) == 1
          return rc + arrow + sanitize_ivar(mname)
        end
 # attr_writer
        if mname.length > 1
          if mname[mname.length - 1] == "="
            bname = mname[0, mname.length - 1]
            writers = @cls_attr_writers[ci].split(";")
            j = 0
            while j < writers.length
              if writers[j] == bname
 # Box the rhs when the slot is poly so the assignment
 # type-matches at C level. Spill the rhs to a typed
 # temp first via a statement-expression so its side
 # effects run exactly once: the chain's value must be
 # the *original* rhs (Ruby's `obj.attr = v` returns
 # `v`), so without the temp the comma form would
 # textually substitute `arg0_w` twice and re-execute
 # any function call inside it.
                slot_t = cls_ivar_type(ci, "@" + bname)
                arg0_w = compile_arg0(nid)
                if slot_t == "poly"
                  arg_t = "int"
                  args_id_w = @nd_arguments[nid]
                  if args_id_w >= 0
                    arg_ids_w = get_args(args_id_w)
                    if arg_ids_w.length > 0
                      arg_t = infer_type(arg_ids_w[0])
                    end
                  end
                  tmp_w = new_temp
                  boxed = box_value_to_poly(arg_t, tmp_w)
                  return "({" + c_type(arg_t) + " " + tmp_w + " = " + arg0_w + "; " + rc + arrow + sanitize_ivar(bname) + " = " + boxed + "; " + tmp_w + ";})"
                end
                return "(" + rc + arrow + sanitize_ivar(bname) + " = " + arg0_w + ")"
              end
              j = j + 1
            end
          end
        end
 # Method call
        owner = find_method_owner(ci, mname)
        if owner != ""
          oci2 = find_class_idx(owner)
          midx2 = -1
          if oci2 >= 0
            midx2 = cls_find_method_direct(oci2, mname)
          end
 # Omit the trailing &block slot from default-padding when the
 # callee declares one — we'll fill it explicitly from the
 # call site's literal block below.
          has_proc = cls_method_has_block_param(oci2, midx2)
          ca = ""
          if midx2 >= 0
            ca = compile_typed_call_args(nid, oci2, midx2, has_proc)
          else
            ca = compile_call_args(nid)
          end
          bp = ""
          if has_proc == 1
            bp = block_forward_expr(nid)
            if bp == ""
 # The callee declares &block but the call site provides
 # none — fill the slot with NULL so the C call has the
 # right arity.
              bp = "0"
            end
          end
 # Pad the trailing `_block, _benv` yield-ABI slots when the callee's
 # body uses `yield`. The literal-block path inlines via
 # compile_yield_call_stmt and bypasses this C call entirely, so
 # reaching here means no literal block at the call site.
          yargs = cls_call_yargs(oci2, midx2)
          tail = build_call_tail(ca, bp, yargs)
 # Self-receiver override dispatch: when the receiver is
 # `self` inside a parent-class method body and descendants
 # of @current_class_idx override `mname` (including the
 # operator forms `[]` / `[]=` / `==` / `<=>` / etc.), emit
 # a `switch (self->cls_id)` so the dispatch lands on the
 # override at runtime. Mirrors the bare-imeth case at
 # compile_call_expr's @current_class_idx path. Without
 # this, `self[:foo]` inside `Base#fetch` resolved
 # statically to Base#__aref even when Article < Base
 # overrode `[]`. Issue #563.
          recv_id_so = @nd_receiver[nid]
          if recv_id_so >= 0 && @nd_type[recv_id_so] == "SelfNode" && @current_class_idx >= 0 && @cls_is_value_type[@current_class_idx] == 0 && has_proc == 0
            ovr_pairs_so = cls_method_override_descendants(@current_class_idx, oci2, mname, "imeth")
            if ovr_pairs_so != ""
              base_rt_so = cls_method_return(oci2, mname)
              base_rt_c_so = c_type(base_rt_so)
              rt_ok_so = 1
              ovr_list_so = ovr_pairs_so.split(";")
              ol_so = 0
              while ol_so < ovr_list_so.length
                p_so = ovr_list_so[ol_so].split(",")
                cand_owner_so = p_so[1].to_i
                cand_rt_so = cls_method_return(cand_owner_so, mname)
                if c_type(cand_rt_so) != base_rt_c_so
                  rt_ok_so = 0
                  ol_so = ovr_list_so.length
                else
                  ol_so = ol_so + 1
                end
              end
              base_ptypes_so = midx2 >= 0 ? cls_meth_ptypes_get(oci2, midx2) : "".split(",")
              pt_ok_so = cls_imeth_override_ptypes_match(ovr_pairs_so, mname, base_ptypes_so)
              if rt_ok_so == 1 && pt_ok_so == 1
                tmp_so = new_temp
                default_call_so = ""
                if owner == cname
                  default_call_so = "sp_" + owner + "_" + sanitize_name(mname) + "(" + rc + tail + ")"
                else
                  default_call_so = "sp_" + owner + "_" + sanitize_name(mname) + "((sp_" + owner + " *)" + rc + tail + ")"
                end
                emit("  " + base_rt_c_so + " " + tmp_so + " = " + c_return_default(base_rt_so) + ";")
                emit("  switch (" + rc + "->cls_id) {")
                ol2_so = 0
                while ol2_so < ovr_list_so.length
                  p2_so = ovr_list_so[ol2_so].split(",")
                  cand_internal_ci_so = p2_so[0].to_i
                  cand_cid_so = cls_id_for_user_internal(cand_internal_ci_so)
                  cand_owner2_so = p2_so[1].to_i
                  cand_name_so = @cls_names[cand_owner2_so]
                  cand_call_so = "sp_" + cand_name_so + "_" + sanitize_name(mname) + "((sp_" + cand_name_so + " *)" + rc + tail + ")"
                  emit("    case " + cand_cid_so.to_s + "LL: " + tmp_so + " = " + cand_call_so + "; break;")
                  ol2_so = ol2_so + 1
                end
                emit("    default: " + tmp_so + " = " + default_call_so + "; break;")
                emit("  }")
                return tmp_so
              end
            end
          end
          if owner == cname
            return "sp_" + owner + "_" + sanitize_name(mname) + "(" + rc + tail + ")"
          else
            return "sp_" + owner + "_" + sanitize_name(mname) + "((sp_" + owner + " *)" + rc + tail + ")"
          end
        end
      end
    end
    ""
  end

  def compile_int_class_fallback_expr(nid, mname, rc, recv_type)
 # Fallback: if receiver is int (e.g. from IntArray get) but method belongs to a class,
 # cast the int to the appropriate class pointer and dispatch.
 #
 # ...but NOT when `mname` is a method also defined on a
 # primitive type (String, Array, Hash, Integer, etc.). The
 # int-to-class cast here would silently pick the first user
 # class defining the same method name — e.g. routing
 # `s.index("[")` (a String method on a still-int-typed param)
 # to `ArticlesController#index`. A param typed `mrb_int`
 # because it wasn't pinned upstream is not the IntArray-of-
 # pointers shape this fallback was written for; refuse to
 # pick a user class and let the unresolved-call diagnostic
 # fire instead.
    if recv_type == "int" && primitive_method_shared_with_user_class(mname) == 1
      return ""
    end
    if recv_type == "int"
      ci2 = 0
      while ci2 < @cls_names.length
        cname2 = @cls_names[ci2]
        readers2 = @cls_attr_readers[ci2].split(";")
        found_reader = 0
        j2 = 0
        while j2 < readers2.length
          if readers2[j2] == mname
            found_reader = 1
          end
          j2 = j2 + 1
        end
        if found_reader == 1
          return "((sp_" + cname2 + " *)" + rc + ")->" + sanitize_ivar(mname)
        end
 # Check writers
        if mname.length > 1
          if mname[mname.length - 1] == "="
            bname2 = mname[0, mname.length - 1]
            writers2 = @cls_attr_writers[ci2].split(";")
            j2 = 0
            while j2 < writers2.length
              if writers2[j2] == bname2
                return "(((sp_" + cname2 + " *)" + rc + ")->" + sanitize_ivar(bname2) + " = " + compile_arg0(nid) + ")"
              end
              j2 = j2 + 1
            end
          end
        end
 # Check methods
        owner2 = find_method_owner(ci2, mname)
        if owner2 != ""
          oci3 = find_class_idx(owner2)
          midx3 = -1
          if oci3 >= 0
            midx3 = cls_find_method_direct(oci3, mname)
          end
          ca2 = ""
          if midx3 >= 0
            ca2 = compile_typed_call_args(nid, oci3, midx3, 0)
          else
            ca2 = compile_call_args(nid)
          end
          if ca2 != ""
            return "sp_" + owner2 + "_" + sanitize_name(mname) + "((sp_" + owner2 + " *)" + rc + ", " + ca2 + ")"
          else
            return "sp_" + owner2 + "_" + sanitize_name(mname) + "((sp_" + owner2 + " *)" + rc + ")"
          end
        end
        ci2 = ci2 + 1
      end
    end
    ""
  end


 # Inferred return type for `recv.mname(...)` when `recv` is poly.
 # If every user class that defines mname agrees on the return type,
 # that concrete type is used. If any two disagree, the call is
 # genuinely polymorphic and the caller must treat the result as
 # an sp_RbVal.
 # Returns 1 if class `ci` declares `mname` as an attr_reader (in
 # which case `obj.<mname>` reads `obj->iv_<mname>`).
  def cls_has_attr_reader(ci, mname)
    readers = @cls_attr_readers[ci].split(";")
    j = 0
    while j < readers.length
      if readers[j] == mname
        return 1
      end
      j = j + 1
    end
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        return cls_has_attr_reader(pi, mname)
      end
    end
    0
  end

 # Decide whether a `<poly>[k]` call site (the outer `[]` in
 # `arr[i][k]` chains) can return int instead of poly. The poly
 # value came from `arr[i]` where `arr` is a poly_array; if every
 # element kind observed for `arr`'s slot has an int-returning
 # `[]` (IntArray + Method, the optcarrot `__fetch__` shape), the
 # outer dispatch is guaranteed to land on a poly carrying an int
 # tag, and we can read it as `mrb_int` directly. Returns 0
 # Return the type that compile_poly_method_call would actually emit
 # for `<poly>[idx]`, or "" if `nid` isn't that shape. Used by
 # infer_type to keep its static answer in sync with the emit; the
 # cached annotation from analyze can lag the emit's narrow_int
 # decision (block-param recvs short-circuit narrowing), and
 # downstream consumers like compile_arg0_as_int rely on the
 # answer matching the C type of the temp the emit produces.
  def poly_aref_call_type(nid)
    if @nd_type[nid] != "CallNode" || @nd_name[nid] != "[]"
      return ""
    end
    recv_id = @nd_receiver[nid]
    if recv_id < 0 || infer_type(recv_id) != "poly"
      return ""
    end
    if poly_index_narrow_int(nid) == 1
      return "int"
    end
    "poly"
  end

 # `nullable_poly_hash[k]` — recv's static type carries `?` (a
 # `if recv.nil?; return; end` upstream doesn't strip the suffix),
 # so analyze's [] dispatch falls through to the int default in
 # its cache. The actual emit is sp_<*PolyHash>_get(...) returning
 # sp_RbVal, so the cached "int" diverges from the C temp type and
 # the caller's int-typed param then receives an sp_RbVal unboxed.
 # Detect the shape here so compile_expr_for_expected_type and the
 # poly-dispatch arm can do the unbox even when cached "at" lied.
  def expr_emits_poly_rb_val(nid)
    if @nd_type[nid] != "CallNode" || @nd_name[nid] != "[]"
      return 0
    end
    recv_id = @nd_receiver[nid]
    if recv_id < 0
      return 0
    end
    rt = infer_type(recv_id)
    bt = base_type(rt)
    if bt == "sym_poly_hash" || bt == "str_poly_hash" || bt == "poly_poly_hash"
      return 1
    end
    0
  end

 # whenever the chain doesn't fit the pattern, so the default
 # poly-typed temp is preserved for everything else.
  def poly_index_narrow_int(nid)
    recv_id = @nd_receiver[nid]
    if recv_id < 0
      return 0
    end
 # The receiver must itself be a `[]` call (`arr[i]`).
    if @nd_type[recv_id] != "CallNode" || @nd_name[recv_id] != "[]"
      return 0
    end
    inner_recv = @nd_receiver[recv_id]
    if inner_recv < 0
      return 0
    end
 # Resolve the inner receiver to an ivar (directly, or via a
 # one-step LV alias from `lv = @ivar`).
    iname = ""
    if @nd_type[inner_recv] == "InstanceVariableReadNode"
      iname = @nd_name[inner_recv]
    elsif @nd_type[inner_recv] == "LocalVariableReadNode"
      lv_name = @nd_name[inner_recv]
 # Codegen-time scope alias takes priority (set by the LV-write
 # handler when `lv = @ivar` is emitted in this scope).
      iname = find_var_ivar_alias(lv_name)
 # Fallback for inference-time (`infer_type` before codegen,
 # when the scope stack hasn't been populated yet): walk the
 # enclosing method bodies for a single, unambiguous
 # `lv_name = @ivar` write. If the LV is reassigned from a
 # non-ivar elsewhere, leave iname empty and let the caller
 # bail out — the alias is no longer load-bearing.
      if iname == ""
        iname = find_lv_ivar_alias_in_ast(lv_name)
      end
    end
    if iname == "" || @current_class_idx < 0
      return 0
    end
 # The slot must currently be a poly_array — the only shape that
 # produces a poly via `[i]`.
    slot_t = cls_ivar_type(@current_class_idx, iname)
    if slot_t != "poly_array"
      return 0
    end
 # Derive the heterogeneous element kinds from
 # `cls_ivar_observed_types`. Each entry there is a slot type
 # the ivar held at some scan iteration: `int_array` means int
 # elements were stored, `obj_Method_ptr_array` means Method
 # elements, etc. The final `poly_array` entry just records the
 # widened state and adds no info. A bare `poly` observation
 # (whole-ivar `@x = something_poly`) is unknown — bail out.
    obs = cls_ivar_observed_types_for(@current_class_idx, iname)
    if obs == ""
      return 0
    end
    distinct = obs.split(",")
    saw_any = 0
    di = 0
    while di < distinct.length
      t = distinct[di]
      if t == "" || t == "poly_array"
 # ignore — uninformative
      elsif t == "int_array" || t == "obj_Method_ptr_array"
 # int-returning element kind
        saw_any = 1
      else
 # any other observed slot type (str_array, float_array,
 # other ptr_array variants, "poly" whole-ivar writes…) is
 # not safely narrowable.
        return 0
      end
      di = di + 1
    end
    saw_any
  end

 # Inference-time fallback for resolving `lv_name -> @ivar` when the
 # codegen scope alias isn't available yet. Walks every method body
 # in the current class for `lv_name = @ivar` writes. Returns the
 # ivar name only if the LV is unambiguously aliased (one ivar
 # source, no non-ivar reassignment); empty string otherwise. Cached
 # in `@lv_alias_cache_<class>:<lv>` to keep the per-narrow cost
 # down — this is called during type inference, which runs many
 # iterations.
  def find_lv_ivar_alias_in_ast(lv_name)
    if @current_class_idx < 0
      return ""
    end
    cache_key = @current_class_idx.to_s + ":" + lv_name
    if @lv_alias_cache.key?(cache_key)
      return @lv_alias_cache[cache_key]
    end
    found = ""
    bodies = @cls_meth_bodies[@current_class_idx].split(";")
    bi = 0
    while bi < bodies.length
      bid = bodies[bi].to_i
      if bid >= 0
        r = scan_lv_alias_for(bid, lv_name)
        if r == "?"
 # Ambiguous: at least one non-ivar write to this LV. The
 # alias is unstable and unsafe to use for narrowing.
          found = ""
          break
        end
        if r != ""
          if found != "" && found != r
            found = ""
            break
          end
          found = r
        end
      end
      bi = bi + 1
    end
    @lv_alias_cache[cache_key] = found
    found
  end

 # Recursive AST walk under `nid`. Returns:
 # "" — no `lv_name = ...` write seen
 # "?" — `lv_name = <non-ivar>` write seen (alias is unstable)
 # "@x" — exactly one ivar source `lv_name = @x` seen
  def scan_lv_alias_for(nid, lv_name)
    if nid < 0
      return ""
    end
    found = ""
    if @nd_type[nid] == "LocalVariableWriteNode" && @nd_name[nid] == lv_name
      ex_id = @nd_expression[nid]
      if ex_id >= 0 && @nd_type[ex_id] == "InstanceVariableReadNode"
        found = @nd_name[ex_id]
      else
        return "?"
      end
    end
    cs = []
    push_child_ids(nid, cs)
    k = 0
    while k < cs.length
      r = scan_lv_alias_for(cs[k], lv_name)
      if r == "?"
        return "?"
      end
      if r != ""
        if found != "" && found != r
          return "?"
        end
        found = r
      end
      k = k + 1
    end
    found
  end

 # Read the comma-separated whole-ivar observation list for a given
 # ivar by name. Used by `poly_index_narrow_int`.
  def cls_ivar_observed_types_for(ci, iname)
    if ci < 0 || ci >= @cls_ivar_observed_types.length
      return ""
    end
    names = @cls_ivar_names[ci].split(";")
    parts = @cls_ivar_observed_types[ci].split(";", -1)
    k = 0
    while k < names.length
      if names[k] == iname && k < parts.length
        return parts[k]
      end
      k = k + 1
    end
    ""
  end

 # Poly-recv dispatch helpers (poly_dispatch_return_type /
 # poly_dispatch_narrow_class_set / poly_dispatch_class_in_set /
 # poly_dispatch_arm_param_compat) moved to compiler_helpers.rb
 # -- shared with spinel_analyze.rb.

 # Runtime tag-check for `<poly>.is_a?(<klass>)` / `kind_of?` /
 # `instance_of?`. Returns a C boolean expression for the named
 # built-in class (Integer, String, Float, etc.), including
 # mixin-style names that match every value (Object, Kernel,
 # BasicObject, Comparable). Returns "" when the name has no
 # SP_TAG_* mapping (caller falls back to user-class dispatch).
  def poly_is_a_tag_check(klass, recv_tmp, is_instance_of)
    if klass == "Integer"
      return "(" + recv_tmp + ".tag == SP_TAG_INT)"
    end
    if klass == "String"
      return "(" + recv_tmp + ".tag == SP_TAG_STR)"
    end
    if klass == "Float"
      return "(" + recv_tmp + ".tag == SP_TAG_FLT)"
    end
    if klass == "Symbol"
      return "(" + recv_tmp + ".tag == SP_TAG_SYM)"
    end
    if klass == "NilClass"
      return "(" + recv_tmp + ".tag == SP_TAG_NIL)"
    end
    if klass == "TrueClass"
      return "(" + recv_tmp + ".tag == SP_TAG_BOOL && " + recv_tmp + ".v.b)"
    end
    if klass == "FalseClass"
      return "(" + recv_tmp + ".tag == SP_TAG_BOOL && !" + recv_tmp + ".v.b)"
    end
    if klass == "Numeric"
      return "(" + recv_tmp + ".tag == SP_TAG_INT || " + recv_tmp + ".tag == SP_TAG_FLT)"
    end
    if klass == "Comparable"
      if is_instance_of == 1
        return "0"
      end
      return "(" + recv_tmp + ".tag == SP_TAG_INT || " + recv_tmp + ".tag == SP_TAG_FLT || " + recv_tmp + ".tag == SP_TAG_STR || " + recv_tmp + ".tag == SP_TAG_SYM)"
    end
    if klass == "Object" || klass == "Kernel" || klass == "BasicObject"
 # Every value is_a? Object in Ruby. instance_of?(Object) is FALSE
 # for primitives (their class is Integer/String/etc., not Object).
      if is_instance_of == 1
        return "0"
      end
      return "1"
    end
    if klass == "Array"
      return "(" + recv_tmp + ".tag == SP_TAG_OBJ && (" + recv_tmp + ".cls_id == SP_BUILTIN_INT_ARRAY || " + recv_tmp + ".cls_id == SP_BUILTIN_STR_ARRAY || " + recv_tmp + ".cls_id == SP_BUILTIN_FLT_ARRAY || " + recv_tmp + ".cls_id == SP_BUILTIN_SYM_ARRAY || " + recv_tmp + ".cls_id == SP_BUILTIN_PTR_ARRAY || " + recv_tmp + ".cls_id == SP_BUILTIN_POLY_ARRAY))"
    end
    if klass == "Hash"
      return "(" + recv_tmp + ".tag == SP_TAG_OBJ && (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_INT_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_STR_STR_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_INT_STR_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_SYM_INT_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_SYM_STR_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_STR_POLY_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_SYM_POLY_HASH))"
    end
    if klass == "Range"
      return "(" + recv_tmp + ".tag == SP_TAG_OBJ && " + recv_tmp + ".cls_id == SP_BUILTIN_RANGE)"
    end
    if klass == "Proc"
      return "(" + recv_tmp + ".tag == SP_TAG_OBJ && " + recv_tmp + ".cls_id == SP_BUILTIN_PROC)"
    end
    ""
  end

  def compile_poly_method_call(nid, rc, mname)
    @needs_rb_value = 1
    if mname == "nil?"
      return "sp_poly_nil_p(" + rc + ")"
    end
    if mname == "to_s"
      return "sp_poly_to_s(" + rc + ")"
    end
 # `<poly>.inspect` -- canonical Ruby-style representation
 # (nil -> "nil", strings quoted, etc.). #532's
 # `puts pos.inspect` flows through this when pos came from
 # the nullable `String#index`.
    if mname == "inspect"
      return "sp_poly_inspect(" + rc + ")"
    end
    if mname == "to_i"
 # Unbox the poly value's int payload. For SP_TAG_INT it's the
 # raw `v.i`. For SP_TAG_OBJ branches the runtime values are
 # always pointers — `.to_i` on a class that doesn't define
 # `to_i` is the obj-id in Ruby; we approximate as 0 since
 # spinel doesn't expose a stable obj-id and the only practical
 # use is unboxing a poly-with-int payload (e.g. the result of
 # `arr[i][j]` over a heterogeneous IntArray + Method array,
 # whose dispatch arms all box back to SP_TAG_INT).
      tmp = new_temp
      recv_tmp = new_temp
      emit("  sp_RbVal " + recv_tmp + " = " + rc + ";")
      emit("  mrb_int " + tmp + " = (" + recv_tmp + ".tag == SP_TAG_INT) ? " + recv_tmp + ".v.i : 0;")
      return tmp
    end
 # `<poly>.is_a?(<Class>)` / `kind_of?` / `instance_of?` — decide
 # at runtime by inspecting the SP_TAG_* tag (and cls_id for
 # SP_TAG_OBJ). Without this branch the call falls through to the
 # SP_TAG_OBJ dispatch below, which has no `is_a?` method on any
 # user class — every primitive arm returns the default and
 # `is_a?(Integer)` on a poly slot is always falsy. Common in
 # dispatch helpers like `(addr.is_a?(Integer) ? [addr] : addr).each`.
    if mname == "is_a?" || mname == "kind_of?" || mname == "instance_of?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
 # dynamic Class arg on a poly
 # recv. Recover the recv's cls_id with sp_class_for_poly,
 # then sp_class_le against the runtime-supplied Class.
 # instance_of? still needs equality on the resolved
 # cls_id; sp_class_eq handles that.
          arg_t = infer_type(a[0])
          if arg_t == "class" && @nd_type[a[0]] != "ConstantReadNode"
            recv_tmp = new_temp
            emit("  sp_RbVal " + recv_tmp + " = " + rc + ";")
            @needs_class_table = 1
            @needs_class_ancestors = 1
            if mname == "instance_of?"
              return "sp_class_eq(sp_class_for_poly(" + recv_tmp + "), " + compile_expr(a[0]) + ")"
            end
            return "sp_class_le(sp_class_for_poly(" + recv_tmp + "), " + compile_expr(a[0]) + ")"
          end
          arg_name = @nd_name[a[0]]
          recv_tmp = new_temp
          emit("  sp_RbVal " + recv_tmp + " = " + rc + ";")
          io = mname == "instance_of?" ? 1 : 0
          tag_check = poly_is_a_tag_check(arg_name, recv_tmp, io)
          if tag_check != ""
            return tag_check
          end
 # User-defined class: match by cls_id. instance_of? requires
 # exact class; is_a?/kind_of? include subclasses, so
 # enumerate user classes whose ancestor chain reaches
 # arg_name (cls_is_descendant) and OR them in.
          ci = find_class_idx(arg_name)
          if ci >= 0
 # Tier 4: cls_id stamped on boxed instances is unified
 # (BC + internal_ci) -- compare against that.
            ci_uid = cls_id_for_user_internal(ci)
            if mname == "instance_of?"
              return "(" + recv_tmp + ".tag == SP_TAG_OBJ && " + recv_tmp + ".cls_id == " + ci_uid.to_s + ")"
            end
            check = "(" + recv_tmp + ".tag == SP_TAG_OBJ && (" + recv_tmp + ".cls_id == " + ci_uid.to_s
            cn = 0
            while cn < @cls_names.length
              if cn != ci && cls_is_descendant(cn, ci) == 1
                check = check + " || " + recv_tmp + ".cls_id == " + cls_id_for_user_internal(cn).to_s
              end
              cn = cn + 1
            end
            check = check + "))"
            return check
          end
          return "0"
        end
      end
      return "0"
    end
 # For object method calls, dispatch based on cls_id. Two namespaces
 # of cls_id share SP_TAG_OBJ:
 # - non-negative: index into @cls_names (user-defined classes)
 # - negative SP_BUILTIN_*: built-in pointer types (IntArray, ...)
 # The result temp is typed by the method's return type. If user
 # classes disagree on that type, the result is sp_RbVal and each
 # branch boxes its concrete return value.
 # Pre-compute arg base types (just `infer_type`, no emit) so the
 # return-type analysis can apply the same param-incompat
 # suppression the emit loop uses below. Without this the
 # result temp widens to sp_RbVal whenever an unreachable arm
 # has a different return type. Issue #549.
    args_id_pre = @nd_arguments[nid]
    arg_types_pre = "".split(",")
    if args_id_pre >= 0
      aargs_pre = get_args(args_id_pre)
      kp = 0
      while kp < aargs_pre.length
        arg_types_pre.push(infer_type(aargs_pre[kp]))
        kp = kp + 1
      end
    end
    ret_type = poly_dispatch_return_type(mname, nid, arg_types_pre)
 # Approach 2 narrowing: `<poly>[k]` defaults to poly because the
 # static `[]` dispatch can't pin the return; check whether the
 # poly receiver here came from `<poly_array>[i]` whose every
 # observed element kind has an int-returning `[]` (IntArray,
 # Method-with-int-return). If so, narrow to int so the slot
 # @_pc / @_addr / etc. on the caller side stays mrb_int instead
 # of widening to sp_RbVal and breaking downstream `iv += 1`,
 # `~poly`, and friends.
    narrowed_int_idx = 0
    if ret_type == "poly" && mname == "[]"
      narrowed_int_idx = poly_index_narrow_int(nid)
      if narrowed_int_idx == 1
        ret_type = "int"
      end
    end
    is_poly_ret = ret_type == "poly" ? 1 : 0
    ret_ct = c_type(ret_type)
    ret_def = c_default_val(ret_type)
 # Stash the receiver in a temp so we don't re-evaluate the
 # expression for every if-branch below.
    recv_tmp = new_temp
    emit("  sp_RbVal " + recv_tmp + " = " + rc + ";")
 # Compile the call's argument list once. Track the inferred
 # source type alongside the compiled expression so the int-bit
 # branch below can unbox a poly arg without re-walking the AST.
    arg_compiled = "".split(",")
    arg_types = "".split(",")
    aargs_for_unbox = []
    arg_strs = ""
    args_id = @nd_arguments[nid]
    if args_id >= 0
      aargs = get_args(args_id)
      k = 0
      while k < aargs.length
        ce = compile_expr(aargs[k])
        arg_compiled.push(ce)
        arg_types.push(infer_type(aargs[k]))
        aargs_for_unbox.push(aargs[k])
        arg_strs = arg_strs + ", " + ce
        k = k + 1
      end
    end
    tmp = new_temp
    emit("  " + ret_ct + " " + tmp + " = " + ret_def + ";")
 # `int[i]` (bit-extraction) on a poly receiver. When a CPU
 # register / scratch ivar is widened to sp_RbVal but still
 # carries an int value, `pc[8]` (the page-bit test in branch
 # instructions etc.) must compile to `(pc >> 8) & 1`, not to
 # the array dispatch in the SP_TAG_OBJ block below — which
 # would silently leave the result at nil and miscount cycles.
 # Only emit the int-bit-extract fallback when the index
 # argument is itself an int (or a poly we can unbox to int).
 # For non-int keys (string, sym, ...) the SP_TAG_INT branch
 # is unreachable at runtime and `(recv.v.i >> key)` is
 # invalid C — `>> const char *` won't compile.
    if mname == "[]" && arg_compiled.length >= 1 && (arg_types[0] == "int" || arg_types[0] == "poly")
      a0_int = arg_compiled[0]
      if arg_types[0] == "poly"
        a0_int = "(" + a0_int + ").v.i"
      end
      bit = "((" + recv_tmp + ".v.i >> (" + a0_int + ")) & 1)"
      brhs = is_poly_ret == 1 ? "sp_box_int(" + bit + ")" : bit
      emit("  if (" + recv_tmp + ".tag == SP_TAG_INT) " + tmp + " = " + brhs + ";")
    end
 # SP_TAG_STR arm for string methods that have a concrete
 # str-recv lowering. `v.gsub(/re/, repl)` where v is poly
 # (e.g. v came from `poly_hash[k]`) needs a per-tag dispatch
 # arm — otherwise the poly recv falls through to the
 # SP_TAG_OBJ block, which has no String-method handler, and
 # the result temp stays at its default (mrb_int 0). The
 # caller's downstream assignment to a const char * slot then
 # fails C compile.
    if mname == "gsub" || mname == "sub"
      args_id_gs = @nd_arguments[nid]
      if args_id_gs >= 0
        a_gs = get_args(args_id_gs)
        if a_gs.length >= 2
          rpat_gs = regex_pat_c_expr(a_gs[0])
          fn_gs = mname == "gsub" ? "sp_re_gsub" : "sp_re_sub"
          str_fn_gs = mname == "gsub" ? "sp_str_gsub" : "sp_str_sub"
          rep_gs = compile_expr(a_gs[1])
          if rpat_gs != ""
 # gsub(regex, hash) on the SP_TAG_STR poly arm. Issue #503:
 # the typed-receiver path (compile_string_method_expr) routes
 # str_str_hash replacements through `sp_re_gsub_str_str_hash`;
 # the poly arm previously fell through to `sp_re_gsub` and
 # smuggled the hash pointer through where `const char *rep`
 # is expected. Mirror the typed-receiver branch here.
            if mname == "gsub" && infer_type(a_gs[1]) == "str_str_hash"
              call_gs = "sp_re_gsub_str_str_hash(" + rpat_gs + ", " + recv_tmp + ".v.s, " + rep_gs + ")"
            else
              call_gs = fn_gs + "(" + rpat_gs + ", " + recv_tmp + ".v.s, " + rep_gs + ")"
            end
          else
            call_gs = str_fn_gs + "(" + recv_tmp + ".v.s, " + compile_expr(a_gs[0]) + ", " + rep_gs + ")"
          end
          str_rhs_gs = is_poly_ret == 1 ? "sp_box_str(" + call_gs + ")" : call_gs
          emit("  if (" + recv_tmp + ".tag == SP_TAG_STR) " + tmp + " = " + str_rhs_gs + ";")
        end
      end
    end
 # SP_TAG_STR arm for length / size. `v.length` where v is poly
 # (e.g. v came from `poly_array[i]`) carrying a string at
 # runtime needs a tag-dispatch arm — without this the only
 # length emits live inside the SP_TAG_OBJ block below (typed
 # array variants), so a string-tagged poly always read 0.
 # Surfaces in `if v.is_a?(String) && v.length > 0 ; ... end`
 # against a poly_array[i] receiver: the && condition's second
 # half stays 0, the then-arm never fires, and the user-level
 # guarded code path is silently skipped.
    if mname == "length" || mname == "size"
      slen_c = "sp_str_length(" + recv_tmp + ".v.s)"
      slen_rhs = is_poly_ret == 1 ? "sp_box_int(" + slen_c + ")" : slen_c
      emit("  if (" + recv_tmp + ".tag == SP_TAG_STR) " + tmp + " = " + slen_rhs + ";")
    end
 # SP_TAG_STR arm for empty? on a poly recv. Issue #552.
    if mname == "empty?"
      semp_c = "(sp_str_length(" + recv_tmp + ".v.s) == 0)"
      semp_rhs = is_poly_ret == 1 ? "sp_box_bool(" + semp_c + ")" : semp_c
      emit("  if (" + recv_tmp + ".tag == SP_TAG_STR) " + tmp + " = " + semp_rhs + ";")
    end
 # SP_TAG_STR arm for include? on a poly recv -- only fires
 # when the arg is a string (CRuby's String#include? takes
 # a substring; non-string args TypeError at runtime, so
 # we leave the result temp at its default in that case).
 # Issue #558.
    if mname == "include?" && arg_compiled.length >= 1 && (arg_types.length == 0 || arg_types[0] == "string" || arg_types[0] == "mutable_str" || arg_types[0] == "poly")
      sinc_arg = arg_compiled[0]
      if arg_types.length > 0 && arg_types[0] == "poly"
        sinc_arg = "(" + sinc_arg + ").v.s"
      end
      sinc_c = "sp_str_include(" + recv_tmp + ".v.s, " + sinc_arg + ")"
      sinc_rhs = is_poly_ret == 1 ? "sp_box_bool(" + sinc_c + ")" : sinc_c
      emit("  if (" + recv_tmp + ".tag == SP_TAG_STR) " + tmp + " = " + sinc_rhs + ";")
    end
    emit("  if (" + recv_tmp + ".tag == SP_TAG_OBJ) {")
 # User-class dispatch
    i = 0
    while i < @cls_names.length
      cname = @cls_names[i]
      midx = cls_find_method_direct(i, mname)
      owner_idx = i
      if midx < 0
        owner_name = find_method_owner(i, mname)
        if owner_name != ""
          owner_idx = find_class_idx(owner_name)
          if owner_idx >= 0
            midx = cls_find_method_direct(owner_idx, mname)
          end
        end
      end
      if midx >= 0
 # Match each arm to the target method's *fixed* C arity:
 # pad missing trailing slots with default-typed zeros, and
 # truncate extras (when the call site supplies more args than
 # this candidate accepts — happens when several classes share
 # the method name but disagree on parameter count).
        arm_arg_strs = ""
        arm_ptypes = cls_meth_ptypes_get(owner_idx, midx)
        pk = 0
        while pk < arm_ptypes.length
          if pk < arg_compiled.length
 # When this arm's param widened to `poly` (cross-
 # call-site union) but the call site supplied a
 # concrete value (string / mrb_int / symbol / ...),
 # box it via the appropriate sp_box_* helper so the
 # arg type matches the slot — otherwise gcc errors
 # `incompatible type for argument` on `const char *` /
 # `mrb_int` into a `sp_RbVal`. The inverse direction
 # (poly arg into a concrete-typed param) is handled
 # downstream; this only does the boxing direction.
            arg_v = arg_compiled[pk]
            arm_pt_base = base_type(arm_ptypes[pk])
 # Inverse direction: this arm expects a concrete primitive
 # but the call site supplied a value whose actual C type
 # is sp_RbVal (analyze's cached `at` lagged the emit -- see
 # expr_emits_poly_rb_val). Unbox via the matching union
 # field. Mirrors compile_expr_for_expected_type's poly→prim.
            if pk < aargs_for_unbox.length && expr_emits_poly_rb_val(aargs_for_unbox[pk]) == 1
              if arm_pt_base == "int" || arm_pt_base == "symbol"
                @needs_rb_value = 1
                arg_v = "(" + arg_v + ").v.i"
                if arm_pt_base == "symbol"
                  arg_v = "(sp_sym)" + arg_v
                end
              elsif arm_pt_base == "string" || arm_pt_base == "mutable_str"
                @needs_rb_value = 1
                arg_v = "(" + arg_v + ").v.s"
              elsif arm_pt_base == "float"
                @needs_rb_value = 1
                arg_v = "(" + arg_v + ").v.f"
              elsif arm_pt_base == "bool"
                @needs_rb_value = 1
                arg_v = "(" + arg_v + ").v.b"
              end
            end
            if arm_pt_base == "poly" && pk < arg_types.length && arg_types[pk] != "poly" && arg_types[pk] != ""
              arg_v = box_value_to_poly(arg_types[pk], arg_v)
            end
            arm_arg_strs = arm_arg_strs + ", " + arg_v
          else
            pad = "0"
            pt_base = base_type(arm_ptypes[pk])
            if pt_base == "poly"
              pad = "sp_box_nil()"
            end
            arm_arg_strs = arm_arg_strs + ", " + pad
          end
          pk = pk + 1
        end
        call_expr = "sp_" + @cls_names[owner_idx] + "_" + sanitize_name(mname) + "((sp_" + @cls_names[owner_idx] + " *)" + recv_tmp + ".v.p" + arm_arg_strs + ")"
        rhs = call_expr
        if is_poly_ret == 1
          this_rt = cls_method_return(owner_idx, mname)
          rhs = box_val_to_poly(call_expr, this_rt)
        end
 # Suppress user-class arms whose param-slot types are
 # incompatible with the dispatch-site arg types — when the
 # box/unbox logic above can't bridge them. E.g. `sub.fetch(
 # "title", "")` dispatched at a site where `sub` may be a
 # FlashLike whose `fetch(key, default)` has `key: mrb_int`
 # (committed by sym-only direct callers) — the String "title"
 # can't be cast to `mrb_int` without a runtime sym lookup, and
 # the receiver in any source-level-valid path is a Hash, never
 # FlashLike, so the arm is unreachable at runtime. Parallels
 # the `narrowed_int_idx` skip below.
        arm_incompat = 0
        pk_chk = 0
        while pk_chk < arm_ptypes.length && pk_chk < arg_compiled.length && pk_chk < arg_types.length
          at_b = base_type(arg_types[pk_chk])
          pt_b = base_type(arm_ptypes[pk_chk])
          if at_b != "" && pt_b != "" && at_b != "poly" && pt_b != "poly" && at_b != pt_b
 # int/symbol/bool all lower to mrb_int — compatible.
            if (at_b == "int" && pt_b == "symbol") || (at_b == "symbol" && pt_b == "int") ||
               (at_b == "int" && pt_b == "bool")   || (at_b == "bool"   && pt_b == "int")
 # compatible
            else
              arm_incompat = 1
            end
          end
          pk_chk = pk_chk + 1
        end
 # Narrowed `[]` arms (Approach 2): suppress user-class arms
 # whose `[]` doesn't return int — the dead-code emit would
 # otherwise assign e.g. a string to the now-mrb_int result
 # temp and fail the C compile. The runtime can't reach these
 # arms anyway because the observation set narrowed past them.
        if arm_incompat == 1
 # skip — runtime can't reach this arm in a source-level-valid
 # path because the dispatch-site arg types preclude the user
 # class as the actual receiver.
        elsif narrowed_int_idx == 1 && cls_method_return(owner_idx, mname) != "int"
 # skip
        else
          emit("    if (" + recv_tmp + ".cls_id == " + cls_id_for_user_internal(i).to_s + ") " + tmp + " = " + rhs + ";")
        end
      elsif cls_has_attr_reader(i, mname) == 1
 # An auto-registered attr_reader doesn't appear in
 # @cls_meth_names, so the explicit-method walk above misses it.
 # Read the ivar directly. .
        ivar_expr = "((sp_" + cname + " *)" + recv_tmp + ".v.p)->" + sanitize_ivar("@" + mname)
        rhs = ivar_expr
        if is_poly_ret == 1
          this_rt = cls_ivar_type(i, "@" + mname)
          rhs = box_val_to_poly(ivar_expr, this_rt)
        end
        if narrowed_int_idx == 1 && cls_ivar_type(i, "@" + mname) != "int"
 # skip non-int attr_reader arms on a narrowed `[]`
        else
          emit("    if (" + recv_tmp + ".cls_id == " + cls_id_for_user_internal(i).to_s + ") " + tmp + " = " + rhs + ";")
        end
      elsif mname.length > 1 && mname[mname.length - 1] == "=" && cls_has_attr_writer(i, mname[0, mname.length - 1]) == 1
 # An auto-registered attr_writer setter (`obj.x = v`) on a
 # poly-typed receiver. Without this arm the cls_id dispatch
 # finds neither a real method nor an attr_reader, falls
 # through silently, and the assignment never executes —
 # `obj.x = v` becomes a no-op.
        bname = mname[0, mname.length - 1]
        raw_val = arg_compiled.length > 0 ? arg_compiled[0] : "0"
        raw_t   = arg_types.length > 0 ? arg_types[0] : ""
        slot_t  = cls_ivar_type(i, "@" + bname)
 # Match the rhs to the slot's concrete C type for *this arm*.
 # Three cases:
 # slot poly + arg concrete -> box the arg.
 # slot concrete + arg poly -> unbox the arg.
 # else -> direct assign.
 # Different arms in the dispatch may take different branches
 # (e.g. one slot is `int`, another is `string`).
        store_val = raw_val
        if slot_t == "poly" && raw_t != "poly" && raw_t != ""
          store_val = box_value_to_poly(raw_t, raw_val)
        elsif slot_t != "poly" && raw_t == "poly"
          store_val = unbox_poly_to(slot_t, raw_val)
        end
        ivar_lhs = "((sp_" + cname + " *)" + recv_tmp + ".v.p)->" + sanitize_ivar("@" + bname)
 # `x = v` returns v in Ruby. The result tmp's type is set by
 # poly_dispatch_return_type (poly when slot types diverge,
 # otherwise the common slot type). Box / coerce the stored
 # value into the tmp's expected shape.
        rhs_for_tmp = store_val
        if is_poly_ret == 1
          rhs_for_tmp = box_val_to_poly(store_val, slot_t)
        end
        emit("    if (" + recv_tmp + ".cls_id == " + cls_id_for_user_internal(i).to_s + ") { " + ivar_lhs + " = " + store_val + "; " + tmp + " = " + rhs_for_tmp + "; }")
      end
      i = i + 1
    end
 # Built-in type dispatch (cls_id < 0).
    emit_poly_builtin_dispatch(recv_tmp, mname, arg_compiled, arg_types, tmp, is_poly_ret, narrowed_int_idx)
    emit("  }")
    tmp
  end

 # Emit branches for the built-in (negative cls_id) entries. Each
 # entry maps a (SP_BUILTIN_*, method) pair to a C expression.
 # Adding a new built-in type means one more `if` branch here.
  def emit_poly_builtin_dispatch(recv_tmp, mname, arg_compiled, arg_types, result_tmp, is_poly_ret, narrowed_int = 0)
    a0 = ""
    if arg_compiled.length > 0
      a0 = arg_compiled[0]
 # Unbox if poly — every built-in `[]` arm here passes a0 to a
 # function expecting `mrb_int` (sp_IntArray_get etc., or the
 # Method fn_ptr's int parameter). When the caller's arg is
 # poly (e.g. `def fetch(addr); @fetch[addr][addr]; end` with
 # addr widened), we must unbox before the C call.
      if arg_types.length > 0 && arg_types[0] == "poly"
        a0 = "(" + a0 + ").v.i"
      end
    end
 # `[]` — element types differ per built-in. When the result temp
 # is sp_RbVal (poly return), every branch can box into it. When
 # the temp is concretely typed, only built-ins whose element type
 # fits the temp can contribute — otherwise the assignment is a
 # C type mismatch. The unmatched runtime types simply leave the
 # temp at its default (`0`/empty) for that input, which is
 # acceptable since the caller's static type analysis already
 # picked a compatible result type.
 #
 # Every built-in [] arm here passes the key to a function
 # expecting `mrb_int`. Only emit the arms when the key type
 # is int or poly (poly is unboxed via `.v.i` above). For
 # non-int keys (string, sym), these arms are unreachable at
 # runtime (a poly recv carrying a String key would be a hash,
 # not an array) and emitting them produces Wint-conversion
 # warnings — or hard errors under -Werror.
    a0_is_int = arg_compiled.length >= 1 && (arg_types.length == 0 || arg_types[0] == "int" || arg_types[0] == "poly")
 # Hash dispatch arms for `[]` on a poly recv whose runtime
 # storage is a *-Hash variant. The chained `outer[k1][k2]`
 # shape where outer is StrPolyHash lands here — the inner []
 # recv carries an arbitrary str-keyed hash storage. Emit
 # arms keyed by the string-typed index. Sym-keyed variants
 # are skipped here because the sp_SymIntHash / sp_SymStrHash
 # typedefs are emit-gated by @needs flags set during pre-scan,
 # which doesn't see this dispatch path yet; the existing
 # sp_StrIntHash family ships unconditionally in sp_runtime.h.
    if mname == "[]" && arg_compiled.length >= 1
      key_t = arg_types.length > 0 ? arg_types[0] : ""
      if key_t == "string" || key_t == "mutable_str"
        if is_poly_ret == 1
          emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_INT_HASH) " + result_tmp + " = sp_box_int(sp_StrIntHash_get((sp_StrIntHash *)" + recv_tmp + ".v.p, " + arg_compiled[0] + "));")
          emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_STR_HASH) " + result_tmp + " = sp_box_str(sp_StrStrHash_get((sp_StrStrHash *)" + recv_tmp + ".v.p, " + arg_compiled[0] + "));")
          emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_POLY_HASH) " + result_tmp + " = sp_StrPolyHash_get((sp_StrPolyHash *)" + recv_tmp + ".v.p, " + arg_compiled[0] + ");")
        end
      end
    end
 # `fetch` arms — parallel to `[]` above for the (key, default)
 # form. Each Str*-Hash variant tests has_key first, returns the
 # boxed value on hit, or the boxed default on miss. Sibling to
 # #456 (which added Hash arms to poly-recv `[]` / `[]=`); without
 # this, `sub.fetch("k", "d")` on a poly recv that resolves to a
 # Hash variant at runtime matches no arm and silently returns
 # the temp's nil default — even though the Hash holds the key.
 # Sym-keyed variants are deferred for the same `@needs`-gating
 # reason as `[]`.
    if mname == "fetch" && arg_compiled.length >= 1
      key_t = arg_types.length > 0 ? arg_types[0] : ""
      if (key_t == "string" || key_t == "mutable_str") && is_poly_ret == 1
        key_c = arg_compiled[0]
        def_box = "sp_box_nil()"
        if arg_compiled.length >= 2
          def_t = arg_types.length >= 2 ? arg_types[1] : ""
          def_c = arg_compiled[1]
          if def_t == "poly" || def_t == ""
            def_box = def_c
          else
            def_box = box_value_to_poly(def_t, def_c)
          end
        end
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_INT_HASH) " + result_tmp + " = sp_StrIntHash_has_key((sp_StrIntHash *)" + recv_tmp + ".v.p, " + key_c + ") ? sp_box_int(sp_StrIntHash_get((sp_StrIntHash *)" + recv_tmp + ".v.p, " + key_c + ")) : " + def_box + ";")
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_STR_HASH) " + result_tmp + " = sp_StrStrHash_has_key((sp_StrStrHash *)" + recv_tmp + ".v.p, " + key_c + ") ? sp_box_str(sp_StrStrHash_get((sp_StrStrHash *)" + recv_tmp + ".v.p, " + key_c + ")) : " + def_box + ";")
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_POLY_HASH) " + result_tmp + " = sp_StrPolyHash_has_key((sp_StrPolyHash *)" + recv_tmp + ".v.p, " + key_c + ") ? sp_StrPolyHash_get((sp_StrPolyHash *)" + recv_tmp + ".v.p, " + key_c + ") : " + def_box + ";")
      end
    end
 # `dup` arms — Hash#dup on a poly recv whose runtime storage is
 # any hash variant. matched[:path_params].dup is the canonical
 # form in real-blog's request-params chain. Pre-fix the call
 # fell through to int default ("cannot resolve call to 'dup' on
 # int" warning), leaving downstream chained writes silently
 # against the int 0. Each arm dups via the matching runtime
 # helper and boxes back as obj. Only the always-in hash variants
 # (sp_runtime.h) are emitted; SymInt / SymStr variants are
 # typedef-gated by @needs flags which aren't reliably set at
 # this emit point.
    if mname == "dup"
      if is_poly_ret == 1
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_INT_HASH) " + result_tmp + " = sp_box_obj((void *)sp_StrIntHash_dup((sp_StrIntHash *)" + recv_tmp + ".v.p), SP_BUILTIN_STR_INT_HASH);")
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_STR_HASH) " + result_tmp + " = sp_box_obj((void *)sp_StrStrHash_dup((sp_StrStrHash *)" + recv_tmp + ".v.p), SP_BUILTIN_STR_STR_HASH);")
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_INT_STR_HASH) " + result_tmp + " = sp_box_obj((void *)sp_IntStrHash_dup((sp_IntStrHash *)" + recv_tmp + ".v.p), SP_BUILTIN_INT_STR_HASH);")
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_POLY_HASH) " + result_tmp + " = sp_box_obj((void *)sp_StrPolyHash_dup((sp_StrPolyHash *)" + recv_tmp + ".v.p), SP_BUILTIN_STR_POLY_HASH);")
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_POLY_HASH) " + result_tmp + " = sp_box_obj((void *)sp_SymPolyHash_dup((sp_SymPolyHash *)" + recv_tmp + ".v.p), SP_BUILTIN_SYM_POLY_HASH);")
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_POLY_POLY_HASH) " + result_tmp + " = sp_box_obj((void *)sp_PolyPolyHash_dup((sp_PolyPolyHash *)" + recv_tmp + ".v.p), SP_BUILTIN_POLY_POLY_HASH);")
      end
    end
 # length / size arms — for a poly recv whose runtime storage
 # is an Array or Hash variant. The SP_TAG_STR length arm fires
 # earlier in compile_poly_method_call; this covers the
 # SP_TAG_OBJ side. Without these arms, a `param.length` call
 # on a body-usage-widened poly param (issue #552) silently
 # reads the result_tmp default (0) for every non-string
 # runtime value. Result type is always int / sp_box_int.
    if mname == "length" || mname == "size"
      ic = "sp_IntArray_length((sp_IntArray *)" + recv_tmp + ".v.p)"
      irhs = is_poly_ret == 1 ? "sp_box_int(" + ic + ")" : ic
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_INT_ARRAY) " + result_tmp + " = " + irhs + ";")
      fc = "sp_FloatArray_length((sp_FloatArray *)" + recv_tmp + ".v.p)"
      frhs = is_poly_ret == 1 ? "sp_box_int(" + fc + ")" : fc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_FLT_ARRAY) " + result_tmp + " = " + frhs + ";")
      sc = "sp_StrArray_length((sp_StrArray *)" + recv_tmp + ".v.p)"
      srhs = is_poly_ret == 1 ? "sp_box_int(" + sc + ")" : sc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_ARRAY) " + result_tmp + " = " + srhs + ";")
      yc = "sp_IntArray_length((sp_IntArray *)" + recv_tmp + ".v.p)"
      yrhs = is_poly_ret == 1 ? "sp_box_int(" + yc + ")" : yc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_ARRAY) " + result_tmp + " = " + yrhs + ";")
      pc = "sp_PtrArray_length((sp_PtrArray *)" + recv_tmp + ".v.p)"
      prhs = is_poly_ret == 1 ? "sp_box_int(" + pc + ")" : pc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_PTR_ARRAY) " + result_tmp + " = " + prhs + ";")
      polyc = "sp_PolyArray_length((sp_PolyArray *)" + recv_tmp + ".v.p)"
      polyrhs = is_poly_ret == 1 ? "sp_box_int(" + polyc + ")" : polyc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_POLY_ARRAY) " + result_tmp + " = " + polyrhs + ";")
      sihc = "sp_StrIntHash_length((sp_StrIntHash *)" + recv_tmp + ".v.p)"
      sihrhs = is_poly_ret == 1 ? "sp_box_int(" + sihc + ")" : sihc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_INT_HASH) " + result_tmp + " = " + sihrhs + ";")
      sshc = "sp_StrStrHash_length((sp_StrStrHash *)" + recv_tmp + ".v.p)"
      sshrhs = is_poly_ret == 1 ? "sp_box_int(" + sshc + ")" : sshc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_STR_HASH) " + result_tmp + " = " + sshrhs + ";")
      isthc = "sp_IntStrHash_length((sp_IntStrHash *)" + recv_tmp + ".v.p)"
      isthrhs = is_poly_ret == 1 ? "sp_box_int(" + isthc + ")" : isthc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_INT_STR_HASH) " + result_tmp + " = " + isthrhs + ";")
      sphc = "sp_StrPolyHash_length((sp_StrPolyHash *)" + recv_tmp + ".v.p)"
      sphrhs = is_poly_ret == 1 ? "sp_box_int(" + sphc + ")" : sphc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_POLY_HASH) " + result_tmp + " = " + sphrhs + ";")
      ypc = "sp_SymPolyHash_length((sp_SymPolyHash *)" + recv_tmp + ".v.p)"
      yprhs = is_poly_ret == 1 ? "sp_box_int(" + ypc + ")" : ypc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_POLY_HASH) " + result_tmp + " = " + yprhs + ";")
      pphc = "sp_PolyPolyHash_length((sp_PolyPolyHash *)" + recv_tmp + ".v.p)"
      pphrhs = is_poly_ret == 1 ? "sp_box_int(" + pphc + ")" : pphc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_POLY_POLY_HASH) " + result_tmp + " = " + pphrhs + ";")
    end
 # empty? arms -- sibling of length/size for the poly recv
 # variants. Issue #552. Always returns a bool (sp_box_bool
 # under is_poly_ret); otherwise the result temp's declared
 # type is bool.
    if mname == "empty?"
      iec = "(sp_IntArray_length((sp_IntArray *)" + recv_tmp + ".v.p) == 0)"
      ierhs = is_poly_ret == 1 ? "sp_box_bool(" + iec + ")" : iec
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_INT_ARRAY) " + result_tmp + " = " + ierhs + ";")
      fec = "(sp_FloatArray_length((sp_FloatArray *)" + recv_tmp + ".v.p) == 0)"
      ferhs = is_poly_ret == 1 ? "sp_box_bool(" + fec + ")" : fec
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_FLT_ARRAY) " + result_tmp + " = " + ferhs + ";")
      sec = "(sp_StrArray_length((sp_StrArray *)" + recv_tmp + ".v.p) == 0)"
      serhs = is_poly_ret == 1 ? "sp_box_bool(" + sec + ")" : sec
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_ARRAY) " + result_tmp + " = " + serhs + ";")
      yec = "(sp_IntArray_length((sp_IntArray *)" + recv_tmp + ".v.p) == 0)"
      yerhs = is_poly_ret == 1 ? "sp_box_bool(" + yec + ")" : yec
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_ARRAY) " + result_tmp + " = " + yerhs + ";")
      pec = "(sp_PtrArray_length((sp_PtrArray *)" + recv_tmp + ".v.p) == 0)"
      perhs = is_poly_ret == 1 ? "sp_box_bool(" + pec + ")" : pec
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_PTR_ARRAY) " + result_tmp + " = " + perhs + ";")
      polyec = "(sp_PolyArray_length((sp_PolyArray *)" + recv_tmp + ".v.p) == 0)"
      polyerhs = is_poly_ret == 1 ? "sp_box_bool(" + polyec + ")" : polyec
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_POLY_ARRAY) " + result_tmp + " = " + polyerhs + ";")
      sihec = "(sp_StrIntHash_length((sp_StrIntHash *)" + recv_tmp + ".v.p) == 0)"
      siherhs = is_poly_ret == 1 ? "sp_box_bool(" + sihec + ")" : sihec
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_INT_HASH) " + result_tmp + " = " + siherhs + ";")
      sshec = "(sp_StrStrHash_length((sp_StrStrHash *)" + recv_tmp + ".v.p) == 0)"
      ssherhs = is_poly_ret == 1 ? "sp_box_bool(" + sshec + ")" : sshec
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_STR_HASH) " + result_tmp + " = " + ssherhs + ";")
      isthec = "(sp_IntStrHash_length((sp_IntStrHash *)" + recv_tmp + ".v.p) == 0)"
      istherhs = is_poly_ret == 1 ? "sp_box_bool(" + isthec + ")" : isthec
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_INT_STR_HASH) " + result_tmp + " = " + istherhs + ";")
      sphec = "(sp_StrPolyHash_length((sp_StrPolyHash *)" + recv_tmp + ".v.p) == 0)"
      spherhs = is_poly_ret == 1 ? "sp_box_bool(" + sphec + ")" : sphec
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_POLY_HASH) " + result_tmp + " = " + spherhs + ";")
      ypec = "(sp_SymPolyHash_length((sp_SymPolyHash *)" + recv_tmp + ".v.p) == 0)"
      yperhs = is_poly_ret == 1 ? "sp_box_bool(" + ypec + ")" : ypec
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_POLY_HASH) " + result_tmp + " = " + yperhs + ";")
      pphec = "(sp_PolyPolyHash_length((sp_PolyPolyHash *)" + recv_tmp + ".v.p) == 0)"
      ppherhs = is_poly_ret == 1 ? "sp_box_bool(" + pphec + ")" : pphec
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_POLY_POLY_HASH) " + result_tmp + " = " + ppherhs + ";")
    end
 # include? arms -- arg-type-keyed dispatch over the Array
 # and Hash variants matching the arg's key family. Issue #558.
 # Arrays use the per-element-type `_include` helpers; Hashes
 # alias include? -> has_key? per CRuby semantics.
    if mname == "include?" && arg_compiled.length >= 1
      inc_arg_t = arg_types.length > 0 ? arg_types[0] : ""
      inc_arg = arg_compiled[0]
 # symbol arg: SymArray (sp_IntArray storage) + Sym-keyed Hash variants.
      if inc_arg_t == "symbol"
        ic = "sp_IntArray_include((sp_IntArray *)" + recv_tmp + ".v.p, (mrb_int)(" + inc_arg + "))"
        irhs = is_poly_ret == 1 ? "sp_box_bool(" + ic + ")" : ic
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_ARRAY) " + result_tmp + " = " + irhs + ";")
        sihc = "sp_SymIntHash_has_key((sp_SymIntHash *)" + recv_tmp + ".v.p, " + inc_arg + ")"
        sihrhs = is_poly_ret == 1 ? "sp_box_bool(" + sihc + ")" : sihc
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_INT_HASH) " + result_tmp + " = " + sihrhs + ";")
        sshc = "sp_SymStrHash_has_key((sp_SymStrHash *)" + recv_tmp + ".v.p, " + inc_arg + ")"
        sshrhs = is_poly_ret == 1 ? "sp_box_bool(" + sshc + ")" : sshc
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_STR_HASH) " + result_tmp + " = " + sshrhs + ";")
        sphc = "sp_SymPolyHash_has_key((sp_SymPolyHash *)" + recv_tmp + ".v.p, " + inc_arg + ")"
        sphrhs = is_poly_ret == 1 ? "sp_box_bool(" + sphc + ")" : sphc
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_POLY_HASH) " + result_tmp + " = " + sphrhs + ";")
      end
 # string arg: StrArray + Str-keyed Hash variants.
      if inc_arg_t == "string" || inc_arg_t == "mutable_str"
        sc = "sp_StrArray_include((sp_StrArray *)" + recv_tmp + ".v.p, " + inc_arg + ")"
        srhs = is_poly_ret == 1 ? "sp_box_bool(" + sc + ")" : sc
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_ARRAY) " + result_tmp + " = " + srhs + ";")
        stihc = "sp_StrIntHash_has_key((sp_StrIntHash *)" + recv_tmp + ".v.p, " + inc_arg + ")"
        stihrhs = is_poly_ret == 1 ? "sp_box_bool(" + stihc + ")" : stihc
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_INT_HASH) " + result_tmp + " = " + stihrhs + ";")
        ststhc = "sp_StrStrHash_has_key((sp_StrStrHash *)" + recv_tmp + ".v.p, " + inc_arg + ")"
        ststhrhs = is_poly_ret == 1 ? "sp_box_bool(" + ststhc + ")" : ststhc
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_STR_HASH) " + result_tmp + " = " + ststhrhs + ";")
        stphc = "sp_StrPolyHash_has_key((sp_StrPolyHash *)" + recv_tmp + ".v.p, " + inc_arg + ")"
        stphrhs = is_poly_ret == 1 ? "sp_box_bool(" + stphc + ")" : stphc
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_POLY_HASH) " + result_tmp + " = " + stphrhs + ";")
      end
 # int arg: IntArray + Int-keyed Hash.
      if inc_arg_t == "int"
        iac = "sp_IntArray_include((sp_IntArray *)" + recv_tmp + ".v.p, " + inc_arg + ")"
        iarhs = is_poly_ret == 1 ? "sp_box_bool(" + iac + ")" : iac
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_INT_ARRAY) " + result_tmp + " = " + iarhs + ";")
        ishc = "sp_IntStrHash_has_key((sp_IntStrHash *)" + recv_tmp + ".v.p, " + inc_arg + ")"
        ishrhs = is_poly_ret == 1 ? "sp_box_bool(" + ishc + ")" : ishc
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_INT_STR_HASH) " + result_tmp + " = " + ishrhs + ";")
      end
 # float arg: FloatArray.
      if inc_arg_t == "float"
        fac = "sp_FloatArray_include((sp_FloatArray *)" + recv_tmp + ".v.p, " + inc_arg + ")"
        farhs = is_poly_ret == 1 ? "sp_box_bool(" + fac + ")" : fac
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_FLT_ARRAY) " + result_tmp + " = " + farhs + ";")
      end
 # poly arg: PolyArray + PolyPolyHash.
      if inc_arg_t == "poly" || inc_arg_t == ""
        boxed_inc_arg = inc_arg_t == "poly" ? inc_arg : "sp_box_int(" + inc_arg + ")"
        pac = "sp_PolyArray_include((sp_PolyArray *)" + recv_tmp + ".v.p, " + boxed_inc_arg + ")"
        parhs = is_poly_ret == 1 ? "sp_box_bool(" + pac + ")" : pac
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_POLY_ARRAY) " + result_tmp + " = " + parhs + ";")
        pphc = "sp_PolyPolyHash_has_key((sp_PolyPolyHash *)" + recv_tmp + ".v.p, " + boxed_inc_arg + ")"
        pphrhs = is_poly_ret == 1 ? "sp_box_bool(" + pphc + ")" : pphc
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_POLY_POLY_HASH) " + result_tmp + " = " + pphrhs + ";")
      end
    end
 # `<poly>.call(...)` arm for the SP_BUILTIN_PROC tag. When a
 # poly_array of procs is iterated (`[proc, ...].each { |p| p.call }`),
 # the per-element block param is typed `poly`, so `p.call` lands
 # here. Pack the call args into the same mrb_int[] convention used
 # by sp_proc_call elsewhere; pad with 0 when there are no args
 # (sp_proc_new's `_unused` slot expects args[0] to be addressable).
    if mname == "call"
      ca = ""
      ck = 0
      while ck < arg_compiled.length
        if ck > 0
          ca = ca + ", "
        end
        ca = ca + arg_compiled[ck]
        ck = ck + 1
      end
      if ca == ""
        ca = "0"
      end
      proc_c = "sp_proc_call((sp_Proc *)" + recv_tmp + ".v.p, (mrb_int[]){" + ca + "})"
      proc_rhs = is_poly_ret == 1 ? "sp_box_int(" + proc_c + ")" : proc_c
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_PROC) " + result_tmp + " = " + proc_rhs + ";")
    end
    if mname == "[]" && arg_compiled.length >= 1 && a0_is_int
      ic = "sp_IntArray_get((sp_IntArray *)" + recv_tmp + ".v.p, " + a0 + ")"
      irhs = is_poly_ret == 1 ? "sp_box_int(" + ic + ")" : ic
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_INT_ARRAY) " + result_tmp + " = " + irhs + ";")
      if is_poly_ret == 1
        fc = "sp_FloatArray_get((sp_FloatArray *)" + recv_tmp + ".v.p, " + a0 + ")"
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_FLT_ARRAY) " + result_tmp + " = sp_box_float(" + fc + ");")
        sc = "sp_StrArray_get((sp_StrArray *)" + recv_tmp + ".v.p, " + a0 + ")"
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_ARRAY) " + result_tmp + " = sp_box_str(" + sc + ");")
 # sym_array shares IntArray storage; tag back as symbol when
 # the caller wants a poly result.
        yc = "(sp_sym)sp_IntArray_get((sp_IntArray *)" + recv_tmp + ".v.p, " + a0 + ")"
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_ARRAY) " + result_tmp + " = sp_box_sym(" + yc + ");")
      end
 # PtrArray dispatch — sp_PtrArray_get returns void*, which is
 # implicitly convertible to any pointer for the non-poly path
 # (result_tmp may be `sp_Foo *`) and accepted directly by
 # sp_box_obj for the poly path. Casting through mrb_int would
 # fail to compile when result_tmp is a pointer type — and the
 # narrowed-`[]` path (Approach 2) types result_tmp as mrb_int,
 # so PtrArray cls_ids are unobserved by construction. Skip the
 # arm in that case.
      if narrowed_int == 0
        pc = "sp_PtrArray_get((sp_PtrArray *)" + recv_tmp + ".v.p, " + a0 + ")"
 # Tier 4: read the actual cls_id off the user-class struct's
 # cls_id field rather than stamping a 0 sentinel; otherwise
 # downstream cls_id-keyed dispatch on the boxed element
 # mismatches (cls_id 0 now means BasicObject, not "unknown").
 # The sp_PtrArray_get call must stay inside the cls_id ==
 # SP_BUILTIN_PTR_ARRAY guard -- the recv may carry a different
 # built-in (IntArray, etc.) at runtime and casting it to
 # sp_PtrArray then dereferencing segfaults.
        if is_poly_ret == 1
          emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_PTR_ARRAY) { void *_pe = " + pc + "; " + result_tmp + " = sp_box_obj(_pe, sp_obj_cls_id_of(_pe)); }")
        else
          emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_PTR_ARRAY) " + result_tmp + " = " + pc + ";")
        end
      end
 # PolyArray dispatch — sp_PolyArray_get returns sp_RbVal directly.
 # When the result temp is poly, just assign; otherwise unbox via .v.i
 # (the typed temp's static type drives caller-side conversion).
 # Narrowed-`[]` likewise excludes PolyArray from the observed
 # set: the arm is unreachable, and emitting `.v.i` against a
 # cls_id that won't match at runtime is harmless but noisy.
      if narrowed_int == 0
        polyc = "sp_PolyArray_get((sp_PolyArray *)" + recv_tmp + ".v.p, " + a0 + ")"
        polyrhs = is_poly_ret == 1 ? polyc : "(" + polyc + ").v.i"
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_POLY_ARRAY) " + result_tmp + " = " + polyrhs + ";")
      end
 # Method dispatch — `bm[arg]` / `bm[a1, a2]` on a Method instance
 # is `bm.call(...)`. When bm came through a heterogeneous
 # poly_array (e.g. optcarrots `@fetch[i] = method(:peek_X)` mixed
 # with `@fetch[i] = @ram` where @fetch is widened to poly_array),
 # the static type at the call site is poly, so the typed
 # obj_Method path at line 20367 doesnt fire. Generate the
 # function-pointer cast + indirect call inline, guarded by a
 # null fn_ptr check (Rubys NoMethodError analogue). Handles up
 # to N args by reusing the same arg_compiled list and unboxing
 # any that came in as poly.
      method_idx = find_class_idx("Method")
      if method_idx >= 0 && @needs_method == 1
        mp = "((sp_Method *)" + recv_tmp + ".v.p)"
        sig_args = "void *"
        call_args = "(void *)" + mp + "->iv_self_obj"
        mi = 0
        while mi < arg_compiled.length
          sig_args = sig_args + ", mrb_int"
          ai_val = arg_compiled[mi]
          if mi < arg_types.length && arg_types[mi] == "poly"
            ai_val = "(" + ai_val + ").v.i"
          end
          call_args = call_args + ", " + ai_val
          mi = mi + 1
        end
        mc = "(" + mp + " && " + mp + "->iv_fn_ptr ? ((mrb_int (*)(" + sig_args + "))(uintptr_t)" + mp + "->iv_fn_ptr)(" + call_args + ") : 0)"
        mrhs = is_poly_ret == 1 ? "sp_box_int(" + mc + ")" : mc
        emit("    if (" + recv_tmp + ".cls_id == " + cls_id_for_user_internal(method_idx).to_s + ") " + result_tmp + " = " + mrhs + ";")
      end
    end
 # `[]` with a symbol key — sym_poly_hash dispatch. Mirrors the
 # int-key block above for the case where a poly receiver carries
 # a SymPolyHash at runtime (e.g. a constant hash boxed back into
 # a slot whose static type is poly because of an earlier
 # is_a?(String) branch).
    a0_is_sym = arg_compiled.length >= 1 && arg_types.length >= 1 && arg_types[0] == "symbol"
    if mname == "[]" && a0_is_sym
      shc = "sp_SymPolyHash_get((sp_SymPolyHash *)" + recv_tmp + ".v.p, " + arg_compiled[0] + ")"
      shrhs = is_poly_ret == 1 ? shc : "(" + shc + ").v.i"
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_POLY_HASH) " + result_tmp + " = " + shrhs + ";")
 # SymIntHash arm: heterogeneous-element array of `{n: 3}`-style
 # hashes boxes each as SymIntHash. Returns mrb_int,
 # box to poly when the call site expects poly. Only emit when
 # the program already uses SymIntHash so we don't pull the
 # runtime helpers in for unrelated programs.
      if @needs_sym_int_hash == 1
        sihc = "sp_SymIntHash_get((sp_SymIntHash *)" + recv_tmp + ".v.p, " + arg_compiled[0] + ")"
        sihrhs = is_poly_ret == 1 ? "sp_box_int(" + sihc + ")" : sihc
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_INT_HASH) " + result_tmp + " = " + sihrhs + ";")
      end
      if @needs_sym_str_hash == 1
        sshc = "sp_SymStrHash_get((sp_SymStrHash *)" + recv_tmp + ".v.p, " + arg_compiled[0] + ")"
        sshrhs = is_poly_ret == 1 ? "sp_box_str(" + sshc + ")" : sshc
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_STR_HASH) " + result_tmp + " = " + sshrhs + ";")
      end
    end
 # `length` / `size` — every built-in array exposes its own
 # `_length` helper (sym_array shares IntArray's). PtrArray is
 # safe here because length doesn't need an element type.
    if mname == "length" || mname == "size"
      ic = "sp_IntArray_length((sp_IntArray *)" + recv_tmp + ".v.p)"
      irhs = is_poly_ret == 1 ? "sp_box_int(" + ic + ")" : ic
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_INT_ARRAY) " + result_tmp + " = " + irhs + ";")
      fc = "sp_FloatArray_length((sp_FloatArray *)" + recv_tmp + ".v.p)"
      frhs = is_poly_ret == 1 ? "sp_box_int(" + fc + ")" : fc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_FLT_ARRAY) " + result_tmp + " = " + frhs + ";")
      sc = "sp_StrArray_length((sp_StrArray *)" + recv_tmp + ".v.p)"
      srhs = is_poly_ret == 1 ? "sp_box_int(" + sc + ")" : sc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_ARRAY) " + result_tmp + " = " + srhs + ";")
 # sym_array shares the IntArray representation (same `_length`).
      yc = "sp_IntArray_length((sp_IntArray *)" + recv_tmp + ".v.p)"
      yrhs = is_poly_ret == 1 ? "sp_box_int(" + yc + ")" : yc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_ARRAY) " + result_tmp + " = " + yrhs + ";")
      pc = "sp_PtrArray_length((sp_PtrArray *)" + recv_tmp + ".v.p)"
      prhs = is_poly_ret == 1 ? "sp_box_int(" + pc + ")" : pc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_PTR_ARRAY) " + result_tmp + " = " + prhs + ";")
      polyc = "sp_PolyArray_length((sp_PolyArray *)" + recv_tmp + ".v.p)"
      polyrhs = is_poly_ret == 1 ? "sp_box_int(" + polyc + ")" : polyc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_POLY_ARRAY) " + result_tmp + " = " + polyrhs + ";")
    end
  end

 # Try to compile str[i] <op> "c" as direct char comparison
 # Returns "" if not applicable
  def try_char_cmp(nid, c_op)
    recv = @nd_receiver[nid]
    args_id = @nd_arguments[nid]
    if args_id < 0
      return ""
    end
    a = get_args(args_id)
    if a.length == 0
      return ""
    end
    arg_id = a[0]
    if @nd_type[arg_id] != "StringNode"
      return ""
    end
    lit = @nd_content[arg_id]
    if lit == ""
      lit = @nd_unescaped[arg_id]
    end
    if lit.length != 1
      return ""
    end
    if @nd_type[recv] != "CallNode" || @nd_name[recv] != "[]"
      return ""
    end
    sr = @nd_receiver[recv]
    if sr < 0 || infer_type(sr) != "string"
      return ""
    end
    str_c = compile_expr(sr)
    idx_c = compile_arg0(recv)
    ch = lit
    if lit == "\n"
      ch = "\\n"
    elsif lit == "\t"
      ch = "\\t"
    elsif lit == "\r"
      ch = "\\r"
    elsif lit.ord == 92 || lit.ord == 39
 # backslash or single quote — skip char optimization
      return ""
    end
    "(" + str_c + "[(mrb_int)" + idx_c + "] " + c_op + " '" + ch + "')"
  end

 # Helper for compile_eq's `<container_op> == nil` shape.
 # Returns the C truthy expression for the nil-on-miss check
 # (negated when op is "!="), or "" when the shape isn't
 # recognized so compile_eq falls through to its existing
 # type-strict short-circuits. Issue #562.
  def compile_container_op_nil_check(recv_nid, op)
    mname = @nd_name[recv_nid]
    inner_recv = @nd_receiver[recv_nid]
    if inner_recv < 0
      return ""
    end
    inner_t = infer_type(inner_recv)
    inner_c = compile_expr(inner_recv)
    args_id_c = @nd_arguments[recv_nid]
 # arr[i] == nil -> (i < 0 || i >= len).
    if mname == "[]" && is_array_type(inner_t) == 1 && args_id_c >= 0
      a_c = get_args(args_id_c)
      if a_c.length >= 1
        idx_c = compile_expr(a_c[0])
        len_fn = array_length_fn(inner_t)
        if len_fn != ""
          chk = "(" + idx_c + " < 0 || " + idx_c + " >= " + len_fn + "(" + inner_c + "))"
          return op == "==" ? chk : "(!" + chk + ")"
        end
      end
    end
 # hash[k] == nil -> !has_key?(k). For int-leaf hashes the
 # stored value 0 IS distinguishable from missing key via
 # has_key, so the check is sound (Hash#[] returns nil on
 # miss in CRuby).
    if mname == "[]" && is_hash_type(inner_t) == 1 && args_id_c >= 0
      a_c = get_args(args_id_c)
      if a_c.length >= 1
        has_key_fn = hash_has_key_fn(inner_t)
        if has_key_fn != ""
          key_c = hash_key_arg_for(inner_t, a_c[0])
          chk = "(!" + has_key_fn + "(" + inner_c + ", " + key_c + "))"
          return op == "==" ? chk : "(!" + chk + ")"
        end
      end
    end
 # arr.first / arr.last / arr.pop == nil -> (len == 0).
 # pop on an empty array is a no-op in CRuby (returns nil),
 # so the equality check pre-mutation answer is correct.
    if (mname == "first" || mname == "last" || mname == "pop") && is_array_type(inner_t) == 1
      len_fn = array_length_fn(inner_t)
      if len_fn != "" && (args_id_c < 0 || get_args(args_id_c).length == 0)
        chk = "(" + len_fn + "(" + inner_c + ") == 0)"
        return op == "==" ? chk : "(!" + chk + ")"
      end
    end
 # arr.delete_at(n) == nil -> (n < 0 || n >= len). Checked
 # BEFORE the mutation; CRuby's delete_at returns nil on
 # out-of-range without mutating.
    if mname == "delete_at" && is_array_type(inner_t) == 1 && args_id_c >= 0
      a_c = get_args(args_id_c)
      if a_c.length >= 1
        idx_c = compile_expr(a_c[0])
        len_fn = array_length_fn(inner_t)
        if len_fn != ""
          chk = "(" + idx_c + " < 0 || " + idx_c + " >= " + len_fn + "(" + inner_c + "))"
          return op == "==" ? chk : "(!" + chk + ")"
        end
      end
    end
 # arr.find_index(x) == nil -> !arr.include?(x).
    if mname == "find_index" && is_array_type(inner_t) == 1 && args_id_c >= 0
      a_c = get_args(args_id_c)
      if a_c.length >= 1
        inc_fn = array_include_fn(inner_t)
        if inc_fn != ""
          val_c = compile_expr(a_c[0])
          chk = "(!" + inc_fn + "(" + inner_c + ", " + val_c + "))"
          return op == "==" ? chk : "(!" + chk + ")"
        end
      end
    end
 # regex.match(str) == nil -> !regex.match?(str).
    if mname == "match" && args_id_c >= 0
      rpat = regex_pat_c_expr(inner_recv)
      if rpat != ""
        a_c = get_args(args_id_c)
        if a_c.length >= 1
          chk = "(!sp_re_match_p(" + rpat + ", " + compile_expr(a_c[0]) + "))"
          return op == "==" ? chk : "(!" + chk + ")"
        end
      end
    end
    ""
  end

 # Helper: array-type -> length helper fn name.
  def array_length_fn(t)
    if t == "int_array" || t == "sym_array"
      return "sp_IntArray_length"
    end
    if t == "float_array"
      return "sp_FloatArray_length"
    end
    if t == "str_array"
      return "sp_StrArray_length"
    end
    if t == "poly_array"
      return "sp_PolyArray_length"
    end
    if t.end_with?("_ptr_array")
      return "sp_PtrArray_length"
    end
    ""
  end

  def array_include_fn(t)
    if t == "int_array" || t == "sym_array"
      return "sp_IntArray_include"
    end
    if t == "float_array"
      return "sp_FloatArray_include"
    end
    if t == "str_array"
      return "sp_StrArray_include"
    end
    if t == "poly_array"
      return "sp_PolyArray_include"
    end
    ""
  end

  def hash_has_key_fn(t)
    if t == "str_int_hash"
      return "sp_StrIntHash_has_key"
    end
    if t == "str_str_hash"
      return "sp_StrStrHash_has_key"
    end
    if t == "str_poly_hash"
      return "sp_StrPolyHash_has_key"
    end
    if t == "sym_int_hash"
      return "sp_SymIntHash_has_key"
    end
    if t == "sym_str_hash"
      return "sp_SymStrHash_has_key"
    end
    if t == "sym_poly_hash"
      return "sp_SymPolyHash_has_key"
    end
    if t == "int_str_hash"
      return "sp_IntStrHash_has_key"
    end
    if t == "poly_poly_hash"
      return "sp_PolyPolyHash_has_key"
    end
    ""
  end

  def hash_key_arg_for(t, arg_id)
    if t == "poly_poly_hash"
      return box_expr_to_poly(arg_id)
    end
    if t.start_with?("str_")
      return compile_expr_as_string(arg_id)
    end
    compile_expr(arg_id)
  end

  def compile_eq(nid, op)
    recv = @nd_receiver[nid]
    lt = infer_type(recv)
    args_id = @nd_arguments[nid]
    arg_id = -1
    if args_id >= 0
      a = get_args(args_id)
      if a.length > 0
        arg_id = a[0]
      end
    end
    at = "int"
    if arg_id >= 0
      at = infer_type(arg_id)
    end
 # Container-op `== nil` / `!= nil` shapes that the typed
 # returns can't represent at the value level (sp_IntArray_get
 # returns 0 on out-of-range, not nil). Recognize the call
 # shape on the lhs and emit a length / has_key check
 # equivalent to CRuby's nil-on-miss semantics. Issue #562.
    if at == "nil" && recv >= 0 && @nd_type[recv] == "CallNode"
      r2 = compile_container_op_nil_check(recv, op)
      if r2 != ""
        return r2
      end
    end
 # sp_Class equality via field compare.
 # Class is a value-type struct so plain `==` on a struct
 # isn't valid C; route through the sp_class_eq runtime helper.
 # Same shape for both sides being "class" (the canonical
 # `Foo == Bar` / `c == Foo`) -- mixed class-vs-non-class falls
 # through to the existing cross-type fold below.
    if lt == "class" && at == "class"
      lc_cls = compile_expr(recv)
      rc_cls = arg_id >= 0 ? compile_expr(arg_id) : "((sp_Class){-1LL})"
      @needs_class_table = 1
      if op == "=="
        return "sp_class_eq(" + lc_cls + ", " + rc_cls + ")"
      end
      return "(!sp_class_eq(" + lc_cls + ", " + rc_cls + "))"
    end
 # Time == Time / != — equal instant (tv_sec and tv_nsec). Plain
 # `==` on the struct isn't valid C. Same-instant times compare
 # equal regardless of the is_utc presentation flag.
    if lt == "time" && at == "time"
      le_t = compile_expr(recv)
      re_t = arg_id >= 0 ? compile_expr(arg_id) : "((sp_Time){0,0,0})"
      if op == "=="
        return "(" + time_cmp_expr(le_t, re_t) + " == 0)"
      end
      return "(" + time_cmp_expr(le_t, re_t) + " != 0)"
    end
 # Cross-type prim-vs-obj. Integer#== / Float#== fall back to
 # `other == self` via num_equal (numeric.c); String, Symbol,
 # Nil, True, False are type-strict with no fallback. obj-LHS
 # is handled in compile_obj_operator_expr -- this path is
 # `prim == obj` plus the obj-LHS no-`==`-no-`<=>` fall-through.
    lhs_obj = is_obj_type(lt)
    rhs_obj = is_obj_type(at)
    if lhs_obj != rhs_obj
      other_t = lhs_obj == 1 ? at : lt
 # `obj == nil` / `obj != nil` on a nullable obj
 # type can't constant-fold -- the runtime pointer is allowed
 # to be NULL (the type is obj_<C>?), and the body's behavior
 # depends on the actual value. Fall through to the pointer
 # comparison emit below. Non-nullable obj types still fold
 # because the pointer is never NULL by design (locals are
 # only typed `obj_<C>` after the type-tracker proved every
 # assigned write is non-nil).
      if other_t == "nil"
        obj_side_t = lhs_obj == 1 ? lt : at
        if is_nullable_type(obj_side_t) == 1
          obj_expr_nilcmp = lhs_obj == 1 ? compile_expr(recv) : compile_expr(arg_id)
          if op == "=="
            return "(" + obj_expr_nilcmp + " == NULL)"
          end
          return "(" + obj_expr_nilcmp + " != NULL)"
        end
      end
      if lhs_obj == 0 && (other_t == "int" || other_t == "float")
        cname = at[4, at.length - 4]
        ci = find_class_idx(cname)
        if ci >= 0
          owner = find_method_owner(ci, "==")
          if owner != ""
            owner_ci = find_class_idx(owner)
            midx = cls_find_method_direct(owner_ci, "==")
            ptypes = cls_meth_ptypes_get(owner_ci, midx)
            boxed = ptypes.length > 0 ? compile_expr_for_expected_type(recv, ptypes[0]) : compile_expr(recv)
            obj_expr = compile_expr_gc_rooted(arg_id)
            recv_arg = owner == cname ? obj_expr : "(sp_" + owner + " *)" + obj_expr
            call = "sp_" + owner + "_" + sanitize_name("==") + "(" + recv_arg + ", " + boxed + ")"
            return op == "==" ? call : "(!" + call + ")"
          end
        end
      end
 # Type-strict primitive, or Numeric vs an obj with no user `==`
 # (BasicObject#== identity -> false in MRI).
      if other_t == "int" || other_t == "float" || other_t == "bool" || other_t == "nil" ||
         other_t == "string" || other_t == "mutable_str" || other_t == "symbol"
        return op == "==" ? "FALSE" : "TRUE"
      end
    end
    lc = compile_expr(recv)
    rc = "0"
    if arg_id >= 0
      rc = compile_expr(arg_id)
    end
    if lt == "poly" || at == "poly"
      @needs_rb_value = 1
      left = lc
      right = rc
      if lt != "poly"
        left = box_value_to_poly(lt, lc)
      end
      if at != "poly"
        right = box_value_to_poly(at, rc)
      end
      if op == "=="
        return "sp_poly_eq(" + left + ", " + right + ")"
      else
        return "(!sp_poly_eq(" + left + ", " + right + "))"
      end
    end
 # Symbol equality: distinct from all non-symbol types in Ruby.
    if lt == "symbol"
      if at == "symbol"
        if op == "=="
          return "(" + lc + " == " + rc + ")"
        else
          return "(" + lc + " != " + rc + ")"
        end
      end
 # sym vs non-sym: always unequal in Ruby
      return op == "==" ? "FALSE" : "TRUE"
    end
    if at == "symbol"
 # non-sym lhs vs sym rhs: also always unequal
      return op == "==" ? "FALSE" : "TRUE"
    end
    if lt == "string"
      if at == "nil"
        if op == "=="
          return "(" + lc + " == NULL)"
        else
          return "(" + lc + " != NULL)"
        end
      end
 # Optimize: str[i] == "c" → direct char comparison (no malloc)
      cc = try_char_cmp(nid, op)
      if cc != ""
        return cc
      end
 # NULL-safe equality via sp_str_eq. Plain strcmp(NULL, ...)
 # is UB and segfaults on real inputs (ENV[] returns NULL for
 # unset vars). The helper does a NULL check then strcmp;
 # identical answer for non-NULL operands, so existing
 # equality call sites are unaffected.
      if op == "=="
        return "sp_str_eq(" + lc + ", " + rc + ")"
      else
        return "(!sp_str_eq(" + lc + ", " + rc + "))"
      end
    end
    if at == "nil"
      if type_is_pointer(lt) == 1
        if op == "=="
          return "(" + lc + " == NULL)"
        else
          return "(" + lc + " != NULL)"
        end
      end
 # Pure value-type LHS (int, float, bool) against nil: in Ruby,
 # `0 == nil` is false (only nil equals nil). Without this arm
 # `int == nil` fell through to the raw `(lc == 0)` emit, since
 # compile_expr(NilNode) lowers to "0" and unboxed ints share the
 # same C representation. The conflation surfaced in #521 where
 # `v = h[k]; v == nil` mistook a stored 0 for a missing key.
 # Note: this does NOT fix the underlying hash-missing-key problem
 # (sp_StrIntHash_get still returns 0 for both stored 0 and miss);
 # use Hash#has_key? / Hash#fetch when distinguishing matters.
      if lt == "int" || lt == "float" || lt == "bool"
        if op == "=="
          return "(((void)(" + lc + ")), FALSE)"
        else
          return "(((void)(" + lc + ")), TRUE)"
        end
      end
    end
    if lt == "nil"
 # Symmetric arm for `nil == int` / `nil != int` (and float/bool).
 # Same reasoning as the LHS-typed-int arm above.
      if at == "int" || at == "float" || at == "bool"
        if op == "=="
          return "(((void)(" + rc + ")), FALSE)"
        else
          return "(((void)(" + rc + ")), TRUE)"
        end
      end
    end
 # IntArray-backed equality (int_array, sym_array, and the
 # cross combination -- a `<<`-ed sym-tagged push leaves the
 # static type as int_array but the runtime values are sym
 # ids; both sides share the IntArray layout so the helper
 # is sound). Issue #555.
    if (lt == "int_array" || lt == "sym_array") && (at == "int_array" || at == "sym_array")
      if op == "=="
        return "sp_IntArray_eq((sp_IntArray *)(" + lc + "), (sp_IntArray *)(" + rc + "))"
      else
        return "(!sp_IntArray_eq((sp_IntArray *)(" + lc + "), (sp_IntArray *)(" + rc + ")))"
      end
    end
    if lt == "str_array" && at == "str_array"
      if op == "=="
        return "sp_StrArray_eq(" + lc + ", " + rc + ")"
      else
        return "(!sp_StrArray_eq(" + lc + ", " + rc + "))"
      end
    end
    if lt == "float_array" && at == "float_array"
      if op == "=="
        return "sp_FloatArray_eq(" + lc + ", " + rc + ")"
      else
        return "(!sp_FloatArray_eq(" + lc + ", " + rc + "))"
      end
    end
    if lt == "poly_array" && at == "poly_array"
      if op == "=="
        return "sp_PolyArray_eq(" + lc + ", " + rc + ")"
      else
        return "(!sp_PolyArray_eq(" + lc + ", " + rc + "))"
      end
    end
 # Hash equality arms. Same shape as the typed-array arms
 # above. Issue #555. Compares by sorted key set + per-key
 # value equality (each variant's _eq helper handles its
 # value type's comparison: int via ==, string via sp_str_eq,
 # poly via sp_poly_eq).
    if is_hash_type(lt) == 1 && lt == at
      hash_eq_fn = ""
      if lt == "str_int_hash"
        hash_eq_fn = "sp_StrIntHash_eq"
      elsif lt == "str_str_hash"
        hash_eq_fn = "sp_StrStrHash_eq"
      elsif lt == "int_str_hash"
        hash_eq_fn = "sp_IntStrHash_eq"
      elsif lt == "sym_int_hash"
        hash_eq_fn = "sp_SymIntHash_eq"
        @needs_sym_int_hash = 1
      elsif lt == "sym_str_hash"
        hash_eq_fn = "sp_SymStrHash_eq"
        @needs_sym_str_hash = 1
      elsif lt == "str_poly_hash"
        hash_eq_fn = "sp_StrPolyHash_eq"
        @needs_str_poly_hash = 1
      elsif lt == "sym_poly_hash"
        hash_eq_fn = "sp_SymPolyHash_eq"
        @needs_sym_poly_hash = 1
      elsif lt == "poly_poly_hash"
        hash_eq_fn = "sp_PolyPolyHash_eq"
        @needs_poly_poly_hash = 1
      end
      if hash_eq_fn != ""
        if op == "=="
          return hash_eq_fn + "(" + lc + ", " + rc + ")"
        else
          return "(!" + hash_eq_fn + "(" + lc + ", " + rc + "))"
        end
      end
    end
    "(" + lc + " " + op + " " + rc + ")"
  end

 # Box an already-compiled value of static type `at` into an sp_RbVal.
 # Mirrors box_expr_to_poly but operates on a raw (type, value) pair so
 # callers that already have temps don't have to re-emit the expr.
 # Unbox an sp_RbVal expression `val` into the C representation
 # of `at`. Used at sites where the destructure / cls_id-aware
 # dispatch produced an sp_RbVal but the consumer slot is a
 # concrete C type (mrb_int, sp_IntArray *, const char *, ...).
 # No runtime cls_id check — caller has already narrowed via
 # static type / wrapping cls_id dispatch.
  def unbox_poly_to(at, val)
    base = is_nullable_type(at) == 1 ? base_type(at) : at
    if base == "int" || base == "bool" || base == "nil"
      return "(" + val + ").v.i"
    end
    if base == "float"
      return "(" + val + ").v.f"
    end
    if base == "string"
      return "(const char *)(" + val + ").v.p"
    end
    if base == "symbol"
      return "(sp_sym)(" + val + ").v.i"
    end
    if base == "int_array"
      return "(sp_IntArray *)(" + val + ").v.p"
    end
    if base == "float_array"
      return "(sp_FloatArray *)(" + val + ").v.p"
    end
    if base == "str_array"
      return "(sp_StrArray *)(" + val + ").v.p"
    end
    if base == "sym_array"
      return "(sp_IntArray *)(" + val + ").v.p"
    end
    if base == "poly_array"
      return "(sp_PolyArray *)(" + val + ").v.p"
    end
    if is_ptr_array_type(base) == 1
      return "(sp_PtrArray *)(" + val + ").v.p"
    end
    if is_obj_type(base) == 1
      cname = base[4, base.length - 4]
      return "(sp_" + cname + " *)(" + val + ").v.p"
    end
 # Fallback: cast generic pointer.
    "(void *)(" + val + ").v.p"
  end

  def box_value_to_poly(at, val)
    nullable = is_nullable_type(at)
    raw_at = at
    at = base_type(at)
    if nullable == 1 && is_nullable_pointer_type(raw_at) == 1
      if at == "string"
        return "sp_box_nullable_str(" + val + ")"
      end
      if at == "int_array"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_INT_ARRAY)"
      end
      if at == "float_array"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_FLT_ARRAY)"
      end
      if at == "str_array"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_STR_ARRAY)"
      end
      if at == "sym_array"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_SYM_ARRAY)"
      end
      if is_ptr_array_type(at) == 1
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_PTR_ARRAY)"
      end
      if at == "poly_array"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_POLY_ARRAY)"
      end
      if at == "proc" || at == "lambda"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_PROC)"
      end
      if is_obj_type(at) == 1
        cname = at[4, at.length - 4]
        ci = find_class_idx(cname)
 # Tier 4: stamp the unified cls_id so the
 # boxed value carries the same id that constructors
 # write and that sp_class_for_poly reads back.
        return "sp_box_nullable_obj(" + val + ", " + cls_id_for_user_internal(ci).to_s + ")"
      end
 # Stamp hash cls_id so Hash#dig can recover the concrete type;
 # falling through to cls_id=0 would make dig collapse to nil.
      hcid = cls_id_for_hash_type(at)
      if hcid != ""
        return "sp_box_nullable_obj((void *)(" + val + "), " + hcid + ")"
      end
      if type_is_pointer(at) == 1
        return "sp_box_nullable_obj((void *)(" + val + "), 0)"
      end
    end
    box_non_nullable_value_to_poly(at, val)
  end

  def box_non_nullable_value_to_poly(at, val)
    if at == "poly"
      return val
    end
    if at == "int"
      return "sp_box_int(" + val + ")"
    end
    if at == "string"
      return "sp_box_str(" + val + ")"
    end
    if at == "float"
      return "sp_box_float(" + val + ")"
    end
    if at == "bool"
      return "sp_box_bool(" + val + ")"
    end
    if at == "nil"
 # `val` may be a side-effecting call (e.g. an arm in a
 # cls_id-dispatched table where the user-defined override
 # returns nil because its body is a `puts` / similar). Drop
 # the value but keep the side effect via the comma operator;
 # otherwise the generated dispatch silently elides the call
 # for any subclass whose method's static return type is nil.
      return "((void)(" + val + "), sp_box_nil())"
    end
    if at == "symbol"
      return "sp_box_sym(" + val + ")"
    end
    if at == "int_array"
      return "sp_box_int_array(" + val + ")"
    end
    if at == "float_array"
      return "sp_box_float_array(" + val + ")"
    end
    if at == "str_array"
      return "sp_box_str_array(" + val + ")"
    end
    if at == "sym_array"
      return "sp_box_sym_array(" + val + ")"
    end
    if is_ptr_array_type(at) == 1
      return "sp_box_ptr_array(" + val + ")"
    end
    if at == "poly_array"
      return "sp_box_poly_array(" + val + ")"
    end
    if at == "proc" || at == "lambda"
      return "sp_box_proc(" + val + ")"
    end
    if at == "range"
 # sp_Range is a 16-byte value type; sp_RbVal's union is 8.
 # sp_box_range copies the stack range onto the GC heap and
 # boxes the pointer via SP_BUILTIN_RANGE.
      return "sp_box_range(" + val + ")"
    end
    if at == "time"
 # Same shape as range: sp_Time is wider than sp_RbVal's union,
 # heap-copy via sp_box_time and box through SP_BUILTIN_TIME.
      return "sp_box_time(" + val + ")"
    end
    if is_obj_type(at) == 1
      cname = at[4, at.length - 4]
      ci = find_class_idx(cname)
      return "sp_box_obj(" + val + ", " + cls_id_for_user_internal(ci).to_s + ")"
    end
    hcid = cls_id_for_hash_type(at)
    if hcid != ""
      return "sp_box_obj((void *)(" + val + "), " + hcid + ")"
    end
 # A `sp_String *` (mutable_str) is a heap buffer with a `data`
 # field of const char *. Box it as a string (SP_TAG_STR) so
 # consumers that dispatch on the tag (sp_poly_to_s, write_response
 # in roundhouse's Tep::Server, etc.) read the string content
 # instead of falling through to the SP_TAG_OBJ cls_id=0 case
 # which matches no arm. Issue #541. Spill the recv to a temp via
 # a statement-expression so side effects fire exactly once.
    if at == "mutable_str"
      mtmp = new_temp
      return "({ sp_String *" + mtmp + " = " + val + "; " + mtmp + " ? sp_box_str(" + mtmp + "->data) : sp_box_nil(); })"
    end
 # Other pointer types — box with a neutral cls_id of 0 rather
 # than truncating the pointer to int.
    if type_is_pointer(at) == 1
      return "sp_box_obj((void *)(" + val + "), 0)"
    end
    "sp_box_int(" + val + ")"
  end

  def box_expr_to_poly(nid)
 # Ternary / if-as-expression whose branches may have different
 # concrete types: per-branch box unconditionally. Same-type
 # branches yield a redundant box that still produces correct
 # sp_RbVal; mixed-type branches need the per-branch box to
 # avoid C's pointer/integer ternary-type-mismatch (which would
 # otherwise land as an unsafe cast in the poly slot and
 # segfault). Gating on infer_type's "poly" answer would miss
 # mixed-type cases — unify_return_type treats int as
 # default/unresolved (`int + T → T`), so a genuinely
 # int-string ternary infers as "string" and a poly gate would
 # fall through to the same UB-prone wholesale `sp_box_str`.
    if nid >= 0 && @nd_type[nid] == "IfNode"
 # When the predicate is a statically-decidable is_a? /
 # kind_of? on an already-typed expression, emit only the
 # live arm. The dead arm may contain a recursion call whose
 # argument types don't match the function's signature (e.g.
 # `v.is_a?(Hash) ? recurse(v) : v` where v is statically a
 # string) — generating it would land as a C type error even
 # though the branch is unreachable at runtime.
      sv = static_is_a_value(@nd_predicate[nid])
      if sv == "TRUE"
        body = @nd_body[nid]
        if body >= 0
          ts = get_stmts(body)
          if ts.length > 0
            return box_expr_to_poly(ts.last)
          end
        end
        return "sp_box_nil()"
      end
      if sv == "FALSE"
        sub = @nd_subsequent[nid]
        if sub >= 0
          if @nd_type[sub] == "ElseNode"
            eb = @nd_body[sub]
            if eb >= 0
              es = get_stmts(eb)
              if es.length > 0
                return box_expr_to_poly(es.last)
              end
            end
          else
            return box_expr_to_poly(sub)
          end
        end
        return "sp_box_nil()"
      end
      cond = compile_cond_expr(@nd_predicate[nid])
      then_v = "sp_box_nil()"
      body = @nd_body[nid]
      if body >= 0
        ts = get_stmts(body)
        if ts.length > 0
          then_v = box_expr_to_poly(ts.last)
        end
      end
      else_v = "sp_box_nil()"
      sub = @nd_subsequent[nid]
      if sub >= 0
        if @nd_type[sub] == "ElseNode"
          eb = @nd_body[sub]
          if eb >= 0
            es = get_stmts(eb)
            if es.length > 0
              else_v = box_expr_to_poly(es.last)
            end
          end
        else
          else_v = box_expr_to_poly(sub)
        end
      end
      return "(" + cond + " ? " + then_v + " : " + else_v + ")"
    end
 # Pass the nullable type through; box_value_to_poly's nullable
 # wrapper picks the right `sp_box_nullable_*` variant before
 # falling back to base-type dispatch.
    at = infer_type(nid)
    val = compile_expr(nid)
    box_value_to_poly(at, val)
  end

  def box_val_to_poly(val, at)
    box_value_to_poly(at, val)
  end

 # Emit a chained `@a = @b = ... = expr` write as one rhs evaluation
 # plus N per-slot stores. Caller has verified that `nid` is an
 # InstanceVariableWriteNode whose expression is itself an
 # InstanceVariableWriteNode. Each slot is typed independently (some
 # widened to poly by scan_writer_calls, others kept native), so the
 # store boxes through sp_RbVal only for the poly slots.
  def compile_chained_ivar_writes(nid)
 # Collect the chain of ivar names (head -> tail) and the bottom
 # rhs node id.
    ivars = []
    cur = nid
    while @nd_type[cur] == "InstanceVariableWriteNode"
      ivars.push(@nd_name[cur])
      cur = @nd_expression[cur]
    end
    rhs_id = cur
    rhs_type = infer_type(rhs_id)
 # NilNode rhs has no side effect and `compile_expr(NilNode)` is the
 # null-pointer-constant `0`, which assigns cleanly to any slot
 # type. Routing it through a typed temp would force a `mrb_int 0`
 # variable into pointer slots, which C won't implicitly null. Emit
 # one store per slot through the unchained IVW path; each slot
 # picks its own boxing rule (poly slots box to sp_box_nil()).
    if @nd_type[rhs_id] == "NilNode"
      ki = 0
      while ki < ivars.length
        cur_iv = nid
        kj = 0
        while kj < ki
          cur_iv = @nd_expression[cur_iv]
          kj = kj + 1
        end
        saved_expr = @nd_expression[cur_iv]
        @nd_expression[cur_iv] = rhs_id
        compile_stmt(cur_iv)
        @nd_expression[cur_iv] = saved_expr
        ki = ki + 1
      end
      return
    end
 # Empty `{}` / `[]` literal RHS — `compile_expr` returns the
 # default `sp_StrIntHash_new()` / `sp_IntArray_new()`, but
 # slots may have been promoted to a typed container by their
 # subsequent writes (e.g. `@h["k"] = "v"` lifts the slot to
 # str_str_hash). If every chain participant agrees on the
 # same promoted concrete container type, emit the slot-typed
 # constructor as the temp so each store is type-correct AND
 # the Ruby semantic of one shared object is preserved across
 # the chain. Disagreeing-type chains fall through to the
 # general case below; the resulting C will still warn about
 # pointer
 # type mismatch but at least one slot will be correct.
    if is_empty_hash_literal(rhs_id) == 1 || is_empty_array_literal(rhs_id) == 1
      consensus_t = ""
      consensus_ok = 1
      pi = 0
      while pi < ivars.length
        pt = ""
        if @current_class_idx >= 0
          pt = cls_ivar_type(@current_class_idx, ivars[pi])
        end
        if pi == 0
          consensus_t = pt
        elsif pt != consensus_t
          consensus_ok = 0
        end
        pi = pi + 1
      end
      if consensus_ok == 1 && consensus_t != "" && consensus_t != "str_int_hash" && consensus_t != "int_array" && consensus_t != "poly"
        typed_ctor = ""
        if is_empty_hash_literal(rhs_id) == 1
          if consensus_t == "str_str_hash"
            @needs_str_str_hash = 1
            typed_ctor = "sp_StrStrHash_new()"
          elsif consensus_t == "int_str_hash"
            @needs_int_str_hash = 1
            typed_ctor = "sp_IntStrHash_new()"
          elsif consensus_t == "sym_int_hash"
            @needs_sym_int_hash = 1
            typed_ctor = "sp_SymIntHash_new()"
          elsif consensus_t == "sym_str_hash"
            @needs_sym_str_hash = 1
            typed_ctor = "sp_SymStrHash_new()"
          elsif consensus_t == "str_poly_hash"
            typed_ctor = "sp_StrPolyHash_new()"
          elsif consensus_t == "sym_poly_hash"
            typed_ctor = "sp_SymPolyHash_new()"
          elsif consensus_t == "poly_poly_hash"
            @needs_poly_poly_hash = 1
            @needs_rb_value = 1
            typed_ctor = "sp_PolyPolyHash_new()"
          end
        else
          typed_ctor = empty_array_new_for_type(consensus_t)
        end
        if typed_ctor != ""
          @needs_gc = 1
          typed_tmp = new_temp
          emit("  " + c_type(consensus_t) + " " + typed_tmp + " = " + typed_ctor + ";")
          typed_ivi = 0
          while typed_ivi < ivars.length
            emit("  " + self_arrow + sanitize_ivar(ivars[typed_ivi]) + " = " + typed_tmp + ";")
            typed_ivi = typed_ivi + 1
          end
          return
        end
      end
    end
 # General case: evaluate the rhs once into a typed temp, then
 # store into each slot. Side-effecting rhs (CallNode etc.) must
 # not be replicated.
    rhs_expr = compile_expr(rhs_id)
    tmp = new_temp
    emit("  " + c_type(rhs_type) + " " + tmp + " = " + rhs_expr + ";")
    ki = 0
    while ki < ivars.length
      iname_i = ivars[ki]
      ivt_i = ""
      if @current_class_idx >= 0
        ivt_i = cls_ivar_type(@current_class_idx, iname_i)
      end
      val_i = tmp
      if ivt_i == "poly" && rhs_type != "poly"
        val_i = box_value_to_poly(rhs_type, tmp)
      end
      mod_ivar = 0
      mi3 = 0
      while mi3 < @module_names.length
        mmod = @module_names[mi3]
        if mmod != ""
          if @current_method_name.start_with?(mmod + "_cls_")
            cname3 = mmod + "_" + iname_i[1, iname_i.length - 1]
            ci3 = find_const_idx(cname3)
            if ci3 >= 0
              emit("  cst_" + cname3 + " = " + val_i + ";")
              mod_ivar = 1
            end
          end
        end
        mi3 = mi3 + 1
      end
      if mod_ivar == 0
        emit("  " + self_arrow + sanitize_ivar(iname_i) + " = " + val_i + ";")
      end
      ki = ki + 1
    end
  end

 # Emit a runtime loop that pushes every element of the array `src_expr`
 # (a node id whose value is some typed array) onto the destination
 # int_array variable `dst`. Used when expanding `*args` into a rest
 # parameter that will be received as sp_IntArray *.
  def emit_splat_into_int_array(dst, src_expr)
    src_t = infer_type(src_expr)
    src_v = compile_expr(src_expr)
    @needs_int_array = 1
    @needs_gc = 1
    if src_t == "int_array" || src_t == "sym_array"
      i = new_temp
      emit("  for (mrb_int " + i + " = 0; " + i + " < sp_IntArray_length(" + src_v + "); " + i + "++) sp_IntArray_push(" + dst + ", sp_IntArray_get(" + src_v + ", " + i + "));")
      return
    end
    if src_t == "str_array"
      @needs_str_array = 1
      i = new_temp
      emit("  for (mrb_int " + i + " = 0; " + i + " < sp_StrArray_length(" + src_v + "); " + i + "++) sp_IntArray_push(" + dst + ", (mrb_int)sp_StrArray_get(" + src_v + ", " + i + "));")
      return
    end
    if src_t == "float_array"
      @needs_float_array = 1
      i = new_temp
      emit("  for (mrb_int " + i + " = 0; " + i + " < sp_FloatArray_length(" + src_v + "); " + i + "++) sp_IntArray_push(" + dst + ", (mrb_int)sp_FloatArray_get(" + src_v + ", " + i + "));")
      return
    end
    if is_ptr_array_type(src_t) == 1
      i = new_temp
      emit("  for (mrb_int " + i + " = 0; " + i + " < sp_PtrArray_length(" + src_v + "); " + i + "++) sp_IntArray_push(" + dst + ", (mrb_int)(intptr_t)sp_PtrArray_get(" + src_v + ", " + i + "));")
      return
    end
    if src_t == "poly_array"
      i = new_temp
      emit("  for (mrb_int " + i + " = 0; " + i + " < sp_PolyArray_length(" + src_v + "); " + i + "++) sp_IntArray_push(" + dst + ", sp_PolyArray_get(" + src_v + ", " + i + ").v.i);")
      return
    end
 # Fallback: treat the single value as one element.
    emit("  sp_IntArray_push(" + dst + ", (mrb_int)" + src_v + ");")
  end

 # Read an element of a typed array as an mrb_int (so it fits int param
 # slots and the int_array rest bundle uniformly).
  def array_get_as_int_expr(src_t, src_v, idx_expr)
    if src_t == "int_array" || src_t == "sym_array"
      return "sp_IntArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if src_t == "str_array"
      return "(mrb_int)sp_StrArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if src_t == "float_array"
      return "(mrb_int)sp_FloatArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if is_ptr_array_type(src_t) == 1
      return "(mrb_int)(intptr_t)sp_PtrArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if src_t == "poly_array"
 # Pull the int channel out of the tagged union. Lossy for non-int
 # tags — Spinel's *rest can only hold mrb_int today, so any non-int
 # element splatted into a rest param prints as raw bits.
      return "sp_PolyArray_get(" + src_v + ", " + idx_expr + ").v.i"
    end
    "0"
  end

 # Same as array_get_as_int_expr but returns the element in its native
 # C type (used when the param slot is typed, e.g. const char *).
  def array_get_native_expr(src_t, src_v, idx_expr)
    if src_t == "int_array" || src_t == "sym_array"
      return "sp_IntArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if src_t == "str_array"
      return "sp_StrArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if src_t == "float_array"
      return "sp_FloatArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if is_ptr_array_type(src_t) == 1
      return "sp_PtrArray_get(" + src_v + ", " + idx_expr + ")"
    end
    "0"
  end

 # Splat-aware companion to compile_call_args_with_defaults. Handles a
 # single SplatNode in positional args. The conceptual positional list
 # is (prefix... ++ splat_array ++ suffix...); fixed params eat from the
 # left; the rest param (if any) gets the remainder.
  def compile_call_args_splat(nid, mi, pnames, ptypes, defaults, kw_names, kw_vals, kw_arg_ids, positional_ids, splat_idx, rest_param_idx)
    splat_node = positional_ids[splat_idx]
    splat_src_id = @nd_expression[splat_node]
    prefix_count = splat_idx
    suffix_count = positional_ids.length - splat_idx - 1

 # Pre-evaluate the splat source so we can index it twice (length and
 # element access) without re-evaluating side effects.
    src_t = "int_array"
    src_v = "0"
    if splat_src_id >= 0
      src_t = infer_type(splat_src_id)
      @needs_gc = 1
      src_tmp = new_temp
      emit("  " + c_type(src_t) + " " + src_tmp + " = " + compile_expr(splat_src_id) + ";")
      if type_is_pointer(src_t) == 1
        emit("  SP_GC_ROOT(" + src_tmp + ");")
      end
      src_v = src_tmp
    end
    src_len_expr = length_c_expr(src_t, src_v)
    if src_len_expr == ""
      src_len_expr = "0"
    end

 # Identify if the last emitted param is the explicit rest slot.
    method_has_rest = 0
    if rest_param_idx >= 0 && rest_param_idx == pnames.length - 1
      method_has_rest = 1
    end
    n_fixed = pnames.length
    if method_has_rest == 1
      n_fixed = pnames.length - 1
    end

    result = ""
    k = 0
    while k < pnames.length
      if k > 0
        result = result + ", "
      end

 # Keyword args take priority (matches non-splat path).
      kw_found = 0
      ki = 0
      while ki < kw_names.length
        if kw_names[ki] == pnames[k]
          kw_found = 1
          if k < ptypes.length && ptypes[k] == "poly"
 # Pick the box helper from the arg's actual source
 # type via box_expr_to_poly. A hardcoded sp_box_str
 # would mistype any non-string source (e.g. an
 # `obj_<C>` instance) as SP_TAG_STR — invalid C and a
 # value that disagrees with sp_RbVal's tag/cls_id
 # contract at runtime.
            result = result + box_expr_to_poly(kw_arg_ids[ki])
          else
            result = result + kw_vals[ki]
          end
        end
        ki = ki + 1
      end
      if kw_found == 1
        k = k + 1
        next
      end

 # Rest param: bundle leftover splat elements + suffix positionals.
      if k == pnames.length - 1 && method_has_rest == 1
        @needs_int_array = 1
        @needs_gc = 1
        rest_tmp = new_temp
        emit("  sp_IntArray *" + rest_tmp + " = sp_IntArray_new();")
 # Prefix positionals beyond n_fixed overflow into the rest before
 # any splat content (e.g. take(1, 2, *xs) where take has only a
 # *rest param: the literals 1 and 2 must lead the bundle).
        po_start = n_fixed
        if po_start < 0
          po_start = 0
        end
        if po_start < prefix_count
          poi = po_start
          while poi < prefix_count
            emit("  sp_IntArray_push(" + rest_tmp + ", (mrb_int)" + compile_expr(positional_ids[poi]) + ");")
            poi = poi + 1
          end
        end
        consumed = n_fixed - prefix_count
        if consumed < 0
          consumed = 0
        end
        i_loop = new_temp
        emit("  for (mrb_int " + i_loop + " = " + consumed.to_s + "; " + i_loop + " < " + src_len_expr + "; " + i_loop + "++) sp_IntArray_push(" + rest_tmp + ", " + array_get_as_int_expr(src_t, src_v, i_loop) + ");")
        si = 0
        while si < suffix_count
          pid = positional_ids[splat_idx + 1 + si]
          emit("  sp_IntArray_push(" + rest_tmp + ", (mrb_int)" + compile_expr(pid) + ");")
          si = si + 1
        end
        result = result + rest_tmp
        k = k + 1
        next
      end

 # Fixed param. Determine which conceptual positional it consumes.
      pt = "int"
      if k < ptypes.length
        pt = ptypes[k]
      end
      if k < prefix_count
        if pt == "poly"
          result = result + box_expr_to_poly(positional_ids[k])
        else
 # empty `{}` literal as arg gets coerced to the
 # param's expected hash variant (which may have been widened
 # by narrow_param_hash_types_from_body_writes from the
 # caller-side default `str_int_hash`). Without this, the
 # caller would emit `sp_StrIntHash_new()` and the callee's
 # signature `sp_StrStrHash *` would type-mismatch.
          coerced = empty_hash_coerce(positional_ids[k], pt)
          if coerced != ""
            result = result + coerced
          else
            result = result + compile_expr(positional_ids[k])
          end
        end
        k = k + 1
        next
      end
 # Index into the splat source.
      idx_in_splat = k - prefix_count
 # Unconsumed splat elements available for fixed params:
 # src_len - (positional slots after the splat that need to come
 # from the splat to feed remaining fixed params)
 # We don't know src_len statically, so we trust the caller has
 # provided enough — a runtime over-read returns 0/NULL via the
 # array's bounds clamp.
      slots_left_for_splat = n_fixed - prefix_count
      if idx_in_splat < slots_left_for_splat
        ge = array_get_native_expr(src_t, src_v, idx_in_splat.to_s)
        if pt == "poly"
 # The splat element itself isn't a node id, so wrap manually.
          result = result + ge
        else
          result = result + ge
        end
        k = k + 1
        next
      end
 # Comes from a suffix positional (after the splat).
      suffix_offset = idx_in_splat - slots_left_for_splat
      pid_idx = splat_idx + 1 + suffix_offset
      if pid_idx < positional_ids.length
        if pt == "poly"
          result = result + box_expr_to_poly(positional_ids[pid_idx])
        else
          result = result + compile_expr(positional_ids[pid_idx])
        end
      else
 # Fall back to default if defined.
        if k < defaults.length
          def_id = defaults[k].to_i
          if def_id >= 0
            if k < ptypes.length
              result = result + compile_expr_for_expected_type(def_id, ptypes[k])
            else
              result = result + compile_expr(def_id)
            end
          else
            if k < ptypes.length && ptypes[k] == "poly"
              result = result + "sp_box_nil()"
            else
              result = result + "0"
            end
          end
        else
          if k < ptypes.length && ptypes[k] == "poly"
            result = result + "sp_box_nil()"
          else
            result = result + "0"
          end
        end
      end
      k = k + 1
    end
    result
  end

  def compile_call_args_with_defaults(nid, mi, omit_trailing = 0)
 # `omit_trailing` is the number of trailing param slots to leave out
 # entirely — block-forwarding call sites pass 1 so the &block slot
 # isn't default-padded with "0" (the actual proc is appended by the
 # caller after this returns).
    args_id = @nd_arguments[nid]
    arg_ids = []
    if args_id >= 0
      arg_ids = get_args(args_id)
    end
    pnames = @meth_param_names[mi].split(",")
    ptypes = @meth_param_types[mi].split(",")
    defaults = @meth_has_defaults[mi].split(",")
    rest_param_idx = method_rest_index(mi)
    if omit_trailing > 0
      kept = "".split(",")
      pk = 0
      limit = pnames.length - omit_trailing
      if limit < 0
        limit = 0
      end
      while pk < limit
        kept.push(pnames[pk])
        pk = pk + 1
      end
      pnames = kept
    end
    if rest_param_idx >= pnames.length
      rest_param_idx = -1
    end

 # Check if args contain a KeywordHashNode - extract kw pairs.
 # Track kw_arg_ids parallel to kw_vals so the poly-boxing branch
 # below () can pick the right box helper from the arg's
 # actual source type via box_expr_to_poly, rather than hardcoding
 # sp_box_str.
    kw_names = "".split(",")
    kw_vals = "".split(",")
    kw_arg_ids = []
    positional_ids = []
    splat_idx = -1
    splat_count_local = 0
    ak = 0
    while ak < arg_ids.length
      if @nd_type[arg_ids[ak]] == "KeywordHashNode"
        elems = parse_id_list(@nd_elements[arg_ids[ak]])
        ek = 0
        while ek < elems.length
          if @nd_type[elems[ek]] == "AssocNode"
            key_id = @nd_key[elems[ek]]
            if key_id >= 0
              kname = ""
              if @nd_type[key_id] == "SymbolNode"
                kname = @nd_content[key_id]
              end
              kw_names.push(kname)
              kw_vals.push(compile_expr(@nd_expression[elems[ek]]))
              kw_arg_ids.push(@nd_expression[elems[ek]])
            end
          end
          ek = ek + 1
        end
      else
        if @nd_type[arg_ids[ak]] == "SplatNode"
          if splat_idx < 0
            splat_idx = positional_ids.length
          end
          splat_count_local = splat_count_local + 1
        end
        positional_ids.push(arg_ids[ak])
      end
      ak = ak + 1
    end

    if splat_count_local == 1
      return compile_call_args_splat(nid, mi, pnames, ptypes, defaults, kw_names, kw_vals, kw_arg_ids, positional_ids, splat_idx, rest_param_idx)
    end

    result = ""
    k = 0
    while k < pnames.length
      if k > 0
        result = result + ", "
      end
 # Check keyword args first
      kw_found = 0
      ki = 0
      while ki < kw_names.length
        if kw_names[ki] == pnames[k]
          kw_found = 1
 # Check if param is poly
          if k < ptypes.length
            if ptypes[k] == "poly"
 # Pick the box helper from the arg's actual source
 # type via box_expr_to_poly. A hardcoded sp_box_str
 # would mistype any non-string source — and a
 # kwargs call site with a poly-widened param
 # (e.g. `model:` after call-site widening folds
 # Article + Comment into poly) is exactly the path
 # that flows non-string objs through here.
              result = result + box_expr_to_poly(kw_arg_ids[ki])
            else
              result = result + kw_vals[ki]
            end
          else
            result = result + kw_vals[ki]
          end
        end
        ki = ki + 1
      end
      if kw_found == 0
        if k < ptypes.length
          if ptypes[k] == "int_array" && k == rest_param_idx
 # Rest parameter (splat). Trigger when caller passes more
 # positional args than the method has params, OR when any
 # positional arg is itself a SplatNode that we have to expand.
            has_splat_arg = 0
            si = k
            while si < positional_ids.length
              if @nd_type[positional_ids[si]] == "SplatNode"
                has_splat_arg = 1
              end
              si = si + 1
            end
 # Treat the last param as a rest target when it's the trailing
 # int_array slot. This covers three cases:
 # - extra positional args spilling in (the original heuristic)
 # - a SplatNode somewhere in the args
 # - no args supplied at all (rest-only method called bare)
            is_last_param = 0
            if k == pnames.length - 1
              is_last_param = 1
            end
            treat_as_rest = 0
            if positional_ids.length > pnames.length || has_splat_arg == 1
              treat_as_rest = 1
            end
            if is_last_param == 1 && positional_ids.length <= k
              treat_as_rest = 1
            end
            if treat_as_rest == 1
 # Fast path: the only positional is a splat whose source is
 # already an int_array. Pass it directly without copying.
              if has_splat_arg == 1 && positional_ids.length == k + 1 && @nd_type[positional_ids[k]] == "SplatNode"
                src_expr = @nd_expression[positional_ids[k]]
                if src_expr >= 0
                  src_t = infer_type(src_expr)
                  if src_t == "int_array" || src_t == "sym_array"
                    result = result + compile_expr(src_expr)
                    k = k + 1
                    next
                  end
                end
              end
              @needs_int_array = 1
              @needs_gc = 1
              tmp = new_temp
              emit("  sp_IntArray *" + tmp + " = sp_IntArray_new();")
              pi = k
              while pi < positional_ids.length
                if @nd_type[positional_ids[pi]] == "SplatNode"
                  src_expr2 = @nd_expression[positional_ids[pi]]
                  if src_expr2 >= 0
                    emit_splat_into_int_array(tmp, src_expr2)
                  end
                else
                  emit("  sp_IntArray_push(" + tmp + ", (mrb_int)" + compile_expr(positional_ids[pi]) + ");")
                end
                pi = pi + 1
              end
              result = result + tmp
              k = k + 1
              next
            end
          end
        end
        if k < positional_ids.length
          if k < ptypes.length
            if ptypes[k] == "poly"
              result = result + box_expr_to_poly(positional_ids[k])
              k = k + 1
              next
            end
 # An empty `[]` literal at the call site needs to
 # construct the right typed-array container. The
 # literal's own infer_type returns int_array
 # (compile_array_literal emits sp_IntArray_new()), but
 # when the param is a concrete typed-array, emit the
 # matching constructor instead.
            if is_empty_array_literal(positional_ids[k]) == 1
              if ptypes[k] == "str_array"
                @needs_str_array = 1
                @needs_gc = 1
                result = result + "sp_StrArray_new()"
                k = k + 1
                next
              end
              if ptypes[k] == "float_array"
                @needs_float_array = 1
                @needs_gc = 1
                result = result + "sp_FloatArray_new()"
                k = k + 1
                next
              end
              if ptypes[k] == "sym_array"
                @needs_int_array = 1
                @needs_gc = 1
                result = result + "sp_IntArray_new()"
                k = k + 1
                next
              end
            end
 # empty `{}` literal -> coerce to the param's
 # widened hash variant (e.g. body promoted str_int_hash
 # to str_str_hash via narrow_param_hash_types_from_body_writes).
            coerced_h = empty_hash_coerce(positional_ids[k], ptypes[k])
            if coerced_h != ""
              result = result + coerced_h
              k = k + 1
              next
            end
 # When the param expects `sp_<C> *` but the arg's static
 # type is `int` (typically a local catching a method
 # whose return widened to mrb_int because the union
 # collapsed somewhere upstream — e.g.
 # `parent = article` after a `nil.return` narrows
 # parent's declared type but the call site below still
 # passes `lv_parent` raw), insert the same cast that
 # compile_int_class_fallback_expr already inserts at
 # property-access sites. Without this, gcc errors
 # `incompatible integer to pointer conversion`.
            if is_obj_type(ptypes[k]) == 1
              arg_at = infer_type(positional_ids[k])
              if arg_at == "int"
                bt_arg = base_type(ptypes[k])
                arg_cname = bt_arg[4, bt_arg.length - 4]
                result = result + "(sp_" + arg_cname + " *)" + compile_expr(positional_ids[k])
                k = k + 1
                next
              end
            end
 # Issue #542 / #545: param body-inferred as a hash or array
 # variant but the caller's arg is int/nil because the source
 # (uninitialized ivar, untyped registry getter, etc.) never
 # got widened. Cast the int/nil value to NULL of the param's
 # pointer type. The matching runtime NULL-guards in
 # `sp_<X>Hash_get` / `sp_PolyArray_length` etc. return the
 # slot's default sentinel so the body's `param["k"]` /
 # `param.length` produces 0 / nil instead of segfaulting --
 # closer to CRuby's NoMethodError (still wrong but at least
 # defined and unlike the silent emit-0).
            if is_hash_type(ptypes[k]) == 1 || ptypes[k] == "poly_array"
              arg_at_h542 = infer_type(positional_ids[k])
              if arg_at_h542 == "int" || arg_at_h542 == "nil"
                result = result + "(" + c_type(ptypes[k]) + ")NULL"
                k = k + 1
                next
              end
              if arg_at_h542 == "poly"
                result = result + "(" + c_type(ptypes[k]) + ")(" + compile_expr(positional_ids[k]) + ").v.p"
                k = k + 1
                next
              end
            end
          end
          if k < ptypes.length
 # Route through compile_expr_for_expected_type so a poly arg
 # passed to a typed param (after an is_a? guard, or whenever
 # the caller is more general than the callee) is unboxed via
 # the matching union field. Mirrors the #438 IntStrHash-key
 # unbox and extends it to user-method args.
            result = result + cast_away_volatile_arg(positional_ids[k], compile_expr_for_expected_type(positional_ids[k], ptypes[k]))
          else
            result = result + cast_away_volatile_arg(positional_ids[k], compile_expr(positional_ids[k]))
          end
        else
 # Use default value
          if k < defaults.length
            def_id = defaults[k].to_i
            if def_id >= 0
 # An empty `{}` default whose receiving param has been
 # body-widened to a specific hash variant (e.g.
 # `set_cookies:` to sp_SymStrHash via callers passing
 # symbol-keyed hashes) needs to construct the matching
 # empty container, not the generic sp_StrIntHash. Mirrors
 # the positional-arg empty_hash_coerce branch above.
              if k < ptypes.length
                coerced_def_h = empty_hash_coerce(def_id, ptypes[k])
                if coerced_def_h != ""
                  result = result + coerced_def_h
                  k = k + 1
                  next
                end
              end
              result = result + compile_expr(def_id)
            else
              result = result + "0"
            end
          else
            result = result + "0"
          end
        end
      end
      k = k + 1
    end
    result
  end

  def compile_constructor_args(ci, nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
 # No call-site args. If init has parameters with defaults, fill them
 # in here `Counter.new` for `initialize(start = 0)`).
      init_ci = find_init_class(ci)
      if init_ci >= 0
        init_idx = cls_find_method_direct(init_ci, "initialize")
        if init_idx >= 0
          return compile_typed_call_args(nid, init_ci, init_idx, 0, 1)
        end
      end
      return ""
    end
    arg_ids = get_args(args_id)
 # Check if any arg is a KeywordHashNode
    has_kw = 0
    ak = 0
    while ak < arg_ids.length
      if @nd_type[arg_ids[ak]] == "KeywordHashNode"
        has_kw = 1
      end
      ak = ak + 1
    end
    if has_kw == 0
 # Positional args: compile against the inferred initializer
 # signature so defaults are filled and poly params are boxed.
      init_ci_p = find_init_class(ci)
      if init_ci_p >= 0
        init_idx_p = cls_find_method_direct(init_ci_p, "initialize")
        if init_idx_p >= 0
          return compile_typed_call_args(nid, init_ci_p, init_idx_p, 0, 1)
        end
      end
      return compile_call_args(nid)
    end
 # Extract keyword pairs — remember the expression nid too so we can
 # box it (sp_box_int etc.) when the matching ctor param is poly.
    kw_names = "".split(",")
    kw_exprs = []
    ak = 0
    while ak < arg_ids.length
      if @nd_type[arg_ids[ak]] == "KeywordHashNode"
        elems = parse_id_list(@nd_elements[arg_ids[ak]])
        ek = 0
        while ek < elems.length
          if @nd_type[elems[ek]] == "AssocNode"
            key_id = @nd_key[elems[ek]]
            if key_id >= 0
              kname = ""
              if @nd_type[key_id] == "SymbolNode"
                kname = @nd_content[key_id]
              end
              kw_names.push(kname)
              kw_exprs.push(@nd_expression[elems[ek]])
            end
          end
          ek = ek + 1
        end
      end
      ak = ak + 1
    end
 # Get init param names/types from class
    init_ci = find_init_class(ci)
    if init_ci < 0
      return compile_call_args(nid)
    end
    init_idx = cls_find_method_direct(init_ci, "initialize")
    if init_idx < 0
      return compile_call_args(nid)
    end
    pnames = cls_meth_pnames_get(init_ci, init_idx)
    ptypes = cls_meth_ptypes_get(init_ci, init_idx)
 # Kwarg-as-bundle: if the init has exactly one positional param,
 # the kwargs don't match its name, and the param's inferred type
 # is `str_poly_hash` (set by the matching analyze-side widening
 # for the same shape), build a sp_StrPolyHash from the kwargs and
 # pass it as the single arg. Sam Ruby's #530 segv: roundhouse's
 # `Article.new(title: "", body: "...")` lowered to
 # `sp_Article_new(0)` because no kwarg name matched the
 # `attrs` positional, then `attrs["title"]` dereferenced NULL.
    if pnames.length == 1 && pk_kwarg_name_matches?(kw_names, pnames) == 0 && ptypes.length >= 1 && ptypes[0] == "str_poly_hash"
      @needs_rb_value = 1
      hash_tmp_530 = new_temp
      emit("  sp_StrPolyHash *" + hash_tmp_530 + " = sp_StrPolyHash_new();")
      ki_530 = 0
      while ki_530 < kw_names.length
        key_c = "(&(\"\\xff\" \"" + kw_names[ki_530] + "\")[1])"
        emit("  sp_StrPolyHash_set(" + hash_tmp_530 + ", " + key_c + ", " + box_expr_to_poly(kw_exprs[ki_530]) + ");")
        ki_530 = ki_530 + 1
      end
      return hash_tmp_530
    end
 # Build args in param order using keyword values
    result = ""
    pk = 0
    while pk < pnames.length
      if pk > 0
        result = result + ", "
      end
      pt = "int"
      if pk < ptypes.length
        pt = ptypes[pk]
      end
      found = 0
      ki = 0
      while ki < kw_names.length
        if kw_names[ki] == pnames[pk]
          expr_id = kw_exprs[ki]
          if pt == "poly"
            result = result + box_expr_to_poly(expr_id)
          else
            result = result + compile_expr(expr_id)
          end
          found = 1
        end
        ki = ki + 1
      end
      if found == 0
        if pt == "poly"
          result = result + "sp_box_nil()"
        else
          result = result + "0"
        end
      end
      pk = pk + 1
    end
    result
  end

 # Returns 1 if any kw_name matches any pname, 0 otherwise. Helper
 # for compile_constructor_args's kwarg-as-bundle detection. Issue
 # #530.
  def pk_kwarg_name_matches?(kw_names, pnames)
    ki = 0
    while ki < kw_names.length
      pi = 0
      while pi < pnames.length
        if kw_names[ki] == pnames[pi]
          return 1
        end
        pi = pi + 1
      end
      ki = ki + 1
    end
    0
  end

  def compile_call_args(nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      return ""
    end
    arg_ids = get_args(args_id)
 # Check if multiple args may trigger GC
    gc_count = 0
    k = 0
    while k < arg_ids.length
      if expr_may_gc(arg_ids[k]) == 1
        gc_count = gc_count + 1
      end
      k = k + 1
    end
    if gc_count >= 2
      return compile_gc_safe_args(arg_ids)
    end
    result = ""
    k = 0
    while k < arg_ids.length
      if k > 0
        result = result + ", "
      end
      result = result + cast_away_volatile_arg(arg_ids[k], compile_expr(arg_ids[k]))
      k = k + 1
    end
    result
  end

 # When the enclosing function uses setjmp (top-level begin/rescue),
 # every pointer LV in main() is declared `volatile T *`. Passing
 # such a local to a function that takes plain `T *` discards the
 # volatile qualifier — gcc -Wdiscarded-qualifiers and clang's
 # -Wincompatible-pointer-types-discards-qualifiers flag it. Casting
 # away volatile is safe because the qualifier is strictly stronger
 # than what the callee asks for. Mirrors the bigint-side cast at
 # the operator dispatch (search for `(sp_Bigint *)`).
  def cast_away_volatile_arg(arg_id, val)
    if @needs_setjmp != 1
      return val
    end
    if arg_id < 0
      return val
    end
    if @nd_type[arg_id] != "LocalVariableReadNode"
      return val
    end
    vt = find_var_declared_type(@nd_name[arg_id])
    if vt == "" || type_is_pointer(vt) != 1
      return val
    end
    "(" + c_type(vt) + ")" + val
  end

  def compile_proc_call_args(nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      return "0"
    end
    arg_ids = get_args(args_id)
    if arg_ids.length == 0
      return "0"
    end
    result = ""
    k = 0
    while k < arg_ids.length
      if k > 0
        result = result + ", "
      end
      val = compile_expr(arg_ids[k])
      at = infer_type(arg_ids[k])
      if type_is_pointer(at) == 1
        result = result + "(mrb_int)(uintptr_t)(" + val + ")"
      else
        result = result + val
      end
      k = k + 1
    end
    result
  end

  def compile_gc_safe_args(arg_ids)
    temps = "".split(",")
    k = 0
    while k < arg_ids.length
      if expr_may_gc(arg_ids[k]) == 1
        tmp = new_temp
        at = infer_type(arg_ids[k])
        ct = c_type(at)
        emit("  " + ct + " " + tmp + " = " + cast_away_volatile_arg(arg_ids[k], compile_expr(arg_ids[k])) + ";")
        if type_is_pointer(at) == 1
          emit("  SP_GC_ROOT(" + tmp + ");")
        end
        temps.push(tmp)
      else
        temps.push(cast_away_volatile_arg(arg_ids[k], compile_expr(arg_ids[k])))
      end
      k = k + 1
    end
    result = ""
    k = 0
    while k < temps.length
      if k > 0
        result = result + ", "
      end
      result = result + temps[k]
      k = k + 1
    end
    result
  end

  def constructor_arg_needs_root(arg_type)
    bt = base_type(arg_type)
    if is_obj_type(bt) == 1
      return 1
    end
    if is_array_type(bt) == 1 || is_ptr_array_type(bt) == 1 || is_tuple_type(bt) == 1
      return 1
    end
    if bt == "fiber" || bt == "bigint" || bt == "lambda" || bt == "poly_array"
      return 1
    end
    0
  end

  def root_constructor_arg_if_needed(expr_id, expr, arg_type, later_arg_may_gc)
    if constructor_arg_needs_root(arg_type) == 0
      return expr
    end
    may_gc = 0
    if expr_id >= 0
      may_gc = expr_may_gc(expr_id)
    end
    if may_gc == 0 && later_arg_may_gc == 0
      return expr
    end
    @needs_gc = 1
    tmp = new_temp
    emit("  " + c_type(arg_type) + " " + tmp + " = " + expr + ";")
    emit("  SP_GC_ROOT(" + tmp + ");")
    tmp
  end

 # compile_typed_call_args for callers that hold the owner / method
 # names rather than pre-resolved indices. Untyped fallback on miss.
  def compile_typed_call_args_by_name(nid, owner, mname, omit_trailing = 0)
    owner_ci = find_class_idx(owner)
    return compile_call_args(nid) if owner_ci < 0
    midx = cls_find_method_direct(owner_ci, mname)
    return compile_call_args(nid) if midx < 0
    compile_typed_call_args(nid, owner_ci, midx, omit_trailing)
  end

  def compile_typed_call_args(nid, target_ci, target_midx, omit_trailing, root_constructor_args = 0)
 # Like compile_call_args but casts arguments to match target method param
 # types AND fills in defaults from @cls_meth_defaults for trailing
 # parameters the caller omitted . Returns "" only when the
 # method takes no parameters at all.
 #
 # `omit_trailing` is the number of trailing param slots to leave out
 # entirely — block-forwarding call sites pass 1 so the &block slot
 # isn't default-padded with "0" (the actual proc is appended by the
 # caller after this returns).
    args_id = @nd_arguments[nid]
    raw_arg_ids = []
    if args_id >= 0
      raw_arg_ids = get_args(args_id)
    end
    all_defaults = @cls_meth_defaults[target_ci].split("|")
    ptypes = cls_meth_ptypes_get(target_ci, target_midx)
    pnames_t = cls_meth_pnames_get(target_ci, target_midx)
    defaults = "".split(",")
    if target_midx < all_defaults.length
      defaults = all_defaults[target_midx].split(",")
    end
 # Pull out kwargs (KeywordHashNode) from the positional stream
 # so the loop below can map `key: value` to the matching named
 # param. Without this, a trailing `head(204, content_type: "x")`
 # call-site widening would land the whole keyword hash on the
 # next positional slot (ptype[1]) and emit garbage for the
 # actual content_type kwarg slot.
    arg_ids = []
    kw_name_to_arg = "".split(",")
    kw_name_keys  = "".split(",")
    kak = 0
    while kak < raw_arg_ids.length
      if @nd_type[raw_arg_ids[kak]] == "KeywordHashNode"
        kelems = parse_id_list(@nd_elements[raw_arg_ids[kak]])
        kei = 0
        while kei < kelems.length
          if @nd_type[kelems[kei]] == "AssocNode"
            kkey = @nd_key[kelems[kei]]
            kval = @nd_expression[kelems[kei]]
            if kkey >= 0 && kval >= 0 && @nd_type[kkey] == "SymbolNode"
              knm = @nd_content[kkey]
              if knm == ""
                knm = @nd_name[kkey]
              end
              kw_name_keys.push(knm)
              kw_name_to_arg.push(kval.to_s)
            end
          end
          kei = kei + 1
        end
      else
        arg_ids.push(raw_arg_ids[kak])
      end
      kak = kak + 1
    end
 # Drop the trailing slots the caller will fill explicitly (the
 # &block slot when block-forwarding) — otherwise a surplus
 # positional arg would mis-cast against the omitted slot's type
 # and the loop's default-padding would emit "0" for the slot the
 # caller is about to fill itself.
    if omit_trailing > 0
      kept = []
      pk = 0
      limit = ptypes.length - omit_trailing
      if limit < 0
        limit = 0
      end
      while pk < limit
        kept.push(ptypes[pk])
        pk = pk + 1
      end
      ptypes = kept
    end
 # Resolve each named param against the kwarg map by injecting
 # the matched kwarg's value-id into arg_ids[slot] so the loop's
 # positional path picks it up. Same effect as
 # compile_call_args_with_defaults's kwarg routing.
    if kw_name_keys.length > 0
      pkk = 0
      while pkk < pnames_t.length
        kwi = 0
        while kwi < kw_name_keys.length
          if kw_name_keys[kwi] == pnames_t[pkk]
            while arg_ids.length <= pkk
              arg_ids.push(-1)
            end
            arg_ids[pkk] = kw_name_to_arg[kwi].to_i
          end
          kwi = kwi + 1
        end
        pkk = pkk + 1
      end
    end
    total = ptypes.length
    if arg_ids.length > total
      total = arg_ids.length
    end
    if total == 0
      return ""
    end
    later_arg_may_gc = []
    if root_constructor_args == 1
      gc_expr_ids = []
      gk = 0
      while gk < total
        gc_expr_id = -1
        if gk < arg_ids.length
          gc_expr_id = arg_ids[gk]
        else
          if gk < defaults.length
            gc_expr_id = defaults[gk].to_i
          end
        end
        gc_expr_ids.push(gc_expr_id)
        gk = gk + 1
      end
      seen_gc = 0
      gk = total - 1
      while gk >= 0
        later_arg_may_gc[gk] = seen_gc
        gc_expr_id = gc_expr_ids[gk]
        if gc_expr_id >= 0 && expr_may_gc(gc_expr_id) == 1
          seen_gc = 1
        end
        gk = gk - 1
      end
    end
    result = ""
    pcname = ""
    k = 0
    while k < total
      if k > 0
        result = result + ", "
      end
      if k < arg_ids.length && arg_ids[k] >= 0
        at = infer_type(arg_ids[k])
        if k < ptypes.length
          pt = ptypes[k]
          pt_base = base_type(pt)
          if pt_base == "poly" || pt_base == "string" || is_array_type(pt_base) == 1 || (at == "poly" && is_obj_type(pt_base) == 1)
            aexpr = compile_expr_for_expected_type(arg_ids[k], pt)
            if root_constructor_args == 1
              aexpr = root_constructor_arg_if_needed(arg_ids[k], aexpr, pt, later_arg_may_gc[k])
            end
            result = result + aexpr
            k = k + 1
            next
          end
          aexpr = compile_expr(arg_ids[k])
          if at == "int"
            if is_obj_type(pt) == 1
 # Cast int to object pointer. Strip the nullable `?`
 # marker before deriving the C class name — a param
 # type like `obj_BoundMethod?` would otherwise produce
 # `(sp_BoundMethod? *)0` and gcc chokes on the stray `?`.
              pt_base = pt
              if is_nullable_type(pt) == 1
                pt_base = base_type(pt)
              end
              pcname = pt_base[4, pt_base.length - 4]
              aexpr = "(sp_" + pcname + " *)" + aexpr
            end
          end
          if is_obj_type(at) == 1
            if pt == "int"
 # Cast object pointer to int
              aexpr = "(mrb_int)" + aexpr
            end
          end
        else
          aexpr = compile_expr(arg_ids[k])
          pt = at
        end
        if root_constructor_args == 1
          aexpr = root_constructor_arg_if_needed(arg_ids[k], aexpr, pt, later_arg_may_gc[k])
        end
        result = result + aexpr
      else
 # Caller omitted this trailing arg — emit the method's
 # default expression. The default was authored in the
 # callee's class scope, so any `self` / `@ivar` references
 # need to resolve against the call's receiver, not the
 # caller's self. Switch @current_class_idx and override
 # `self_arrow` for the duration of the inline expansion.
        if k < defaults.length
          def_id = defaults[k].to_i
          if def_id >= 0
            recv_for_default = @nd_receiver[nid]
            saved_ci = @current_class_idx
            saved_override = @self_override
            if recv_for_default >= 0
 # Materialize the recv into a C expression. Wrap in
 # parens so any cast/operator chain stays self-
 # contained when consumed as `(<recv>)->iv_X` (via
 # `self_arrow`) or as the first arg of a same-class
 # method call (via `self_expr`).
              recv_c = compile_expr_gc_rooted(recv_for_default)
 # Cast the recv expression to the target class's
 # pointer type when the static type of the recv is not
 # already that pointer (e.g. an inherited @apu ivar
 # whose slot was inferred as mrb_int but the runtime
 # value is sp_Optcarrot_APU *). Without the cast, an
 # `@cpu` reference inside the default expression
 # lowers to `(<recv>)->iv_cpu` which gcc rejects when
 # `<recv>` is mrb_int.
              recv_t = infer_type(recv_for_default)
              target_obj_t = "obj_" + @cls_names[target_ci]
              if base_type(recv_t) != target_obj_t && @cls_is_value_type[target_ci] != 1
                recv_c = "(sp_" + @cls_names[target_ci] + " *)" + recv_c
              end
              @self_override = "(" + recv_c + ")"
              @current_class_idx = target_ci
            end
            if k < ptypes.length
              aexpr = compile_expr_for_expected_type(def_id, ptypes[k])
              if root_constructor_args == 1
                aexpr = root_constructor_arg_if_needed(def_id, aexpr, ptypes[k], later_arg_may_gc[k])
              end
              result = result + aexpr
            else
              aexpr = compile_expr(def_id)
              if root_constructor_args == 1
                aexpr = root_constructor_arg_if_needed(def_id, aexpr, infer_type(def_id), later_arg_may_gc[k])
              end
              result = result + aexpr
            end
            @current_class_idx = saved_ci
            @self_override = saved_override
          else
            if k < ptypes.length && ptypes[k] == "poly"
              result = result + "sp_box_nil()"
            else
              result = result + "0"
            end
          end
        else
          if k < ptypes.length && ptypes[k] == "poly"
            result = result + "sp_box_nil()"
          else
            result = result + "0"
          end
        end
      end
      k = k + 1
    end
    result
  end

  def find_method_owner(ci, mname)
    if ci < 0
      return ""
    end
    mnames = @cls_meth_names[ci].split(";")
    j = 0
    while j < mnames.length
      if mnames[j] == mname
        return @cls_names[ci]
      end
      j = j + 1
    end
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        return find_method_owner(pi, mname)
      end
    end
    ""
  end

 # `recv OP rhs` lowering for an obj-typed receiver. When the
 # receiver's class (or an ancestor) defines `op` as a user method,
 # returns the C expression `sp_<owner>_<op>(<recv_c>, <rhs_c>)`.
 # Returns "" when no dispatch applies (caller falls back to its
 # inline path, or to `warn_unresolved_call`).
  def obj_op_dispatch_expr(recv_t, recv_c, op, rhs_c)
    if is_obj_type(recv_t) == 0
      return ""
    end
    cname = recv_t[4, recv_t.length - 4]
    ci = find_class_idx(cname)
    if ci < 0
      return ""
    end
    owner = find_method_owner(ci, op)
    if owner == ""
      warn_unresolved_call(op, "obj_" + cname)
      return ""
    end
    cast = ""
    if owner != cname
      cast = "(sp_" + owner + " *)"
    end
    "sp_" + owner + "_" + sanitize_name(op) + "(" + cast + recv_c + ", " + rhs_c + ")"
  end

  def if_branch_has_multi_stmt(body)
    if body < 0
      return 0
    end
    if get_stmts(body).length > 1
      return 1
    end
    0
  end

 # Assign the value of an if-arm body to a temp, executing any
 # leading side-effect statements before the assignment. Body
 # convention: stmts[0..n-2] run for their side-effects;
 # stmts[n-1] supplies the arm's value. Empty/missing body → "0".
  def compile_if_arm_to_tmp(body, tmp, unified_t)
    if body < 0
      emit("  " + tmp + " = 0;")
      return
    end
    stmts = get_stmts(body)
    if stmts.length == 0
      emit("  " + tmp + " = 0;")
      return
    end
    i = 0
    while i < stmts.length - 1
      compile_stmt(stmts[i])
      i = i + 1
    end
    last_id = stmts.last
    val = compile_expr(last_id)
    if unified_t == "poly" && infer_type(last_id) != "poly"
      val = box_value_to_poly(infer_type(last_id), val)
    end
    emit("  " + tmp + " = " + val + ";")
  end

  def compile_if_expr(nid)
    cond = compile_cond_expr(@nd_predicate[nid])
    unified_t = infer_type(nid)
    body = @nd_body[nid]
    sub = @nd_subsequent[nid]

 # Side-effect-aware path: when any branch holds more than one
 # statement, the leading stmts must execute conditionally. The
 # plain ternary form drops them. Emit a real if-statement that
 # assigns to a temp and return the temp as the expression value.
 # Elsif chains recurse — the inner call returns either a temp or
 # a ternary string, both valid expressions.
    has_then_multi = if_branch_has_multi_stmt(body)
    has_else_multi = 0
    if sub >= 0 && @nd_type[sub] == "ElseNode"
      has_else_multi = if_branch_has_multi_stmt(@nd_body[sub])
    end
    if has_then_multi == 1 || has_else_multi == 1
      tmp = new_temp
      emit("  " + c_type(unified_t) + " " + tmp + ";")
      emit("  if (" + cond + ") {")
      @indent = @indent + 1
      compile_if_arm_to_tmp(body, tmp, unified_t)
      @indent = @indent - 1
      emit("  } else {")
      @indent = @indent + 1
      if sub >= 0 && @nd_type[sub] == "ElseNode"
        compile_if_arm_to_tmp(@nd_body[sub], tmp, unified_t)
      elsif sub >= 0
        sub_val = compile_if_expr(sub)
        sub_t = infer_type(sub)
        if unified_t == "poly" && sub_t != "poly"
          sub_val = box_value_to_poly(sub_t, sub_val)
        end
        emit("  " + tmp + " = " + sub_val + ";")
      else
        emit("  " + tmp + " = 0;")
      end
      @indent = @indent - 1
      emit("  }")
      return tmp
    end

 # Fast path: every branch is at most one statement, so the
 # whole if-expression collapses to a C ternary.
    then_val = "0"
    then_t = "nil"
    if body >= 0
      stmts = get_stmts(body)
      if stmts.length > 0
        then_t = infer_type(stmts.last)
        then_val = compile_expr(stmts.last)
      end
    end
    else_val = "0"
    else_t = "nil"
    if sub >= 0
      if @nd_type[sub] == "ElseNode"
        eb = @nd_body[sub]
        if eb >= 0
          es = get_stmts(eb)
          if es.length > 0
            else_t = infer_type(es.last)
            else_val = compile_expr(es.last)
          end
        end
      else
        else_t = infer_type(sub)
        else_val = compile_if_expr(sub)
      end
    end
 # When the if-expression's unified type is `poly` but the
 # branches have concrete types, the raw C ternary
 # `(cond ? sp_IntArray * : sp_PtrArray *)` mixes pointer types
 # and the C compiler rejects the assignment to sp_RbVal.
 # Box each branch into sp_RbVal so the ternary's two arms
 # share a type. Keeps the static infer_type(IfNode) → poly
 # contract that downstream dispatch (e.g. .each on poly recv)
 # relies on.
    if unified_t == "poly"
      if then_t != "poly"
        then_val = box_value_to_poly(then_t, then_val)
      end
      if else_t != "poly"
        else_val = box_value_to_poly(else_t, else_val)
      end
    end
    "(" + cond + " ? " + then_val + " : " + else_val + ")"
  end

  def compile_unless_expr(nid)
    cond = compile_cond_expr(@nd_predicate[nid])
    then_val = "0"
    then_t = "nil"
    body = @nd_body[nid]
    if body >= 0
      stmts = get_stmts(body)
      if stmts.length > 0
        then_t = infer_type(stmts.last)
        then_val = compile_expr(stmts.last)
      end
    end
    unified_t = infer_type(nid)
    else_val = c_return_default(then_t)
    if unified_t == "poly"
      if then_t != "poly"
        then_val = box_value_to_poly(then_t, then_val)
      end
      else_val = box_value_to_poly("nil", "0")
    end
    "(!" + cond + " ? " + then_val + " : " + else_val + ")"
  end

 # Compile an `ArrayNode` literal as `sp_PolyArray *`, regardless
 # of the inferred elem type. Used by the nested-array path in
 # the poly_array branch so 3D-and-deeper arrays preserve cls_id
 # tags through every level (e.g. an inner `[1,2,3]` ends up
 # boxed via `sp_box_int_array` so the dispatch can still
 # `sp_IntArray_get` on it).
  def compile_array_literal_as_poly(nid)
    @needs_gc = 1
    @needs_rb_value = 1
    elems = parse_id_list(@nd_elements[nid])
    tmp = new_temp
    emit("  sp_PolyArray *" + tmp + " = sp_PolyArray_new();")
    k = 0
    while k < elems.length
      eid = elems[k]
      et = infer_type(eid)
      if @nd_type[eid] == "ArrayNode" && (is_ptr_array_type(et) == 1 || et == "poly_array")
        inner = compile_array_literal_as_poly(eid)
        emit("  sp_PolyArray_push(" + tmp + ", sp_box_poly_array(" + inner + "));")
      elsif is_ptr_array_type(et) == 1
 # Non-ArrayNode whose static type is a typed `<X>_ptr_array`
 # (e.g. `Array.new(N) { ... }` returning int_array_ptr_array).
 # Convert at runtime so each inner element keeps its real
 # cls_id (sp_box_int_array etc.) — `arr[i][j][k]` chains
 # correctly through the next-level dispatch.
        val = compile_expr(eid)
        inner_t = ptr_array_elem_type(et)
        conv = new_temp
        ii = new_temp
        emit("  sp_PolyArray *" + conv + " = sp_PolyArray_new();")
        emit("  for (mrb_int " + ii + " = 0; " + ii + " < sp_PtrArray_length(" + val + "); " + ii + "++) {")
        inner_get = "(" + c_type(inner_t) + ")sp_PtrArray_get(" + val + ", " + ii + ")"
        emit("    sp_PolyArray_push(" + conv + ", " + box_value_to_poly(inner_t, inner_get) + ");")
        emit("  }")
        emit("  sp_PolyArray_push(" + tmp + ", sp_box_poly_array(" + conv + "));")
      else
        val = compile_expr(eid)
        emit("  sp_PolyArray_push(" + tmp + ", " + box_value_to_poly(et, val) + ");")
      end
      k = k + 1
    end
    tmp
  end

  def compile_array_literal(nid)
    @needs_gc = 1
    elems = parse_id_list(@nd_elements[nid])
    if elems.length == 0
      @needs_int_array = 1
      return "sp_IntArray_new()"
    end
    compile_array_literal_from_ids(elems, array_literal_arr_type(elems))
  end

 # Pick the array type for a non-empty `[e0, e1, ...]` literal. Spinel's
 # general infer_array_elem_type returns `int_array` when no other arm
 # claims the shape, which silently swallows raw-pointer elements
 # (FFI `:ptr` returns) into an IntArray slot — every push then fires
 # `-Wint-conversion` because mrb_int isn't void*. Check that case up
 # front: if every element infers as `ptr`, lower the literal directly
 # to `ptr_ptr_array` so codegen picks sp_PtrArray + noscan. Otherwise
 # defer to the existing inference cascade.
  def array_literal_arr_type(elems)
    if elems.length > 0 && infer_type(elems[0]) == "ptr"
      all_ptr = 1
      k = 1
      while k < elems.length
        if infer_type(elems[k]) != "ptr"
          all_ptr = 0
        end
        k = k + 1
      end
      if all_ptr == 1
        return "ptr_ptr_array"
      end
    end
    infer_array_elem_type_from_ids(elems)
  end

 # Body of compile_array_literal, parameterised on the list of value
 # node ids and the resolved array element type. Lets a HashNode
 # whose keys are 0..N-1 (lowered to Array) reuse the same emission
 # paths by feeding in the AssocNode rhs ids without needing an
 # ArrayNode wrapper.
  def compile_array_literal_from_ids(elems, arr_type)
    @needs_gc = 1
    if is_tuple_type(arr_type) == 1
      name = tuple_c_name(arr_type)
      tmp = new_temp
      parts = tuple_elem_types_str(arr_type).split(",")
      emit("  " + name + " *" + tmp + " = (" + name + " *)sp_gc_alloc(sizeof(" + name + "), NULL, " + tuple_scan_name(arr_type) + ");")
      k = 0
      while k < elems.length && k < parts.length
        emit("  " + tmp + "->_" + k.to_s + " = " + compile_expr(elems[k]) + ";")
        k = k + 1
      end
      return tmp
    end
    if arr_type == "str_array"
      @needs_str_array = 1
      tmp = new_temp
      emit("  sp_StrArray *" + tmp + " = sp_StrArray_new();")
      k = 0
      while k < elems.length
        emit("  sp_StrArray_push(" + tmp + ", " + compile_expr(elems[k]) + ");")
        k = k + 1
      end
      return tmp
    end
    if arr_type == "poly_array"
      @needs_rb_value = 1
      tmp = new_temp
      emit("  sp_PolyArray *" + tmp + " = sp_PolyArray_new();")
      k = 0
      while k < elems.length
        et = infer_type(elems[k])
 # 3D+ shape: when the element is itself a typed
 # `<X>_ptr_array` that came from a nested ArrayNode, the
 # default `compile_array_literal` for that element would
 # emit a typed sp_PtrArray and `sp_box_ptr_array` would
 # erase the elem type (cls_id PTR_ARRAY). Recompile the
 # nested literal as poly_array so the next-level dispatch
 # sees `cls_id == POLY_ARRAY` and recurses with each
 # innermost typed array still tagged correctly.
        if @nd_type[elems[k]] == "ArrayNode" && (is_ptr_array_type(et) == 1 || et == "poly_array")
          val = compile_array_literal_as_poly(elems[k])
          emit("  sp_PolyArray_push(" + tmp + ", sp_box_poly_array(" + val + "));")
        elsif is_ptr_array_type(et) == 1
 # Same 3D+ erasure but the element is a non-ArrayNode
 # expression (e.g. `Array.new(N) { ... }` returning a
 # typed `<X>_ptr_array`). compile_array_literal_as_poly
 # only walks ArrayNodes — emit a runtime conversion that
 # iterates the typed PtrArray and tags each inner with
 # its real cls_id (sp_box_int_array etc.).
          val = compile_expr(elems[k])
          inner_t = ptr_array_elem_type(et)
          conv = new_temp
          ii = new_temp
          emit("  sp_PolyArray *" + conv + " = sp_PolyArray_new();")
          emit("  for (mrb_int " + ii + " = 0; " + ii + " < sp_PtrArray_length(" + val + "); " + ii + "++) {")
          inner_get = "(" + c_type(inner_t) + ")sp_PtrArray_get(" + val + ", " + ii + ")"
          emit("    sp_PolyArray_push(" + conv + ", " + box_value_to_poly(inner_t, inner_get) + ");")
          emit("  }")
          emit("  sp_PolyArray_push(" + tmp + ", sp_box_poly_array(" + conv + "));")
        else
          val = compile_expr(elems[k])
          emit("  sp_PolyArray_push(" + tmp + ", " + box_value_to_poly(et, val) + ");")
        end
        k = k + 1
      end
      return tmp
    end
    if arr_type == "float_array"
      @needs_float_array = 1
      tmp = new_temp
      emit("  sp_FloatArray *" + tmp + " = sp_FloatArray_new();")
      k = 0
      while k < elems.length
        emit("  sp_FloatArray_push(" + tmp + ", " + compile_expr(elems[k]) + ");")
        k = k + 1
      end
      return tmp
    end
    if is_ptr_array_type(arr_type) == 1
      tmp = new_temp
 # Raw `:ptr` elements (FFI returns, dlopen handles, ...) don't
 # carry sp_gc_hdr, so the default GC-scanning PtrArray would crash
 # when the collector tried to walk element headers. Pick the
 # noscan constructor — the array header is still GC-tracked but
 # element slots are treated as opaque pointer-sized values.
      if ptr_array_elem_type(arr_type) == "ptr"
        emit("  sp_PtrArray *" + tmp + " = sp_PtrArray_new_noscan();")
      else
        emit("  sp_PtrArray *" + tmp + " = sp_PtrArray_new();")
      end
 # Root the freshly-allocated PtrArray before compiling element
 # expressions. Each element is typically Klass.new(...), and that
 # call allocates → may trigger GC. Without this, GC sees `tmp` as
 # unreachable and frees it, leaving a dangling pointer that the
 # subsequent push (and the eventual ivar assignment) writes through.
      emit("  SP_GC_ROOT(" + tmp + ");")
      k = 0
      while k < elems.length
        emit("  sp_PtrArray_push(" + tmp + ", " + compile_expr(elems[k]) + ");")
        k = k + 1
      end
      return tmp
    end
    @needs_int_array = 1
    tmp = new_temp
    emit("  sp_IntArray *" + tmp + " = sp_IntArray_new();")
    k = 0
    while k < elems.length
      eid = elems[k]
 # SplatNode in an Array literal — `[*range]` or `[*arr]` —
 # expands the inner expression's elements into the array.
 # Without this branch, compile_expr lowered the splat to a
 # default value (e.g., the lower bound of a Range), so
 # `[*0..4096]` ended up as just `[0]`.
      if @nd_type[eid] == "SplatNode"
        inner = @nd_expression[eid]
        it = infer_type(inner)
 # Root tmp so a sp_IntArray_push grow inside the splat loop
 # can't sweep the half-built array. Hoist range / source
 # expressions to a temp so side effects (method calls in the
 # bound, chained recv) fire exactly once.
        emit("  SP_GC_ROOT(" + tmp + ");")
        if @nd_type[inner] == "RangeNode"
          lo = compile_expr(@nd_left[inner])
          hi_expr = compile_expr(@nd_right[inner])
          hi = new_temp
          emit("  mrb_int " + hi + " = " + hi_expr + ";")
          cmp = range_excl_end(inner) == 1 ? "<" : "<="
          ii = new_temp
          emit("  for (mrb_int " + ii + " = " + lo + "; " + ii + " " + cmp + " " + hi + "; " + ii + "++) {")
          emit("    sp_IntArray_push(" + tmp + ", " + ii + ");")
          emit("  }")
        elsif it == "int_array" || it == "sym_array"
          src_expr = compile_expr(inner)
          src = new_temp
          emit("  sp_IntArray *" + src + " = " + src_expr + ";")
          emit("  SP_GC_ROOT(" + src + ");")
          ii = new_temp
          emit("  for (mrb_int " + ii + " = 0; " + ii + " < sp_IntArray_length(" + src + "); " + ii + "++) {")
          emit("    sp_IntArray_push(" + tmp + ", sp_IntArray_get(" + src + ", " + ii + "));")
          emit("  }")
        end
        k = k + 1
        next
      end
      ev = compile_expr(eid)
      et = infer_type(eid)
 # Unbox poly values when pushing into a (concrete) IntArray.
 # An ArrayNode literal whose elements are poly (e.g.
 # `[addr]` where addr's recorded type is sp_RbVal) needs the
 # int payload extracted via `.v.i`. Without this, the C
 # compiler rejects the push with "incompatible type".
      if et == "poly"
        ev = "(" + ev + ").v.i"
      end
      emit("  sp_IntArray_push(" + tmp + ", " + ev + ");")
      k = k + 1
    end
    tmp
  end

 # HashNode literal whose keys are 0..N-1 lowered to an Array
 # literal. Reuses compile_array_literal_from_ids by mapping each
 # AssocNode to its rhs value id.
  def compile_int_keyed_hash_as_array(nid)
    @needs_gc = 1
    elems = parse_id_list(@nd_elements[nid])
    vids = []
    k = 0
    while k < elems.length
      vids.push(@nd_expression[elems[k]])
      k = k + 1
    end
    compile_array_literal_from_ids(vids, infer_array_elem_type_from_ids(vids))
  end

  def compile_hash_literal(nid)
    @needs_gc = 1
    if is_int_array_lowered_hash(nid) == 1
      return compile_int_keyed_hash_as_array(nid)
    end
    elems = parse_id_list(@nd_elements[nid])
    if elems.length == 0
      @needs_str_int_hash = 1
      return "sp_StrIntHash_new()"
    end
    ht = infer_hash_val_type(nid)
    if ht == "int_str_hash"
      @needs_int_str_hash = 1
      tmp = new_temp
      emit("  sp_IntStrHash *" + tmp + " = sp_IntStrHash_new();")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          emit("  sp_IntStrHash_set(" + tmp + ", " + compile_expr(@nd_key[el]) + ", " + compile_expr(@nd_expression[el]) + ");")
        end
      }
      return tmp
    end
    if ht == "str_str_hash"
      @needs_str_str_hash = 1
      tmp = new_temp
      emit("  sp_StrStrHash *" + tmp + " = sp_StrStrHash_new();")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          vt = infer_type(@nd_expression[el])
          val = compile_expr(@nd_expression[el])
          if vt == "int"
            val = "sp_int_to_s(" + val + ")"
          else
            if vt == "float"
              val = "sp_float_to_s(" + val + ")"
            else
              if vt == "bool"
                val = "(" + val + " ? \"true\" : \"false\")"
              end
            end
          end
          emit("  sp_StrStrHash_set(" + tmp + ", " + compile_expr_as_string(@nd_key[el]) + ", " + val + ");")
        end
      }
      return tmp
    end
    if ht == "sym_int_hash"
      @needs_sym_int_hash = 1
      tmp = new_temp
      emit("  sp_SymIntHash *" + tmp + " = sp_SymIntHash_new();")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          emit("  sp_SymIntHash_set(" + tmp + ", " + compile_expr(@nd_key[el]) + ", " + compile_expr(@nd_expression[el]) + ");")
        end
      }
      return tmp
    end
    if ht == "sym_str_hash"
      @needs_sym_str_hash = 1
      tmp = new_temp
      emit("  sp_SymStrHash *" + tmp + " = sp_SymStrHash_new();")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          emit("  sp_SymStrHash_set(" + tmp + ", " + compile_expr(@nd_key[el]) + ", " + compile_expr(@nd_expression[el]) + ");")
        end
      }
      return tmp
    end
    if ht == "sym_poly_hash"
      @needs_rb_value = 1
      tmp = new_temp
      emit("  sp_SymPolyHash *" + tmp + " = sp_SymPolyHash_new();")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          emit("  sp_SymPolyHash_set(" + tmp + ", " + compile_expr(@nd_key[el]) + ", " + box_expr_to_poly(@nd_expression[el]) + ");")
        end
      }
      return tmp
    end
    if ht == "str_poly_hash"
      @needs_rb_value = 1
      tmp = new_temp
      emit("  sp_StrPolyHash *" + tmp + " = sp_StrPolyHash_new();")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          emit("  sp_StrPolyHash_set(" + tmp + ", " + compile_expr_as_string(@nd_key[el]) + ", " + box_expr_to_poly(@nd_expression[el]) + ");")
        end
      }
      return tmp
    end
    if ht == "poly_poly_hash"
 # Mixed-shape keys (e.g. `{ 0 => false, a: 1 }`). Both key
 # and value carry their own tag; box each at the assoc site.
 # Issue #536.
      @needs_rb_value = 1
      @needs_poly_poly_hash = 1
      tmp = new_temp
      emit("  sp_PolyPolyHash *" + tmp + " = sp_PolyPolyHash_new();")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          emit("  sp_PolyPolyHash_set(" + tmp + ", " + box_expr_to_poly(@nd_key[el]) + ", " + box_expr_to_poly(@nd_expression[el]) + ");")
        end
      }
      return tmp
    end
    @needs_str_int_hash = 1
    tmp = new_temp
    emit("  sp_StrIntHash *" + tmp + " = sp_StrIntHash_new();")
    elems.each { |el|
      if @nd_type[el] == "AssocNode"
        emit("  sp_StrIntHash_set(" + tmp + ", " + compile_expr_as_string(@nd_key[el]) + ", " + compile_expr(@nd_expression[el]) + ");")
      end
    }
    tmp
  end

 # ---- Statement compiler ----
  def compile_stmt(nid)
    if nid < 0
      return
    end
    t = @nd_type[nid]
    if t == "UnsupportedNode"
 # Same loud-error path as compile_expr's UnsupportedNode arm.
      $stderr.puts "Spinel: cannot compile " + @nd_content[nid] + " at line " + @nd_value[nid].to_s + " (unsupported Ruby syntax)"
      exit(1)
    end
    if t == "MultiWriteNode"
      compile_multi_write(nid)
      return
    end
    if t == "GlobalVariableWriteNode"
      gname = @nd_name[nid]
      if gname != "$stderr" && gname != "$stdout" && gname != "$?"
        cname = sanitize_gvar(gname)
        val = compile_expr(@nd_expression[nid])
        emit("  " + cname + " = " + val + ";")
        return
      end
    end
    if t == "GlobalVariableOperatorWriteNode"
 # `$x += val`, `$x -= val`, etc. Mirrors LocalVariableOperatorWriteNode
 # for the storage path (sanitize_gvar instead of fiber_var_ref).
      op = @nd_binop[nid]
      val = compile_expr(@nd_expression[nid])
      cname = sanitize_gvar(@nd_name[nid])
      if op == "+"
        emit("  " + cname + " += " + val + ";")
      end
      if op == "-"
        emit("  " + cname + " -= " + val + ";")
      end
      if op == "*"
        emit("  " + cname + " *= " + val + ";")
      end
      if op == "/"
        emit("  " + cname + " = sp_idiv(" + cname + ", " + val + ");")
      end
      if op == "%"
        emit("  " + cname + " = sp_imod(" + cname + ", " + val + ");")
      end
      if op == "<<"
        emit("  " + cname + " <<= " + val + ";")
      end
      if op == ">>"
        emit("  " + cname + " >>= " + val + ";")
      end
      if op == "&"
        emit("  " + cname + " &= " + val + ";")
      end
      if op == "|"
        emit("  " + cname + " |= " + val + ";")
      end
      if op == "^"
        emit("  " + cname + " ^= " + val + ";")
      end
      return
    end
    if t == "GlobalVariableOrWriteNode"
 # `$x ||= val`. Short-circuit: only evaluate RHS when LHS is
 # falsy. compile_expr can emit prerequisite statements; running
 # it inside the C `if` block ensures those side effects only
 # fire on the assign branch. Note: in Ruby, an undefined $-var
 # reads as nil, which is falsy in C terms, so the `if (!cname)`
 # guard fires both for never-assigned and assigned-to-falsy.
      cname = sanitize_gvar(@nd_name[nid])
      emit("  if (!(" + cname + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("    " + cname + " = " + val + ";")
      emit("  }")
      return
    end
    if t == "GlobalVariableAndWriteNode"
 # `$x &&= val`. Short-circuit: only evaluate RHS when LHS is
 # truthy. compile_expr can emit prerequisite statements; running
 # it inside the C `if` block keeps those side effects on the
 # assign branch only. Mirror of OrWrite, condition inverted.
      cname = sanitize_gvar(@nd_name[nid])
      emit("  if (" + cname + ") {")
      val = compile_expr(@nd_expression[nid])
      emit("    " + cname + " = " + val + ";")
      emit("  }")
      return
    end
    if t == "ClassVariableWriteNode"
 # `@@x = val` inside class body or method. Storage is the
 # per-(class,name) C global cvar_<ClassName>_<var> registered
 # by collect_cvars during the pre-pass. If the cvar wasn't seen
 # there (e.g. inside a class-method that pre-pass missed) we
 # register defensively.
      qname = cvar_qname(@current_class_idx, @nd_name[nid])
      val = compile_expr(@nd_expression[nid])
      val_t = infer_type(@nd_expression[nid])
      register_cvar(qname, val_t)
      emit("  cvar_" + qname + " = " + val + ";")
      return
    end
    if t == "ClassVariableOperatorWriteNode"
 # `@@x op= val` -- desugar to `@@x = @@x op val`. Mirrors
 # GlobalVariableOperatorWriteNode and the instance-var
 # variant. Same storage path as ClassVariableWriteNode.
      qname = cvar_qname(@current_class_idx, @nd_name[nid])
      val = compile_expr(@nd_expression[nid])
      val_t = infer_type(@nd_expression[nid])
      register_cvar(qname, val_t)
      cname = "cvar_" + qname
      op = @nd_binop[nid]
      if op == "+"
        emit("  " + cname + " += " + val + ";")
      elsif op == "-"
        emit("  " + cname + " -= " + val + ";")
      elsif op == "*"
        emit("  " + cname + " *= " + val + ";")
      elsif op == "/"
        emit("  " + cname + " = sp_idiv(" + cname + ", " + val + ");")
      elsif op == "%"
        emit("  " + cname + " = sp_imod(" + cname + ", " + val + ");")
      elsif op == "<<"
        emit("  " + cname + " <<= " + val + ";")
      elsif op == ">>"
        emit("  " + cname + " >>= " + val + ";")
      elsif op == "&"
        emit("  " + cname + " &= " + val + ";")
      elsif op == "|"
        emit("  " + cname + " |= " + val + ";")
      elsif op == "^"
        emit("  " + cname + " ^= " + val + ";")
      else
        emit("  " + cname + " = " + cname + " " + op + " " + val + ";")
      end
      return
    end
    if t == "ClassVariableOrWriteNode"
 # `@@x ||= val` -- evaluate rhs only when @@x is falsy.
 # Mirror of GlobalVariableOrWriteNode.
      qname = cvar_qname(@current_class_idx, @nd_name[nid])
      val_t = infer_type(@nd_expression[nid])
      register_cvar(qname, val_t)
      cname = "cvar_" + qname
      emit("  if (!(" + cname + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("    " + cname + " = " + val + ";")
      emit("  }")
      return
    end
    if t == "ClassVariableAndWriteNode"
 # `@@x &&= val` -- evaluate rhs only when @@x is truthy.
      qname = cvar_qname(@current_class_idx, @nd_name[nid])
      val_t = infer_type(@nd_expression[nid])
      register_cvar(qname, val_t)
      cname = "cvar_" + qname
      emit("  if (" + cname + ") {")
      val = compile_expr(@nd_expression[nid])
      emit("    " + cname + " = " + val + ";")
      emit("  }")
      return
    end
    if t == "RedoNode"
 # `redo` -- jump to the top of the current iteration without
 # advancing the iterator or re-evaluating the loop guard. The
 # loop emitter installs a label via push_redo_label /
 # emit_redo_label; we goto the innermost.
      if @redo_label_stack.length == 0
        $stderr.puts "Spinel: `redo` outside of a loop"
        exit(1)
      end
      lbl = @redo_label_stack.last
      emit("  goto " + lbl + ";")
      return
    end
    if t == "AliasGlobalVariableNode"
 # `alias $copy $orig` -- compile-time only. collect_all
 # already populated @galias_*; references through
 # sanitize_gvar / scan_features / infer_type pick up the
 # rewrite. Nothing to emit at runtime.
      return
    end
    if t == "AliasMethodNode"
 # `alias new old` -- compile-time only. The class-collect pass
 # already registered a duplicate method-table entry under the
 # new name pointing to the same body_id; subsequent dispatch
 # finds it like any other method.
      return
    end
    if t == "UndefNode"
 # `undef foo` -- compile-time only. The class-collect pass
 # already recorded the removal in @undef_*; nothing to emit.
      return
    end
    if t == "PreExecutionNode"
 # `BEGIN { ... }`. collect_all already pushed the body onto
 # @pre_execution_blocks; emit_main hoists it to the top of
 # main(). The toplevel statement itself is a no-op at its
 # source location.
      return
    end
    if t == "PostExecutionNode"
 # `END { ... }`. collect_all pushed the body onto
 # @post_execution_blocks; emit_post_execution_funcs emits the
 # static sp_end_block_<n> function and emit_main inserts an
 # atexit() call at startup.
      return
    end
    if t == "LocalVariableWriteNode"
      lname = @nd_name[nid]
 # `var = method(:name)` (no receiver, top-level) is the legacy
 # static-alias path: the call_expr handler returns a `0`
 # placeholder, we record (lname, mref) here, and a later
 # `m.call(x)` is rewritten in compile_dot_call_expr to a
 # direct `sp_<name>(x)` call. Inside a class body OR with a
 # receiver (`var = recv.method(:_)`), the call expr already
 # produced a real obj_Method instance — fall through to the
 # normal compile path so the typed local picks it up. .
      expr_id = @nd_expression[nid]
      if expr_id >= 0
        if @nd_type[expr_id] == "CallNode"
          if @nd_name[expr_id] == "method" && @nd_receiver[expr_id] < 0 && @current_class_idx < 0
            args_id = @nd_arguments[expr_id]
            if args_id >= 0
              arg_ids = get_args(args_id)
              if arg_ids.length >= 1
                mref = @nd_content[arg_ids[0]]
                if mref == ""
                  mref = @nd_name[arg_ids[0]]
                end
                @method_ref_vars.push(lname)
                @method_ref_names.push(mref)
                emit("  /* " + lname + " = method(:" + mref + ") */")
                return
              end
            end
          end
        end
      end
      vref = fiber_var_ref(lname)
      vt = find_var_type(lname)
 # Empty array literal: create the correct array type. Returning
 # early here also preserves the scope's already-promoted type
 # , #85) — the fall-through path below would clobber
 # vt with infer_type([])'s "int_array" via set_var_type.
      if vt == "str_array" || vt == "float_array" || vt == "sym_array" || vt == "poly_array" || is_ptr_array_type(vt) == 1
        expr_id = @nd_expression[nid]
        if expr_id >= 0 && @nd_type[expr_id] == "ArrayNode"
          elems = parse_id_list(@nd_elements[expr_id])
          if elems.length == 0
            if vt == "str_array"
              @needs_str_array = 1
              @needs_gc = 1
              emit("  " + vref + " = sp_StrArray_new();")
            elsif vt == "float_array"
              @needs_float_array = 1
              @needs_gc = 1
              emit("  " + vref + " = sp_FloatArray_new();")
            elsif vt == "sym_array"
 # sym_array shares sp_IntArray storage.
              @needs_int_array = 1
              @needs_gc = 1
              emit("  " + vref + " = sp_IntArray_new();")
            elsif vt == "poly_array"
              @needs_rb_value = 1
              @needs_gc = 1
              emit("  " + vref + " = sp_PolyArray_new();")
            else
              @needs_gc = 1
              emit("  " + vref + " = sp_PtrArray_new();")
            end
            return
          end
        end
      end
 # Empty hash literal: create the correct hash type. The local's
 # type was promoted by scan_locals' empty-hash promotion (str_int_hash
 # default refined based on first []= site's key/value types).
 # Without these arms the literal `{}` would always emit
 # sp_StrIntHash_new() and the assignment would mismatch the
 # promoted local's struct type.
      if vt == "str_str_hash" || vt == "int_str_hash" || vt == "sym_int_hash" || vt == "sym_str_hash" || vt == "str_poly_hash" || vt == "sym_poly_hash" || vt == "poly_poly_hash"
        expr_id2 = @nd_expression[nid]
        if expr_id2 >= 0 && @nd_type[expr_id2] == "HashNode"
          elems2 = parse_id_list(@nd_elements[expr_id2])
          if elems2.length == 0
            @needs_gc = 1
            if vt == "str_str_hash"
              @needs_str_str_hash = 1
              emit("  " + vref + " = sp_StrStrHash_new();")
            elsif vt == "int_str_hash"
              @needs_int_str_hash = 1
              emit("  " + vref + " = sp_IntStrHash_new();")
            elsif vt == "sym_int_hash"
              @needs_sym_int_hash = 1
              emit("  " + vref + " = sp_SymIntHash_new();")
            elsif vt == "sym_str_hash"
              @needs_sym_str_hash = 1
              emit("  " + vref + " = sp_SymStrHash_new();")
            elsif vt == "str_poly_hash"
              @needs_str_poly_hash = 1
              @needs_rb_value = 1
              emit("  " + vref + " = sp_StrPolyHash_new();")
            elsif vt == "sym_poly_hash"
              @needs_sym_poly_hash = 1
              @needs_rb_value = 1
              emit("  " + vref + " = sp_SymPolyHash_new();")
            elsif vt == "poly_poly_hash"
              @needs_poly_poly_hash = 1
              @needs_rb_value = 1
              emit("  " + vref + " = sp_PolyPolyHash_new();")
            end
            return
          end
        end
      end
      if vt == "bigint"
        rhs_t = infer_type(@nd_expression[nid])
        val = compile_expr(@nd_expression[nid])
        if rhs_t == "bigint"
          emit("  " + vref + " = " + val + ";")
        else
          emit("  " + vref + " = sp_bigint_new_int(" + val + ");")
        end
 # Trigger GC after bigint statement (safe point - all results stored in vars)
        emit("  if(sp_gc_bytes>sp_gc_threshold){size_t _b=sp_gc_bytes;sp_gc_collect();size_t _f=_b-sp_gc_bytes;if(_f<_b/4)sp_gc_threshold=_b*2;else if(sp_gc_bytes>0){sp_gc_threshold=sp_gc_bytes*4;if(sp_gc_threshold<sp_gc_threshold_init)sp_gc_threshold=sp_gc_threshold_init;}else sp_gc_threshold=sp_gc_threshold_init;}")
