        @indent = @indent + 1
        push_scope
        if has_bp == 1
          declare_var(bp1, "int")
        end
        redo_label = push_redo_label
        emit_redo_label(redo_label)
        compile_stmts_body(@nd_body[@nd_block[nid]])
        pop_redo_label
        pop_scope
        @indent = @indent - 1
        emit("  }")
      end
    end
